export fn sqlite3WhereOutputRowCount(pWInfo: Ptr) LogEst {
    return rd(LogEst, pWInfo, WhereInfo_nRowOut);
}

export fn sqlite3WhereIsDistinct(pWInfo: Ptr) c_int {
    return rd(u8, pWInfo, WhereInfo_eDistinct);
}

export fn sqlite3WhereIsOrdered(pWInfo: Ptr) c_int {
    const n = rd(i8, pWInfo, WhereInfo_nOBSat);
    return if (n < 0) 0 else n;
}

export fn sqlite3WhereOrderByLimitOptLabel(pWInfo: Ptr) c_int {
    if (!wiBitGet(pWInfo, WI_bOrderedInnerLoop)) {
        return rd(c_int, pWInfo, WhereInfo_iContinue);
    }
    const pInner = wiLevelAt(pWInfo, @intCast(wiNLevel(pWInfo) - 1));
    if (rdp(pInner, WhereLevel_pRJ) != null) {
        return rd(c_int, pWInfo, WhereInfo_iContinue);
    }
    return rd(c_int, pInner, WhereLevel_addrNxt);
}

export fn sqlite3WhereMinMaxOptEarlyOut(v: Ptr, pWInfo: Ptr) void {
    if (!wiBitGet(pWInfo, WI_bOrderedInnerLoop)) return;
    if (rd(i8, pWInfo, WhereInfo_nOBSat) == 0) return;
    var i: c_int = wiNLevel(pWInfo) - 1;
    while (i >= 0) : (i -= 1) {
        const pInner = wiLevelAt(pWInfo, @intCast(i));
        if ((wlWsFlags(wlvWLoop(pInner)) & WHERE_COLUMN_IN) != 0) {
            _ = c.sqlite3VdbeGoto(v, rd(c_int, pInner, WhereLevel_addrNxt));
            return;
        }
    }
    _ = c.sqlite3VdbeGoto(v, rd(c_int, pWInfo, WhereInfo_iBreak));
}

export fn sqlite3WhereContinueLabel(pWInfo: Ptr) c_int {
    return rd(c_int, pWInfo, WhereInfo_iContinue);
}

export fn sqlite3WhereBreakLabel(pWInfo: Ptr) c_int {
    return rd(c_int, pWInfo, WhereInfo_iBreak);
}

export fn sqlite3WhereOkOnePass(pWInfo: Ptr, aiCur: [*]c_int) c_int {
    const src: [*]const c_int = @ptrCast(@alignCast(fieldPtr(pWInfo, WhereInfo_aiCurOnePass)));
    aiCur[0] = src[0];
    aiCur[1] = src[1];
    return rd(u8, pWInfo, WhereInfo_eOnePass);
}

export fn sqlite3WhereUsesDeferredSeek(pWInfo: Ptr) c_int {
    return @intFromBool(wiBitGet(pWInfo, WI_bDeferredSeek));
}

// ─── WhereOrSet helpers ─────────────────────────────────────────────────────
inline fn orSetA(pSet: Ptr, i: usize) Ptr {
    return fieldPtr(pSet, WhereOrSet_a + i * sizeof_WhereOrCost);
}
fn whereOrMove(pDest: Ptr, pSrc: Ptr) void {
    const n = rd(u16, pSrc, WhereOrSet_n);
    wr(u16, pDest, WhereOrSet_n, n);
    @memcpy(@as([*]u8, @ptrCast(orSetA(pDest, 0).?))[0 .. @as(usize, n) * sizeof_WhereOrCost], @as([*]u8, @ptrCast(orSetA(pSrc, 0).?)));
}

fn whereOrInsert(pSet: Ptr, prereq: Bitmask, rRun: LogEst, nOut: LogEst) c_int {
    const n0 = rd(u16, pSet, WhereOrSet_n);
    var p: Ptr = orSetA(pSet, 0);
    var i: u16 = n0;
    while (i > 0) : ({
        i -= 1;
        p = fieldPtr(p, sizeof_WhereOrCost);
    }) {
        const pRun = rd(LogEst, p, WhereOrCost_rRun);
        const pPrereq = rd(Bitmask, p, WhereOrCost_prereq);
        if (rRun <= pRun and (prereq & pPrereq) == prereq) {
            // goto whereOrInsert_done
            wr(Bitmask, p, WhereOrCost_prereq, prereq);
            wr(LogEst, p, WhereOrCost_rRun, rRun);
            if (rd(LogEst, p, WhereOrCost_nOut) > nOut) wr(LogEst, p, WhereOrCost_nOut, nOut);
            return 1;
        }
        if (pRun <= rRun and (pPrereq & prereq) == pPrereq) {
            return 0;
        }
    }
    if (n0 < N_OR_COST) {
        p = orSetA(pSet, @intCast(n0));
        wr(u16, pSet, WhereOrSet_n, n0 + 1);
        wr(LogEst, p, WhereOrCost_nOut, nOut);
    } else {
        p = orSetA(pSet, 0);
        var j: u16 = 1;
        while (j < n0) : (j += 1) {
            const pj = orSetA(pSet, j);
            if (rd(LogEst, p, WhereOrCost_rRun) > rd(LogEst, pj, WhereOrCost_rRun)) p = pj;
        }
        if (rd(LogEst, p, WhereOrCost_rRun) <= rRun) return 0;
    }
    wr(Bitmask, p, WhereOrCost_prereq, prereq);
    wr(LogEst, p, WhereOrCost_rRun, rRun);
    if (rd(LogEst, p, WhereOrCost_nOut) > nOut) wr(LogEst, p, WhereOrCost_nOut, nOut);
    return 1;
}

export fn sqlite3WhereGetMask(pMaskSet: Ptr, iCursor: c_int) Bitmask {
    const ix: [*]const c_int = @ptrCast(@alignCast(fieldPtr(pMaskSet, WhereMaskSet_ix)));
    if (ix[0] == iCursor) return 1;
    const n = rd(c_int, pMaskSet, WhereMaskSet_n);
    var i: c_int = 1;
    while (i < n) : (i += 1) {
        if (ix[@intCast(i)] == iCursor) return maskbit(i);
    }
    return 0;
}

export fn sqlite3WhereMalloc(pWInfo: Ptr, nByte: u64) Ptr {
    const db = parseDb(wiParse(pWInfo));
    var pBlock = c.sqlite3DbMallocRawNN(db, nByte + sizeof_WhereMemBlock);
    if (pBlock != null) {
        wr(?*anyopaque, pBlock, WhereMemBlock_pNext, rdp(pWInfo, WhereInfo_pMemToFree));
        wr(u64, pBlock, WhereMemBlock_sz, nByte);
        wr(?*anyopaque, pWInfo, WhereInfo_pMemToFree, pBlock);
        pBlock = fieldPtr(pBlock, sizeof_WhereMemBlock);
    }
    return pBlock;
}

export fn sqlite3WhereRealloc(pWInfo: Ptr, pOld: Ptr, nByte: u64) Ptr {
    const pNew = sqlite3WhereMalloc(pWInfo, nByte);
    if (pNew != null and pOld != null) {
        const pOldBlk = fieldPtr(pOld, 0 -% sizeof_WhereMemBlock);
        const oldSz = rd(u64, pOldBlk, WhereMemBlock_sz);
        @memcpy(@as([*]u8, @ptrCast(pNew.?))[0..@intCast(oldSz)], @as([*]u8, @ptrCast(pOld.?)));
    }
    return pNew;
}

fn createMask(pMaskSet: Ptr, iCursor: c_int) void {
    const n = rd(c_int, pMaskSet, WhereMaskSet_n);
    const ix: [*]c_int = @ptrCast(@alignCast(fieldPtr(pMaskSet, WhereMaskSet_ix)));
    ix[@intCast(n)] = iCursor;
    wr(c_int, pMaskSet, WhereMaskSet_n, n + 1);
}

fn whereRightSubexprIsColumn(p0: Ptr) Ptr {
    const p = c.sqlite3ExprSkipCollateAndLikely(exprRight(p0));
    if (p != null and exprOp(p) == TK_COLUMN and !hasProp(p, EP_FixedCol)) {
        return p;
    }
    return null;
}

