// WhereScan iterator + sqlite3WhereFindTerm
// ════════════════════════════════════════════════════════════════════════════

// Expr stack-frame for indexInAffinityOk: build a synthetic Expr inline.
fn indexInAffinityOk(pParse: Ptr, pTerm: Ptr, idxaff: u8) ?[*:0]const u8 {
    var pX = wtExpr(pTerm);
    var inexpr: [128]u8 align(8) = undefined;
    @memset(&inexpr, 0); // synthetic Expr; sizeof(Expr) < 128
    if (c.sqlite3ExprIsVector(exprLeft(pX)) != 0) {
        const iField: usize = @intCast(wtIField(pTerm) - 1);
        const inp: Ptr = @ptrCast(&inexpr);
        wr(u32, inp, Expr_flags, 0);
        wr(u8, inp, Expr_op, @intCast(TK_EQ));
        const leftList = rdp(exprLeft(pX), Expr_x);
        wr(?*anyopaque, inp, Expr_pLeft, elItemExpr(leftList, iField));
        // ExprUseXSelect(pX): pX->x.pSelect->pEList->a[iField].pExpr
        const pSel = rdp(pX, Expr_x);
        const pEList = rdp(pSel, Select_pEList);
        wr(?*anyopaque, inp, Expr_pRight, elItemExpr(pEList, iField));
        pX = inp;
    }
    if (c.sqlite3IndexAffinityOk(pX, idxaff) != 0) {
        const pRet = c.sqlite3ExprCompareCollSeq(pParse, pX);
        return if (pRet != null) rd(?[*:0]const u8, pRet, CollSeq_zName) else strBINARY();
    }
    return null;
}

inline fn scanAiColumn(pScan: Ptr) [*]i16 {
    return @ptrCast(@alignCast(fieldPtr(pScan, WhereScan_aiColumn)));
}
inline fn scanAiCur(pScan: Ptr) [*]c_int {
    return @ptrCast(@alignCast(fieldPtr(pScan, WhereScan_aiCur)));
}

fn whereScanNext(pScan: Ptr) Ptr {
    var k = rd(c_int, pScan, WhereScan_k);
    var pWC = rdp(pScan, WhereScan_pWC);
    const opMask = rd(u32, pScan, WhereScan_opMask);
    const zCollName = rd(?[*:0]const u8, pScan, WhereScan_zCollName);
    const idxaff = rd(u8, pScan, WhereScan_idxaff);
    while (true) {
        const iEquiv = rd(u8, pScan, WhereScan_iEquiv);
        const iColumn = scanAiColumn(pScan)[@intCast(iEquiv - 1)];
        const iCur = scanAiCur(pScan)[@intCast(iEquiv - 1)];
        while (true) { // do { ... } while(pWC!=0)
            const nTerm = wcNTerm(pWC);
            var pTerm = wcTermAt(pWC, k);
            while (k < nTerm) : ({
                k += 1;
                pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
            }) {
                if (wtLeftCursor(pTerm) == iCur and
                    wtLeftColumn(pTerm) == iColumn and
                    (iColumn != XN_EXPR or
                        c.sqlite3ExprCompareSkip(exprLeft(wtExpr(pTerm)), rdp(pScan, WhereScan_pIdxExpr), iCur) == 0) and
                    (rd(u8, pScan, WhereScan_iEquiv) <= 1 or !hasProp(wtExpr(pTerm), EP_OuterON)))
                {
                    if ((wtEOperator(pTerm) & WO_EQUIV) != 0 and
                        rd(u8, pScan, WhereScan_nEquiv) < WHERESCAN_NEQ)
                    {
                        const pX = whereRightSubexprIsColumn(wtExpr(pTerm));
                        if (pX != null) {
                            const nEquiv = rd(u8, pScan, WhereScan_nEquiv);
                            var j: u8 = 0;
                            while (j < nEquiv) : (j += 1) {
                                if (scanAiCur(pScan)[j] == exprITable(pX) and
                                    scanAiColumn(pScan)[j] == exprIColumn(pX))
                                {
                                    break;
                                }
                            }
                            if (j == nEquiv) {
                                scanAiCur(pScan)[j] = exprITable(pX);
                                scanAiColumn(pScan)[j] = @intCast(exprIColumn(pX));
                                wr(u8, pScan, WhereScan_nEquiv, nEquiv + 1);
                            }
                        }
                    }
                    if ((@as(u32, wtEOperator(pTerm)) & opMask) != 0) {
                        if (zCollName != null and (wtEOperator(pTerm) & WO_ISNULL) == 0) {
                            var zColl: ?[*:0]const u8 = undefined;
                            const pParse = wiParse(wcWInfo(pWC));
                            const pXe = wtExpr(pTerm);
                            if ((wtEOperator(pTerm) & WO_IN) != 0) {
                                zColl = indexInAffinityOk(pParse, pTerm, idxaff);
                                if (zColl == null) continue;
                            } else {
                                if (c.sqlite3IndexAffinityOk(pXe, idxaff) == 0) continue;
                                const pColl = c.sqlite3ExprCompareCollSeq(pParse, pXe);
                                zColl = if (pColl != null) rd(?[*:0]const u8, pColl, CollSeq_zName) else strBINARY();
                            }
                            if (c.sqlite3StrICmp(zColl, zCollName) != 0) continue;
                        }
                        if ((wtEOperator(pTerm) & (WO_EQ | WO_IS)) != 0) {
                            const pXr = exprRight(wtExpr(pTerm));
                            if (pXr != null and exprOp(pXr) == TK_COLUMN and
                                exprITable(pXr) == scanAiCur(pScan)[0] and
                                exprIColumn(pXr) == scanAiColumn(pScan)[0])
                            {
                                continue;
                            }
                        }
                        wr(?*anyopaque, pScan, WhereScan_pWC, pWC);
                        wr(c_int, pScan, WhereScan_k, k + 1);
                        return pTerm;
                    }
                }
            }
            pWC = wcOuter(pWC);
            k = 0;
            if (pWC == null) break;
        }
        if (rd(u8, pScan, WhereScan_iEquiv) >= rd(u8, pScan, WhereScan_nEquiv)) break;
        pWC = rdp(pScan, WhereScan_pOrigWC);
        k = 0;
        wr(u8, pScan, WhereScan_iEquiv, rd(u8, pScan, WhereScan_iEquiv) + 1);
    }
    return null;
}

fn whereScanInitIndexExpr(pScan: Ptr) Ptr {
    wr(u8, pScan, WhereScan_idxaff, c.sqlite3ExprAffinity(rdp(pScan, WhereScan_pIdxExpr)));
    return whereScanNext(pScan);
}

fn whereScanInit(pScan: Ptr, pWC: Ptr, iCur: c_int, iColumn0: c_int, opMask: u32, pIdx: Ptr) Ptr {
    var iColumn = iColumn0;
    wr(?*anyopaque, pScan, WhereScan_pOrigWC, pWC);
    wr(?*anyopaque, pScan, WhereScan_pWC, pWC);
    wr(?*anyopaque, pScan, WhereScan_pIdxExpr, null);
    wr(u8, pScan, WhereScan_idxaff, 0);
    wr(?*anyopaque, pScan, WhereScan_zCollName, null);
    wr(u32, pScan, WhereScan_opMask, opMask);
    wr(c_int, pScan, WhereScan_k, 0);
    scanAiCur(pScan)[0] = iCur;
    wr(u8, pScan, WhereScan_nEquiv, 1);
    wr(u8, pScan, WhereScan_iEquiv, 1);
    if (pIdx != null) {
        const j: usize = @intCast(iColumn);
        iColumn = idxAiColumn(pIdx)[j];
        if (iColumn == rd(i16, rdp(pIdx, Index_pTable), Table_iPKey)) {
            iColumn = XN_ROWID;
        } else if (iColumn >= 0) {
            wr(u8, pScan, WhereScan_idxaff, colAffinity(rdp(pIdx, Index_pTable), @intCast(iColumn)));
            wr(?[*:0]const u8, pScan, WhereScan_zCollName, idxAzColl(pIdx)[j]);
        } else if (iColumn == XN_EXPR) {
            const aColExpr = rdp(pIdx, Index_aColExpr);
            wr(?*anyopaque, pScan, WhereScan_pIdxExpr, elItemExpr(aColExpr, j));
            wr(?[*:0]const u8, pScan, WhereScan_zCollName, idxAzColl(pIdx)[j]);
            scanAiColumn(pScan)[0] = XN_EXPR;
            return whereScanInitIndexExpr(pScan);
        }
    } else if (iColumn == XN_EXPR) {
        return null;
    }
    scanAiColumn(pScan)[0] = @intCast(iColumn);
    return whereScanNext(pScan);
}

export fn sqlite3WhereFindTerm(pWC: Ptr, iCur: c_int, iColumn: c_int, notReady: Bitmask, op0: u32, pIdx: Ptr) Ptr {
    var pResult: Ptr = null;
    var scan: [sizeof_WhereScan_buf]u8 align(8) = undefined;
    const pScan: Ptr = @ptrCast(&scan);
    var p = whereScanInit(pScan, pWC, iCur, iColumn, op0, pIdx);
    const op = op0 & (WO_EQ | WO_IS);
    while (p != null) {
        if ((wtPrereqRight(p) & notReady) == 0) {
            if (wtPrereqRight(p) == 0 and (@as(u32, wtEOperator(p)) & op) != 0) {
                return p;
            }
            if (pResult == null) pResult = p;
        }
        p = whereScanNext(pScan);
    }
    return pResult;
}
const sizeof_WhereScan_buf = off("sizeof_WhereScan", 112);

fn findIndexCol(pParse: Ptr, pList: Ptr, iBase: c_int, pIdx: Ptr, iCol: usize) c_int {
    const zColl = idxAzColl(pIdx)[iCol];
    const n = elNExpr(pList);
    var i: c_int = 0;
    while (i < n) : (i += 1) {
        const p = c.sqlite3ExprSkipCollateAndLikely(elItemExpr(pList, @intCast(i)));
        if (p != null and
            (exprOp(p) == TK_COLUMN or exprOp(p) == TK_AGG_COLUMN) and
            exprIColumn(p) == idxAiColumn(pIdx)[iCol] and
            exprITable(p) == iBase)
        {
            const pColl = c.sqlite3ExprNNCollSeq(pParse, elItemExpr(pList, @intCast(i)));
            if (c.sqlite3StrICmp(rd(?[*:0]const u8, pColl, CollSeq_zName), zColl) == 0) {
                return i;
            }
        }
    }
    return -1;
}

fn indexColumnNotNull(pIdx: Ptr, iCol: usize) c_int {
    const j = idxAiColumn(pIdx)[iCol];
    if (j >= 0) {
        return @intFromBool(colNotNull(rdp(pIdx, Index_pTable), @intCast(j)));
    } else if (j == -1) {
        return 1;
    } else {
        return 0;
    }
}

fn isDistinctRedundant(pParse: Ptr, pTabList: Ptr, pWC: Ptr, pDistinct: Ptr) c_int {
    if (slNSrc(pTabList) != 1) return 0;
    const iBase = rd(c_int, slItem(pTabList, 0), SrcItem_iCursor);
    const pTab = rdp(slItem(pTabList, 0), SrcItem_pSTab);

    {
        var i: c_int = 0;
        const n = elNExpr(pDistinct);
        while (i < n) : (i += 1) {
            const p = c.sqlite3ExprSkipCollateAndLikely(elItemExpr(pDistinct, @intCast(i)));
            if (p == null) continue;
            if (exprOp(p) != TK_COLUMN and exprOp(p) != TK_AGG_COLUMN) continue;
            if (exprITable(p) == iBase and exprIColumn(p) < 0) return 1;
        }
    }

    var pIdx = rdp(pTab, Table_pIndex);
    while (pIdx != null) : (pIdx = rdp(pIdx, Index_pNext)) {
        if (!isUniqueIndex(pIdx)) continue;
        if (rdp(pIdx, Index_pPartIdxWhere) != null) continue;
        var i: c_int = 0;
        const nk = idxNKeyCol(pIdx);
        while (i < nk) : (i += 1) {
            if (sqlite3WhereFindTerm(pWC, iBase, i, ~@as(Bitmask, 0), WO_EQ, pIdx) == null) {
                if (findIndexCol(pParse, pDistinct, iBase, pIdx, @intCast(i)) < 0) break;
                if (indexColumnNotNull(pIdx, @intCast(i)) == 0) break;
            }
        }
        if (i == nk) return 1;
    }
    return 0;
}

fn estLog(N: LogEst) LogEst {
    return if (N <= 10) 0 else c.sqlite3LogEst(@intCast(N)) - 33;
}

// VdbeOp offsets (config-invariant)
const VdbeOp_opcode = off("VdbeOp_opcode", 0); // u8
const VdbeOp_p1 = off("VdbeOp_p1", 4); // i32
const VdbeOp_p2 = off("VdbeOp_p2", 8); // i32
const VdbeOp_p3 = off("VdbeOp_p3", 12); // i32
const VdbeOp_p5 = off("VdbeOp_p5", 2); // u16
const sizeof_VdbeOp = off("sizeof_VdbeOp", 32);

fn translateColumnToCopy(pParse: Ptr, iStart0: c_int, iTabCur: c_int, iRegister: c_int, iAutoidxCur: c_int) void {
    const v = rdp(pParse, Parse_pVdbe);
    var pOp = c.sqlite3VdbeGetOp(v, iStart0);
    const iEnd = c.sqlite3VdbeCurrentAddr(v);
    if (dbMallocFailed(parseDb(pParse))) return;
    var iStart = iStart0;
    while (iStart < iEnd) : ({
        iStart += 1;
        pOp = fieldPtr(pOp, sizeof_VdbeOp);
    }) {
        if (rd(c_int, pOp, VdbeOp_p1) != iTabCur) continue;
        const opc = rd(u8, pOp, VdbeOp_opcode);
        if (opc == OP_Column) {
            wr(u8, pOp, VdbeOp_opcode, @intCast(OP_Copy));
            wr(c_int, pOp, VdbeOp_p1, rd(c_int, pOp, VdbeOp_p2) + iRegister);
            wr(c_int, pOp, VdbeOp_p2, rd(c_int, pOp, VdbeOp_p3));
            wr(c_int, pOp, VdbeOp_p3, 0);
            wr(u16, pOp, VdbeOp_p5, 2);
        } else if (opc == OP_Rowid) {
            wr(u8, pOp, VdbeOp_opcode, @intCast(OP_Sequence));
            wr(c_int, pOp, VdbeOp_p1, iAutoidxCur);
        }
    }
}

// ════════════════════════════════════════════════════════════════════════════
// Outer-join compatibility, automatic index, Bloom filter
// ════════════════════════════════════════════════════════════════════════════

fn constraintCompatibleWithOuterJoin(pTerm: Ptr, pSrc: Ptr) c_int {
    if (!hasProp(wtExpr(pTerm), EP_OuterON | EP_InnerON) or
        rd(c_int, wtExpr(pTerm), Expr_w_iJoin) != rd(c_int, pSrc, SrcItem_iCursor))
    {
        return 0;
    }
    const jt = fgJoin(pSrc);
    if ((jt & @as(u8, @intCast(JT_LEFT | JT_RIGHT))) != 0 and
        hasProp(wtExpr(pTerm), EP_InnerON))
    {
        return 0;
    }
    return 1;
}

fn columnIsGoodIndexCandidate(pTab: Ptr, iCol: c_int) c_int {
    var pIdx = rdp(pTab, Table_pIndex);
    while (pIdx != null) : (pIdx = rdp(pIdx, Index_pNext)) {
        var j: c_int = 0;
        const nk = idxNKeyCol(pIdx);
        while (j < nk) : (j += 1) {
            if (idxAiColumn(pIdx)[@intCast(j)] == iCol) {
                if (j == 0) return 0;
                if (idxHasStat1(pIdx) and idxAiRowLogEst(pIdx)[@intCast(j + 1)] > 20) return 0;
                break;
            }
        }
    }
    return 1;
}

fn termCanDriveIndex(pTerm: Ptr, pSrc: Ptr, notReady: Bitmask) c_int {
    if (wtLeftCursor(pTerm) != rd(c_int, pSrc, SrcItem_iCursor)) return 0;
    if ((wtEOperator(pTerm) & (WO_EQ | WO_IS)) == 0) return 0;
    const jt = fgJoin(pSrc);
    if ((jt & @as(u8, @intCast(JT_LEFT | JT_LTORJ | JT_RIGHT))) != 0 and
        constraintCompatibleWithOuterJoin(pTerm, pSrc) == 0)
    {
        return 0;
    }
    if ((wtPrereqRight(pTerm) & notReady) != 0) return 0;
    const leftCol = wtLeftColumn(pTerm);
    if (leftCol < 0) return 0;
    const aff = colAffinity(rdp(pSrc, SrcItem_pSTab), @intCast(leftCol));
    if (c.sqlite3IndexAffinityOk(wtExpr(pTerm), aff) == 0) return 0;
    return columnIsGoodIndexCandidate(rdp(pSrc, SrcItem_pSTab), leftCol);
}

fn constructAutomaticIndex(pParse: Ptr, pWC: Ptr, notReady: Bitmask, pLevel: Ptr) void {
    const db = parseDb(pParse);
    var nKeyCol: c_int = 0;
    var sentWarning: bool = false;
    var useBloomFilter: bool = false;
    var pPartial: Ptr = null;
    var iContinue: c_int = 0;
    var addrCounter: c_int = 0;
    const v = rdp(pParse, Parse_pVdbe);
    const addrInit = c.sqlite3VdbeAddOp0(v, OP_Once);

    const pTabList = rdp(wcWInfo(pWC), WhereInfo_pTabList);
    const pSrc = slItem(pTabList, @intCast(wlvIFrom(pLevel)));
    const pTable = rdp(pSrc, SrcItem_pSTab);
    const nTerm = wcNTerm(pWC);
    const pLoop = wlvWLoop(pLevel);
    var idxCols: Bitmask = 0;

    {
        var i: c_int = 0;
        var pTerm = wcA(pWC);
        while (i < nTerm) : ({
            i += 1;
            pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
        }) {
            const pExpr = wtExpr(pTerm);
            if ((wtWtFlags(pTerm) & TERM_VIRTUAL) == 0 and
                c.sqlite3ExprIsSingleTableConstraint(pExpr, pTabList, @intCast(wlvIFrom(pLevel)), 0) != 0)
            {
                pPartial = c.sqlite3ExprAnd(pParse, pPartial, c.sqlite3ExprDup(db, pExpr, 0));
            }
            if (termCanDriveIndex(pTerm, pSrc, notReady) != 0) {
                const iCol = wtLeftColumn(pTerm);
                const cMask: Bitmask = if (iCol >= BMS) maskbit(BMS - 1) else maskbit(iCol);
                if (!sentWarning) {
                    c.sqlite3_log(SQLITE_WARNING_AUTOINDEX, "automatic index on %s(%s)", rd(?[*:0]const u8, pTable, Table_zName), colCnName(pTable, @intCast(iCol)));
                    sentWarning = true;
                }
                if ((idxCols & cMask) == 0) {
                    if (whereLoopResize(db, pLoop, nKeyCol + 1) != 0) {
                        c.sqlite3ExprDelete(db, pPartial);
                        return;
                    }
                    wlALTerm(pLoop)[@intCast(nKeyCol)] = pTerm;
                    nKeyCol += 1;
                    idxCols |= cMask;
                }
            }
        }
    }
    wr(u16, pLoop, WhereLoop_u_btree_nEq, @intCast(nKeyCol));
    wr(u16, pLoop, WhereLoop_nLTerm, @intCast(nKeyCol));
    wlSetWsFlags(pLoop, WHERE_COLUMN_EQ | WHERE_IDX_ONLY | WHERE_INDEXED | WHERE_AUTO_INDEX);

    var extraCols: Bitmask = undefined;
    if (isView(pTable)) {
        extraCols = ALLBITS & ~idxCols;
    } else {
        extraCols = rd(Bitmask, pSrc, SrcItem_colUsed) & (~idxCols | maskbit(BMS - 1));
    }
    if (!hasRowid(pTable)) {
        var i: c_int = 0;
        const nc = rd(i16, pTable, Table_nCol);
        while (i < nc) : (i += 1) {
            if ((rd(u16, tabAColAt(pTable, @intCast(i)), Column_colFlags) & COLFLAG_PRIMKEY) == 0) continue;
            if (i >= BMS - 1) {
                extraCols |= maskbit(BMS - 1);
                break;
            }
            if ((idxCols & maskbit(i)) != 0) continue;
            extraCols |= maskbit(i);
        }
    }
    const nColTab = rd(i16, pTable, Table_nCol);
    const mxBitCol: c_int = imin(@as(c_int, BMS - 1), @as(c_int, nColTab));
    {
        var i: c_int = 0;
        while (i < mxBitCol) : (i += 1) {
            if ((extraCols & maskbit(i)) != 0) nKeyCol += 1;
        }
    }
    if ((rd(Bitmask, pSrc, SrcItem_colUsed) & maskbit(BMS - 1)) != 0) {
        nKeyCol += @as(c_int, nColTab) - BMS + 1;
    }

    var zNotUsed: ?[*]u8 = null;
    const pIdx = c.sqlite3AllocateIndexObject(db, @intCast(nKeyCol + @intFromBool(hasRowid(pTable))), 0, &zNotUsed);
    if (pIdx == null) {
        c.sqlite3ExprDelete(db, pPartial);
        return;
    }
    wr(?*anyopaque, pLoop, WhereLoop_u_btree_pIndex, pIdx);
    wr(?*anyopaque, pIdx, Index_zName, @constCast(@ptrCast("auto-index")));
    wr(?*anyopaque, pIdx, Index_pTable, pTable);
    var n: c_int = 0;
    idxCols = 0;
    {
        var i: c_int = 0;
        var pTerm = wcA(pWC);
        while (i < nTerm) : ({
            i += 1;
            pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
        }) {
            if (termCanDriveIndex(pTerm, pSrc, notReady) != 0) {
                const iCol = wtLeftColumn(pTerm);
                const cMask: Bitmask = if (iCol >= BMS) maskbit(BMS - 1) else maskbit(iCol);
                if ((idxCols & cMask) == 0) {
                    const pX = wtExpr(pTerm);
                    idxCols |= cMask;
                    idxAiColumn(pIdx)[@intCast(n)] = @intCast(wtLeftColumn(pTerm));
                    const pColl = c.sqlite3ExprCompareCollSeq(pParse, pX);
                    idxAzColl(pIdx)[@intCast(n)] = if (pColl != null) rd(?[*:0]const u8, pColl, CollSeq_zName) else strBINARY();
                    n += 1;
                    if (exprLeft(pX) != null and c.sqlite3ExprAffinity(exprLeft(pX)) != SQLITE_AFF_TEXT) {
                        useBloomFilter = true;
                    }
                }
            }
        }
    }

    {
        var i: c_int = 0;
        while (i < mxBitCol) : (i += 1) {
            if ((extraCols & maskbit(i)) != 0) {
                idxAiColumn(pIdx)[@intCast(n)] = @intCast(i);
                idxAzColl(pIdx)[@intCast(n)] = strBINARY();
                n += 1;
            }
        }
    }
    if ((rd(Bitmask, pSrc, SrcItem_colUsed) & maskbit(BMS - 1)) != 0) {
        var i: c_int = BMS - 1;
        while (i < nColTab) : (i += 1) {
            idxAiColumn(pIdx)[@intCast(n)] = @intCast(i);
            idxAzColl(pIdx)[@intCast(n)] = strBINARY();
            n += 1;
        }
    }
    if (hasRowid(pTable)) {
        idxAiColumn(pIdx)[@intCast(n)] = @intCast(XN_ROWID);
        idxAzColl(pIdx)[@intCast(n)] = strBINARY();
    }

    wr(c_int, pLevel, WhereLevel_iIdxCur, rd(c_int, pParse, Parse_nTab));
    wr(c_int, pParse, Parse_nTab, rd(c_int, pParse, Parse_nTab) + 1);
    _ = c.sqlite3VdbeAddOp2(v, OP_OpenAutoindex, rd(c_int, pLevel, WhereLevel_iIdxCur), nKeyCol + 1);
    c.sqlite3VdbeSetP4KeyInfo(pParse, pIdx);
    if (optimizationEnabled(db, SQLITE_BloomFilter) and useBloomFilter) {
        _ = c.sqlite3WhereExplainBloomFilter(pParse, wcWInfo(pWC), pLevel);
        wr(c_int, pParse, Parse_nMem, rd(c_int, pParse, Parse_nMem) + 1);
        wr(c_int, pLevel, WhereLevel_regFilter, rd(c_int, pParse, Parse_nMem));
        _ = c.sqlite3VdbeAddOp2(v, OP_Blob, 10000, rd(c_int, pLevel, WhereLevel_regFilter));
    }

    var addrTop: c_int = undefined;
    if ((fgB1(pSrc) & FG_viaCoroutine) != 0) {
        const pSubq = rdp(pSrc, SrcItem_u4_pSubq);
        const regYield = rd(c_int, pSubq, Subquery_regReturn);
        addrCounter = c.sqlite3VdbeAddOp2(v, OP_Integer, 0, 0);
        _ = c.sqlite3VdbeAddOp3(v, OP_InitCoroutine, regYield, 0, rd(c_int, pSubq, Subquery_addrFillSub));
        addrTop = c.sqlite3VdbeAddOp1(v, OP_Yield, regYield);
    } else {
        addrTop = c.sqlite3VdbeAddOp2(v, OP_Rewind, rd(c_int, pLevel, WhereLevel_iTabCur), rd(c_int, pLevel, WhereLevel_addrHalt));
    }
    if (pPartial != null) {
        iContinue = c.sqlite3VdbeMakeLabel(pParse);
        c.sqlite3ExprIfFalse(pParse, pPartial, iContinue, SQLITE_JUMPIFNULL);
        wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_PARTIALIDX);
    }
    const regRecord = c.sqlite3GetTempReg(pParse);
    const regBase = c.sqlite3GenerateIndexKey(pParse, pIdx, rd(c_int, pLevel, WhereLevel_iTabCur), regRecord, 0, null, null, 0);
    if (rd(c_int, pLevel, WhereLevel_regFilter) != 0) {
        _ = c.sqlite3VdbeAddOp4Int(v, OP_FilterAdd, rd(c_int, pLevel, WhereLevel_regFilter), 0, regBase, wlNEq(pLoop));
    }
    _ = c.sqlite3VdbeAddOp2(v, OP_IdxInsert, rd(c_int, pLevel, WhereLevel_iIdxCur), regRecord);
    c.sqlite3VdbeChangeP5(v, OPFLAG_USESEEKRESULT);
    if (pPartial != null) c.sqlite3VdbeResolveLabel(v, iContinue);
    if ((fgB1(pSrc) & FG_viaCoroutine) != 0) {
        c.sqlite3VdbeChangeP2(v, addrCounter, regBase + n);
        translateColumnToCopy(pParse, addrTop, rd(c_int, pLevel, WhereLevel_iTabCur), rd(c_int, rdp(pSrc, SrcItem_u4_pSubq), Subquery_regResult), rd(c_int, pLevel, WhereLevel_iIdxCur));
        _ = c.sqlite3VdbeGoto(v, addrTop);
        // pSrc->fg.viaCoroutine = 0
        wr(u8, pSrc, SrcItem_fg + 1, fgB1(pSrc) & ~FG_viaCoroutine);
        c.sqlite3VdbeJumpHere(v, addrTop);
    } else {
        _ = c.sqlite3VdbeAddOp2(v, OP_Next, rd(c_int, pLevel, WhereLevel_iTabCur), addrTop + 1);
        c.sqlite3VdbeChangeP5(v, SQLITE_STMTSTATUS_AUTOINDEX);
        if ((fgJoin(pSrc) & @as(u8, @intCast(JT_LEFT))) != 0) {
            c.sqlite3VdbeJumpHere(v, addrTop);
        }
    }
    c.sqlite3ReleaseTempReg(pParse, regRecord);
    c.sqlite3VdbeJumpHere(v, addrInit);
    c.sqlite3ExprDelete(db, pPartial);
}
const Column_zCnName = off("Column_zCnName", 0);
inline fn colCnName(pTab: Ptr, i: usize) ?[*:0]const u8 {
    return rd(?[*:0]const u8, tabAColAt(pTab, i), Column_zCnName);
}

fn sqlite3ConstructBloomFilter(pWInfo: Ptr, iLevel0: c_int, pLevel0: Ptr, notReady: Bitmask) void {
    var pLevel = pLevel0;
    var iLevel = iLevel0;
    const pParse = wiParse(pWInfo);
    const v = rdp(pParse, Parse_pVdbe);
    var pLoop = wlvWLoop(pLevel);

    const saved_pIdxEpr = rdp(pParse, Parse_pIdxEpr);
    const saved_pIdxPartExpr = rdp(pParse, Parse_pIdxPartExpr);
    wr(?*anyopaque, pParse, Parse_pIdxEpr, null);
    wr(?*anyopaque, pParse, Parse_pIdxPartExpr, null);

    const addrOnce = c.sqlite3VdbeAddOp0(v, OP_Once);
    while (true) {
        _ = c.sqlite3WhereExplainBloomFilter(pParse, pWInfo, pLevel);
        const addrCont = c.sqlite3VdbeMakeLabel(pParse);
        const iCur = rd(c_int, pLevel, WhereLevel_iTabCur);
        wr(c_int, pParse, Parse_nMem, rd(c_int, pParse, Parse_nMem) + 1);
        wr(c_int, pLevel, WhereLevel_regFilter, rd(c_int, pParse, Parse_nMem));

        const pTabList = rdp(pWInfo, WhereInfo_pTabList);
        const iSrc = wlvIFrom(pLevel);
        const pItem = slItem(pTabList, @intCast(iSrc));
        const pTab = rdp(pItem, SrcItem_pSTab);
        var sz = c.sqlite3LogEstToInt(rd(LogEst, pTab, Table_nRowLogEst));
        if (sz < 10000) sz = 10000 else if (sz > 10000000) sz = 10000000;
        _ = c.sqlite3VdbeAddOp2(v, OP_Blob, @intCast(sz), rd(c_int, pLevel, WhereLevel_regFilter));

        const addrTop = c.sqlite3VdbeAddOp1(v, OP_Rewind, iCur);
        const pSWC = wiSWC(pWInfo);
        {
            var i: c_int = 0;
            var pTerm = wcA(pSWC);
            const nt = wcNTerm(pSWC);
            while (i < nt) : ({
                i += 1;
                pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
            }) {
                const pExpr = wtExpr(pTerm);
                if ((wtWtFlags(pTerm) & TERM_VIRTUAL) == 0 and
                    c.sqlite3ExprIsSingleTableConstraint(pExpr, pTabList, @intCast(iSrc), 0) != 0)
                {
                    c.sqlite3ExprIfFalse(pParse, wtExpr(pTerm), addrCont, SQLITE_JUMPIFNULL);
                }
            }
        }
        if ((wlWsFlags(pLoop) & WHERE_IPK) != 0) {
            const r1 = c.sqlite3GetTempReg(pParse);
            _ = c.sqlite3VdbeAddOp2(v, OP_Rowid, iCur, r1);
            _ = c.sqlite3VdbeAddOp4Int(v, OP_FilterAdd, rd(c_int, pLevel, WhereLevel_regFilter), 0, r1, 1);
            c.sqlite3ReleaseTempReg(pParse, r1);
        } else {
            const pIdx = wlPIndex(pLoop);
            const nn = wlNEq(pLoop);
            const r1 = c.sqlite3GetTempRange(pParse, nn);
            var jj: c_int = 0;
            while (jj < nn) : (jj += 1) {
                c.sqlite3ExprCodeLoadIndexColumn(pParse, pIdx, iCur, jj, r1 + jj);
            }
            _ = c.sqlite3VdbeAddOp4Int(v, OP_FilterAdd, rd(c_int, pLevel, WhereLevel_regFilter), 0, r1, nn);
            c.sqlite3ReleaseTempRange(pParse, r1, nn);
        }
        c.sqlite3VdbeResolveLabel(v, addrCont);
        _ = c.sqlite3VdbeAddOp2(v, OP_Next, rd(c_int, pLevel, WhereLevel_iTabCur), addrTop + 1);
        c.sqlite3VdbeJumpHere(v, addrTop);
        wlSetWsFlags(pLoop, wlWsFlags(pLoop) & ~WHERE_BLOOMFILTER);
        if (optimizationDisabled(parseDb(pParse), SQLITE_BloomPulldown)) break;
        var found = false;
        iLevel += 1;
        while (iLevel < wiNLevel(pWInfo)) : (iLevel += 1) {
            pLevel = wiLevelAt(pWInfo, @intCast(iLevel));
            const pTabItem = slItem(rdp(pWInfo, WhereInfo_pTabList), @intCast(wlvIFrom(pLevel)));
            if ((fgJoin(pTabItem) & @as(u8, @intCast(JT_LEFT | JT_LTORJ))) != 0) continue;
            pLoop = wlvWLoop(pLevel);
            if (pLoop == null) continue;
            if ((wlPrereq(pLoop) & notReady) != 0) continue;
            if ((wlWsFlags(pLoop) & (WHERE_BLOOMFILTER | WHERE_COLUMN_IN)) == WHERE_BLOOMFILTER) {
                found = true;
                break;
            }
        }
        if (!found or iLevel >= wiNLevel(pWInfo)) break;
    }
    c.sqlite3VdbeJumpHere(v, addrOnce);
    wr(?*anyopaque, pParse, Parse_pIdxEpr, saved_pIdxEpr);
    wr(?*anyopaque, pParse, Parse_pIdxPartExpr, saved_pIdxPartExpr);
}

// ════════════════════════════════════════════════════════════════════════════
// sqlite3_index_info allocation + vtab xBestIndex
// ════════════════════════════════════════════════════════════════════════════

// sqlite3_index_info offsets (public ABI; config-invariant)
const II_nConstraint = off("sqlite3_index_info_nConstraint", 0); // i32
const II_aConstraint = off("sqlite3_index_info_aConstraint", 8);
const II_nOrderBy = off("sqlite3_index_info_nOrderBy", 16); // i32
const II_aOrderBy = off("sqlite3_index_info_aOrderBy", 24);
const II_aConstraintUsage = off("sqlite3_index_info_aConstraintUsage", 32);
const II_idxNum = off("sqlite3_index_info_idxNum", 40); // i32
const II_idxStr = off("sqlite3_index_info_idxStr", 48);
const II_needToFreeIdxStr = off("sqlite3_index_info_needToFreeIdxStr", 56); // i32
const II_orderByConsumed = off("sqlite3_index_info_orderByConsumed", 60); // i32
const II_estimatedCost = off("sqlite3_index_info_estimatedCost", 64); // f64
const II_estimatedRows = off("sqlite3_index_info_estimatedRows", 72); // i64
const II_idxFlags = off("sqlite3_index_info_idxFlags", 80); // i32
const II_colUsed = off("sqlite3_index_info_colUsed", 88); // u64
const sizeof_index_info = off("sizeof_sqlite3_index_info", 96);
const sizeof_idxcons = off("sizeof_idxinfo_constraint", 12);
const IC_iColumn = off("idxinfo_constraint_iColumn", 0); // i32
const IC_op = off("idxinfo_constraint_op", 4); // u8
const IC_usable = off("idxinfo_constraint_usable", 5); // u8
const IC_iTermOffset = off("idxinfo_constraint_iTermOffset", 8); // i32
const sizeof_idxorderby = off("sizeof_idxinfo_orderby", 8);
const IO_iColumn = off("idxinfo_orderby_iColumn", 0); // i32
const IO_desc = off("idxinfo_orderby_desc", 4); // u8
const sizeof_idxusage = off("sizeof_idxinfo_usage", 8);
const IU_argvIndex = off("idxinfo_usage_argvIndex", 0); // i32
const IU_omit = off("idxinfo_usage_omit", 4); // u8

// HiddenIndexInfo layout (private to where.c; must match here & sqlite3_vtab_collation)
//   WhereClause *pWC; Parse *pParse; int eDistinct; u32 mIn; u32 mHandleIn;
//   sqlite3_value *aRhs[FLEXARRAY];
const HII_pWC: usize = 0;
const HII_pParse: usize = 8;
const HII_eDistinct: usize = 16; // i32
const HII_mIn: usize = 20; // u32
const HII_mHandleIn: usize = 24; // u32
const HII_aRhs: usize = 32; // pointer array, 8-aligned
inline fn hiddenOf(pIdxInfo: Ptr) Ptr {
    return fieldPtr(pIdxInfo, sizeof_index_info);
}
inline fn szHiddenIndexInfo(N: usize) usize {
    return HII_aRhs + N * 8;
}

const SQLITE_INDEX_CONSTRAINT_EQ: u8 = 2;
const SQLITE_INDEX_CONSTRAINT_ISNULL: u8 = IC_ISNULL;
const SQLITE_INDEX_CONSTRAINT_IS: u8 = IC_IS;

inline fn iiConsAt(p: Ptr, i: usize) Ptr {
    return fieldPtr(rdp(p, II_aConstraint), i * sizeof_idxcons);
}
inline fn iiOrderByAt(p: Ptr, i: usize) Ptr {
    return fieldPtr(rdp(p, II_aOrderBy), i * sizeof_idxorderby);
}
inline fn iiUsageAt(p: Ptr, i: usize) Ptr {
    return fieldPtr(rdp(p, II_aConstraintUsage), i * sizeof_idxusage);
}

fn termFromWhereClause(pWC0: Ptr, iTerm0: c_int) Ptr {
    var p = pWC0;
    var iTerm = iTerm0;
    while (p != null) : (p = wcOuter(p)) {
        if (iTerm < wcNTerm(p)) return wcTermAt(p, iTerm);
        iTerm -= wcNTerm(p);
    }
    return null;
}

fn allocateIndexInfo(pWInfo: Ptr, pWC: Ptr, mUnusable: Bitmask, pSrc: Ptr, pmNoOmit: *u16) Ptr {
    const pParse = wiParse(pWInfo);
    var mNoOmit: u16 = 0;
    var eDistinct: c_int = 0;
    const pOrderBy = rdp(pWInfo, WhereInfo_pOrderBy);
    const pTab = rdp(pSrc, SrcItem_pSTab);

    var nTerm: c_int = 0;
    {
        var p = pWC;
        while (p != null) : (p = wcOuter(p)) {
            var i: c_int = 0;
            var pTerm = wcA(p);
            const nt = wcNTerm(p);
            while (i < nt) : ({
                i += 1;
                pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
            }) {
                wtSetWtFlags(pTerm, wtWtFlags(pTerm) & ~TERM_OK);
                if (wtLeftCursor(pTerm) != rd(c_int, pSrc, SrcItem_iCursor)) continue;
                if ((wtPrereqRight(pTerm) & mUnusable) != 0) continue;
                if ((wtEOperator(pTerm) & ~WO_EQUIV) == 0) continue;
                if ((wtWtFlags(pTerm) & TERM_VNULL) != 0) continue;
                if ((fgJoin(pSrc) & @as(u8, @intCast(JT_LEFT | JT_LTORJ | JT_RIGHT))) != 0 and
                    constraintCompatibleWithOuterJoin(pTerm, pSrc) == 0)
                {
                    continue;
                }
                nTerm += 1;
                wtSetWtFlags(pTerm, wtWtFlags(pTerm) | TERM_OK);
            }
        }
    }

    var nOrderBy: c_int = 0;
    if (pOrderBy != null) {
        const n = elNExpr(pOrderBy);
        var i: c_int = 0;
        while (i < n) : (i += 1) {
            const pExpr = elItemExpr(pOrderBy, @intCast(i));
            if (c.sqlite3ExprIsConstant(null, pExpr) != 0) continue;
            if ((rd(u8, elItem(pOrderBy, @intCast(i)), ExprList_item_fg_sortFlags) & KEYINFO_ORDER_BIGNULL) != 0) break;
            if (exprOp(pExpr) == TK_COLUMN and exprITable(pExpr) == rd(c_int, pSrc, SrcItem_iCursor)) continue;
            if (exprOp(pExpr) == TK_COLLATE) {
                const pE2 = exprLeft(pExpr);
                if (exprOp(pE2) == TK_COLUMN and exprITable(pE2) == rd(c_int, pSrc, SrcItem_iCursor)) {
                    wr(c_int, pExpr, Expr_iColumn, exprIColumn(pE2));
                    if (exprIColumn(pE2) < 0) continue;
                    var zColl = c.sqlite3ColumnColl(tabAColAt(pTab, @intCast(exprIColumn(pE2))));
                    if (zColl == null) zColl = strBINARY();
                    if (c.sqlite3_stricmp(rd(?[*:0]const u8, pExpr, Expr_u), zColl) == 0) continue;
                }
            }
            break;
        }
        if (i == n) {
            const bSortByGroup = (rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_SORTBYGROUP) != 0;
            nOrderBy = n;
            const wf = rd(u16, pWInfo, WhereInfo_wctrlFlags);
            if ((wf & WHERE_DISTINCTBY) != 0 and (fgB2(pSrc) & FG_rowidUsed) == 0) {
                eDistinct = 2 + @as(c_int, @intFromBool(bSortByGroup));
            } else if ((wf & WHERE_GROUPBY) != 0) {
                eDistinct = 1 - @as(c_int, @intFromBool(bSortByGroup));
            } else if ((wf & WHERE_WANT_DISTINCT) != 0) {
                eDistinct = 3;
            }
        }
    }

    const allocSz = sizeof_index_info +
        (sizeof_idxcons + sizeof_idxusage) * @as(usize, @intCast(nTerm)) +
        sizeof_idxorderby * @as(usize, @intCast(nOrderBy)) +
        szHiddenIndexInfo(@intCast(nTerm));
    const pIdxInfo = c.sqlite3DbMallocZero(parseDb(pParse), allocSz);
    if (pIdxInfo == null) {
        c.sqlite3ErrorMsg(pParse, "out of memory");
        return null;
    }
    const pHidden = hiddenOf(pIdxInfo);
    const pIdxCons: Ptr = fieldPtr(pHidden, HII_aRhs + @as(usize, @intCast(nTerm)) * 8);
    const pIdxOrderBy: Ptr = fieldPtr(pIdxCons, @as(usize, @intCast(nTerm)) * sizeof_idxcons);
    const pUsage: Ptr = fieldPtr(pIdxOrderBy, @as(usize, @intCast(nOrderBy)) * sizeof_idxorderby);
    wr(?*anyopaque, pIdxInfo, II_aConstraint, pIdxCons);
    wr(?*anyopaque, pIdxInfo, II_aOrderBy, pIdxOrderBy);
    wr(?*anyopaque, pIdxInfo, II_aConstraintUsage, pUsage);
    wr(i64, pIdxInfo, II_colUsed, @bitCast(rd(Bitmask, pSrc, SrcItem_colUsed)));
    if (!hasRowid(pTab)) {
        const pPk = c.sqlite3PrimaryKeyIndex(pTab);
        var i: c_int = 0;
        const nk = idxNKeyCol(pPk);
        while (i < nk) : (i += 1) {
            var iCol: c_int = idxAiColumn(pPk)[@intCast(i)];
            if (iCol >= BMS - 1) iCol = BMS - 1;
            wr(i64, pIdxInfo, II_colUsed, @bitCast(@as(u64, @bitCast(rd(i64, pIdxInfo, II_colUsed))) | maskbit(iCol)));
        }
    }
    wr(?*anyopaque, pHidden, HII_pWC, pWC);
    wr(?*anyopaque, pHidden, HII_pParse, pParse);
    wr(c_int, pHidden, HII_eDistinct, eDistinct);
    wr(u32, pHidden, HII_mIn, 0);

    {
        var p = pWC;
        var i: c_int = 0;
        var j: c_int = 0;
        while (p != null) : (p = wcOuter(p)) {
            const nLast = i + wcNTerm(p);
            var pTerm = wcA(p);
            while (i < nLast) : ({
                i += 1;
                pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
            }) {
                if ((wtWtFlags(pTerm) & TERM_OK) == 0) continue;
                const pc = fieldPtr(pIdxCons, @as(usize, @intCast(j)) * sizeof_idxcons);
                wr(c_int, pc, IC_iColumn, wtLeftColumn(pTerm));
                wr(c_int, pc, IC_iTermOffset, i);
                var op: u16 = wtEOperator(pTerm) & WO_ALL;
                if (op == WO_IN) {
                    if ((wtWtFlags(pTerm) & TERM_SLICE) == 0) {
                        wr(u32, pHidden, HII_mIn, rd(u32, pHidden, HII_mIn) | smaskbit32(j));
                    }
                    op = WO_EQ;
                }
                if (op == WO_AUX) {
                    wr(u8, pc, IC_op, wtEMatchOp(pTerm));
                } else if ((op & (WO_ISNULL | WO_IS)) != 0) {
                    if (op == WO_ISNULL) {
                        wr(u8, pc, IC_op, SQLITE_INDEX_CONSTRAINT_ISNULL);
                    } else {
                        wr(u8, pc, IC_op, SQLITE_INDEX_CONSTRAINT_IS);
                    }
                } else {
                    // C: `pIdxCons[j].op = (u8)op;` — a *truncating* cast (the low
                    // byte carries the WO_*/SQLITE_INDEX_CONSTRAINT_* code). Use
                    // @truncate, not @intCast: an aux-function constraint can leave
                    // high bits set in `op`, which @intCast would panic on.
                    wr(u8, pc, IC_op, @truncate(op));
                    if ((op & (WO_LT | WO_LE | WO_GT | WO_GE)) != 0 and
                        c.sqlite3ExprIsVector(exprRight(wtExpr(pTerm))) != 0)
                    {
                        if (j < 16) mNoOmit |= (@as(u16, 1) << @intCast(j));
                        if (op == WO_LT) wr(u8, pc, IC_op, @intCast(WO_LE));
                        if (op == WO_GT) wr(u8, pc, IC_op, @intCast(WO_GE));
                    }
                }
                j += 1;
            }
        }
        wr(c_int, pIdxInfo, II_nConstraint, j);
    }
    {
        var i: c_int = 0;
        var j: c_int = 0;
        while (i < nOrderBy) : (i += 1) {
            const pExpr = elItemExpr(pOrderBy, @intCast(i));
            if (c.sqlite3ExprIsConstant(null, pExpr) != 0) continue;
            const po = fieldPtr(pIdxOrderBy, @as(usize, @intCast(j)) * sizeof_idxorderby);
            wr(c_int, po, IO_iColumn, exprIColumn(pExpr));
            wr(u8, po, IO_desc, rd(u8, elItem(pOrderBy, @intCast(i)), ExprList_item_fg_sortFlags) & KEYINFO_ORDER_DESC);
            j += 1;
        }
        wr(c_int, pIdxInfo, II_nOrderBy, j);
    }
    pmNoOmit.* = mNoOmit;
    return pIdxInfo;
}

fn freeIdxStr(pIdxInfo: Ptr) void {
    if (rd(c_int, pIdxInfo, II_needToFreeIdxStr) != 0) {
        c.sqlite3_free(rdp(pIdxInfo, II_idxStr));
        wr(?*anyopaque, pIdxInfo, II_idxStr, null);
        wr(c_int, pIdxInfo, II_needToFreeIdxStr, 0);
    }
}

fn freeIndexInfo(db: Ptr, pIdxInfo: Ptr) void {
    const pHidden = hiddenOf(pIdxInfo);
    const nCon = rd(c_int, pIdxInfo, II_nConstraint);
    var i: c_int = 0;
    while (i < nCon) : (i += 1) {
        const rhsP = fieldPtr(pHidden, HII_aRhs + @as(usize, @intCast(i)) * 8);
        c.sqlite3ValueFree(rdp(rhsP, 0));
        wr(?*anyopaque, rhsP, 0, null);
    }
    freeIdxStr(pIdxInfo);
    c.sqlite3DbFree(db, pIdxInfo);
}

const Table_zErrMsg_unused = 0;
fn vtabBestIndex(pParse: Ptr, pTab: Ptr, p: Ptr) c_int {
    const pVtab = rdp(c.sqlite3GetVTable(parseDb(pParse), pTab), VTable_pVtab);
    const db = parseDb(pParse);
    wr(u32, db, db_nSchemaLock, rd(u32, db, db_nSchemaLock) + 1);
    const pMod = rdp(pVtab, sqlite3_vtab_pModule);
    const xBest = rdp(pMod, sqlite3_module_xBestIndex);
    const fn_t = *const fn (Ptr, Ptr) callconv(.c) c_int;
    const xb: fn_t = @ptrCast(xBest);
    const rc = xb(pVtab, p);
    wr(u32, db, db_nSchemaLock, rd(u32, db, db_nSchemaLock) - 1);

    if (rc != SQLITE_OK and rc != SQLITE_CONSTRAINT) {
        if (rc == SQLITE_NOMEM) {
            _ = c.sqlite3OomFault(db);
        } else if (rdp(pVtab, sqlite3_vtab_zErrMsg) == null) {
            c.sqlite3ErrorMsg(pParse, "%s", c.sqlite3ErrStr(rc));
        } else {
            c.sqlite3ErrorMsg(pParse, "%s", rd(?[*:0]const u8, pVtab, sqlite3_vtab_zErrMsg));
        }
    }
    // pTab->u.vtab.p->bAllSchemas
    const pVT = rdp(pTab, Table_u_vtab_p);
    if (pVT != null and rd(u8, pVT, VTable_bAllSchemas) != 0) {
        sqlite3VtabUsesAllSchemas(pParse);
    }
    c.sqlite3_free(rdp(pVtab, sqlite3_vtab_zErrMsg));
    wr(?*anyopaque, pVtab, sqlite3_vtab_zErrMsg, null);
    return rc;
}
const VTable_pVtab = off("VTable_pVtab", 16);
const VTable_bAllSchemas = off("VTable_bAllSchemas", 29);

// ════════════════════════════════════════════════════════════════════════════
// WhereLoop lifecycle
// ════════════════════════════════════════════════════════════════════════════

const ALTERMSPACE_N: usize = 3;

fn whereLoopInit(p: Ptr) void {
    wr(?*anyopaque, p, WhereLoop_aLTerm, fieldPtr(p, WhereLoop_aLTermSpace));
    wr(u16, p, WhereLoop_nLTerm, 0);
    wr(u16, p, WhereLoop_nLSlot, ALTERMSPACE_N);
    wr(u32, p, WhereLoop_wsFlags, 0);
}

fn whereLoopClearUnion(db: Ptr, p: Ptr) void {
    const ws = wlWsFlags(p);
    if ((ws & (WHERE_VIRTUALTABLE | WHERE_AUTO_INDEX)) != 0) {
        if ((ws & WHERE_VIRTUALTABLE) != 0 and (rd(u8, p, WhereLoop_u_vtab_bits) & VTAB_needFree) != 0) {
            c.sqlite3_free(rdp(p, WhereLoop_u_vtab_idxStr));
            wr(u8, p, WhereLoop_u_vtab_bits, rd(u8, p, WhereLoop_u_vtab_bits) & ~VTAB_needFree);
            wr(?*anyopaque, p, WhereLoop_u_vtab_idxStr, null);
        } else if ((ws & WHERE_AUTO_INDEX) != 0 and wlPIndex(p) != null) {
            c.sqlite3DbFree(db, rdp(wlPIndex(p), Index_zColAff));
            c.sqlite3DbFreeNN(db, wlPIndex(p));
            wr(?*anyopaque, p, WhereLoop_u_btree_pIndex, null);
        }
    }
}

fn whereLoopClear(db: Ptr, p: Ptr) void {
    if (wlALTerm(p) != @as([*]Ptr, @ptrCast(@alignCast(fieldPtr(p, WhereLoop_aLTermSpace).?)))) {
        c.sqlite3DbFreeNN(db, rdp(p, WhereLoop_aLTerm));
        wr(?*anyopaque, p, WhereLoop_aLTerm, fieldPtr(p, WhereLoop_aLTermSpace));
        wr(u16, p, WhereLoop_nLSlot, ALTERMSPACE_N);
    }
    whereLoopClearUnion(db, p);
    wr(u16, p, WhereLoop_nLTerm, 0);
    wr(u32, p, WhereLoop_wsFlags, 0);
}

fn whereLoopResize(db: Ptr, p: Ptr, n0: c_int) c_int {
    if (rd(u16, p, WhereLoop_nLSlot) >= n0) return SQLITE_OK;
    const n = (n0 + 7) & ~@as(c_int, 7);
    const paNew = c.sqlite3DbMallocRawNN(db, @as(u64, 8) * @as(u64, @intCast(n)));
    if (paNew == null) return SQLITE_NOMEM;
    const nLSlot = rd(u16, p, WhereLoop_nLSlot);
    @memcpy(@as([*]u8, @ptrCast(paNew.?))[0 .. 8 * @as(usize, nLSlot)], @as([*]u8, @ptrCast(rdp(p, WhereLoop_aLTerm).?)));
    if (wlALTerm(p) != @as([*]Ptr, @ptrCast(@alignCast(fieldPtr(p, WhereLoop_aLTermSpace).?)))) {
        c.sqlite3DbFreeNN(db, rdp(p, WhereLoop_aLTerm));
    }
    wr(?*anyopaque, p, WhereLoop_aLTerm, paNew);
    wr(u16, p, WhereLoop_nLSlot, @intCast(n));
    return SQLITE_OK;
}

fn whereLoopXfer(db: Ptr, pTo: Ptr, pFrom: Ptr) c_int {
    whereLoopClearUnion(db, pTo);
    if (wlNLTerm(pFrom) > rd(u16, pTo, WhereLoop_nLSlot) and
        whereLoopResize(db, pTo, wlNLTerm(pFrom)) != 0)
    {
        @memset(@as([*]u8, @ptrCast(pTo.?))[0..WHERE_LOOP_XFER_SZ], 0);
        return SQLITE_NOMEM;
    }
    @memcpy(@as([*]u8, @ptrCast(pTo.?))[0..WHERE_LOOP_XFER_SZ], @as([*]u8, @ptrCast(pFrom.?)));
    const nt: usize = @intCast(wlNLTerm(pTo));
    @memcpy(@as([*]u8, @ptrCast(rdp(pTo, WhereLoop_aLTerm).?))[0 .. nt * 8], @as([*]u8, @ptrCast(rdp(pFrom, WhereLoop_aLTerm).?)));
    if ((wlWsFlags(pFrom) & WHERE_VIRTUALTABLE) != 0) {
        wr(u8, pFrom, WhereLoop_u_vtab_bits, rd(u8, pFrom, WhereLoop_u_vtab_bits) & ~VTAB_needFree);
    } else if ((wlWsFlags(pFrom) & WHERE_AUTO_INDEX) != 0) {
        wr(?*anyopaque, pFrom, WhereLoop_u_btree_pIndex, null);
    }
    return SQLITE_OK;
}

fn whereLoopDelete(db: Ptr, p: Ptr) void {
    whereLoopClear(db, p);
    c.sqlite3DbNNFreeNN(db, p);
}

fn whereInfoFree(db: Ptr, pWInfo: Ptr) void {
    c.sqlite3WhereClauseClear(wiSWC(pWInfo));
    while (rdp(pWInfo, WhereInfo_pLoops) != null) {
        const p = rdp(pWInfo, WhereInfo_pLoops);
        wr(?*anyopaque, pWInfo, WhereInfo_pLoops, wlNext(p));
        whereLoopDelete(db, p);
    }
    while (rdp(pWInfo, WhereInfo_pMemToFree) != null) {
        const pNext = rdp(rdp(pWInfo, WhereInfo_pMemToFree), WhereMemBlock_pNext);
        c.sqlite3DbNNFreeNN(db, rdp(pWInfo, WhereInfo_pMemToFree));
        wr(?*anyopaque, pWInfo, WhereInfo_pMemToFree, pNext);
    }
    c.sqlite3DbNNFreeNN(db, pWInfo);
}

// ════════════════════════════════════════════════════════════════════════════
// Cost estimation helpers (STAT4 OFF)
// ════════════════════════════════════════════════════════════════════════════

fn whereRangeAdjust(pTerm: Ptr, nNew: LogEst) LogEst {
    var nRet = nNew;
    if (pTerm != null) {
        if (wtTruthProb(pTerm) <= 0) {
            nRet += wtTruthProb(pTerm);
        } else if ((wtWtFlags(pTerm) & TERM_VNULL) == 0) {
            nRet -= 20;
        }
    }
    return nRet;
}

fn whereRangeScanEst(pParse: Ptr, pBuilder: Ptr, pLower: Ptr, pUpper: Ptr, pLoop: Ptr) c_int {
    _ = pParse;
    _ = pBuilder;
    const nOut0 = wlNOut(pLoop);
    var nOut: c_int = nOut0;
    var nNew = whereRangeAdjust(pLower, nOut0);
    nNew = whereRangeAdjust(pUpper, nNew);
    if (pLower != null and wtTruthProb(pLower) > 0 and pUpper != null and wtTruthProb(pUpper) > 0) {
        nNew -= 20;
    }
    nOut -= @as(c_int, @intFromBool(pLower != null)) + @as(c_int, @intFromBool(pUpper != null));
    if (nNew < 10) nNew = 10;
    if (nNew < nOut) nOut = nNew;
    wr(LogEst, pLoop, WhereLoop_nOut, @intCast(nOut));
    return SQLITE_OK;
}

// Walker.u.sz for estLikePatternLength
fn estLikePatternLength(p: Ptr, eCode: u16) c_int {
    var w: [sizeof_Walker]u8 align(8) = undefined;
    @memset(&w, 0);
    const wp: Ptr = @ptrCast(&w);
    wr(c_int, wp, Walker_u, 0); // u.sz (int)
    wr(u16, wp, Walker_eCode, eCode);
    wr(?*anyopaque, wp, Walker_xExprCallback, @constCast(@ptrCast(&exprNodePatternLengthEst)));
    wr(?*anyopaque, wp, Walker_xSelectCallback, @constCast(@ptrCast(&c.sqlite3SelectWalkFail)));
    if (dbg) {
        wr(?*anyopaque, wp, Walker_xSelectCallback2, @constCast(@ptrCast(&c.sqlite3SelectWalkAssert2)));
    }
    _ = c.sqlite3WalkExpr(wp, p);
    return rd(c_int, wp, Walker_u);
}

fn exprNodePatternLengthEst(pWalker: Ptr, pExpr: Ptr) callconv(.c) c_int {
    if (exprOp(pExpr) == TK_STRING) {
        var sz: c_int = 0;
        var z: [*]const u8 = @ptrCast(rd(?[*:0]const u8, pExpr, Expr_u).?);
        var c1: u8 = undefined;
        var c2: u8 = undefined;
        var c3: u8 = undefined;
        if (rd(u16, pWalker, Walker_eCode) != 0) {
            c1 = '%';
            c2 = '_';
            c3 = 0;
        } else {
            c1 = '*';
            c2 = '?';
            c3 = '[';
        }
        var ch = z[0];
        z += 1;
        while (ch != 0) : ({
            ch = z[0];
            z += 1;
        }) {
            if (ch == c3) {
                if (z[0] != 0) z += 1;
                while (z[0] != 0 and z[0] != ']') z += 1;
            } else if (ch != c1 and ch != c2) {
                sz += 1;
            }
        }
        if (sz > rd(c_int, pWalker, Walker_u)) wr(c_int, pWalker, Walker_u, sz);
    }
    return WRC_Continue;
}

fn whereLoopOutputAdjust(pWC: Ptr, pLoop: Ptr, nRow: LogEst) void {
    const notAllowed = ~(wlPrereq(pLoop) | wlMaskSelf(pLoop));
    var iReduce: LogEst = 0;
    var i: c_int = wcNBase(pWC);
    var pTerm = wcA(pWC);
    while (i > 0) : ({
        i -= 1;
        pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
    }) {
        if ((wtPrereqAll(pTerm) & notAllowed) != 0) continue;
        if ((wtPrereqAll(pTerm) & wlMaskSelf(pLoop)) == 0) continue;
        if ((wtWtFlags(pTerm) & TERM_VIRTUAL) != 0) continue;
        var j: c_int = wlNLTerm(pLoop) - 1;
        var found = false;
        while (j >= 0) : (j -= 1) {
            const pX = wlALTermAt(pLoop, @intCast(j));
            if (pX == null) continue;
            if (pX == pTerm) {
                found = true;
                break;
            }
            if (wtIParent(pX) >= 0 and wcTermAt(pWC, wtIParent(pX)) == pTerm) {
                found = true;
                break;
            }
        }
        if (!found) {
            _ = c.sqlite3ProgressCheck(wiParse(wcWInfo(pWC)));
            if (wlMaskSelf(pLoop) == wtPrereqAll(pTerm)) {
                if ((wtEOperator(pTerm) & 0x3f) != 0 or
                    (fgJoin(slItem(rdp(wcWInfo(pWC), WhereInfo_pTabList), wlITab(pLoop))) & @as(u8, @intCast(JT_LEFT | JT_LTORJ))) == 0)
                {
                    wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_SELFCULL);
                }
            }
            if (wtTruthProb(pTerm) <= 0) {
                wr(LogEst, pLoop, WhereLoop_nOut, wlNOut(pLoop) + wtTruthProb(pTerm));
            } else {
                const pOpExpr = wtExpr(pTerm);
                wr(LogEst, pLoop, WhereLoop_nOut, wlNOut(pLoop) - 1);
                if ((wtEOperator(pTerm) & (WO_EQ | WO_IS)) != 0 and
                    (wtWtFlags(pTerm) & TERM_HEURTRUTH) == 0)
                {
                    const pRight = exprRight(pOpExpr);
                    const pParse = wiParse(wcWInfo(pWC));
                    var k: c_int = 0;
                    if (c.sqlite3ExprIsInteger(pRight, &k, pParse) != 0 and k >= -1 and k <= 1) {
                        k = 10;
                    } else {
                        k = 20;
                    }
                    if (iReduce < k) {
                        wtSetWtFlags(pTerm, wtWtFlags(pTerm) | TERM_HEURTRUTH);
                        iReduce = @intCast(k);
                    }
                } else if (hasProp(pOpExpr, EP_InfixFunc) and exprOp(pOpExpr) == TK_FUNCTION) {
                    var eOp = c.sqlite3ExprIsLikeOperator(pOpExpr);
                    if (eOp > 0) {
                        const pRHS = elItemExpr(rdp(pOpExpr, Expr_x), 0);
                        eOp = @intFromBool(eOp == IC_LIKE);
                        const szPattern = estLikePatternLength(pRHS, @intCast(eOp));
                        if (szPattern > 0) {
                            wr(LogEst, pLoop, WhereLoop_nOut, wlNOut(pLoop) - @as(LogEst, @intCast(szPattern * 2)));
                        }
                    }
                }
            }
        }
    }
    if (wlNOut(pLoop) > nRow - iReduce) {
        wr(LogEst, pLoop, WhereLoop_nOut, nRow - iReduce);
    }
}

fn whereRangeVectorLen(pParse: Ptr, iCur: c_int, pIdx: Ptr, nEq: c_int, pTerm: Ptr) c_int {
    var nCmp = c.sqlite3ExprVectorSize(exprLeft(wtExpr(pTerm)));
    nCmp = imin(nCmp, idxNColumn(pIdx) - nEq);
    var i: c_int = 1;
    while (i < nCmp) : (i += 1) {
        const pLhs = elItemExpr(rdp(exprLeft(wtExpr(pTerm)), Expr_x), @intCast(i));
        var pRhs = exprRight(wtExpr(pTerm));
        if ((exprFlags(pRhs) & EP_xIsSelect) != 0) {
            pRhs = elItemExpr(rdp(rdp(pRhs, Expr_x), Select_pEList), @intCast(i));
        } else {
            pRhs = elItemExpr(rdp(pRhs, Expr_x), @intCast(i));
        }
        if (exprOp(pLhs) != TK_COLUMN or
            exprITable(pLhs) != iCur or
            exprIColumn(pLhs) != idxAiColumn(pIdx)[@intCast(i + nEq)] or
            idxASortOrder(pIdx)[@intCast(i + nEq)] != idxASortOrder(pIdx)[@intCast(nEq)])
        {
            break;
        }
        const aff = c.sqlite3CompareAffinity(pRhs, c.sqlite3ExprAffinity(pLhs));
        const idxaff = c.sqlite3TableColumnAffinity(rdp(pIdx, Index_pTable), exprIColumn(pLhs));
        if (aff != idxaff) break;
        var pL = pLhs;
        var pR = pRhs;
        if (hasProp(wtExpr(pTerm), 0x000400)) { // EP_Commuted
            const tmp = pR;
            pR = pL;
            pL = tmp;
        }
        const pColl = c.sqlite3BinaryCompareCollSeq(pParse, pL, pR);
        if (pColl == null) break;
        if (c.sqlite3StrICmp(rd(?[*:0]const u8, pColl, CollSeq_zName), idxAzColl(pIdx)[@intCast(i + nEq)]) != 0) break;
    }
    return i;
}

// ════════════════════════════════════════════════════════════════════════════
// whereLoopInsert and friends
// ════════════════════════════════════════════════════════════════════════════

fn whereLoopCheaperProperSubset(pX: Ptr, pY: Ptr) c_int {
    if (wlRRun(pX) > wlRRun(pY) and wlNOut(pX) > wlNOut(pY)) return 0;
    if (wlNEq(pX) < wlNEq(pY) and
        wlPIndex(pX) == wlPIndex(pY) and
        wlNSkip(pX) == 0 and wlNSkip(pY) == 0)
    {
        return 1;
    }
    if (wlNLTerm(pX) - wlNSkip(pX) >= wlNLTerm(pY) - wlNSkip(pY)) return 0;
    if (wlNSkip(pY) > wlNSkip(pX)) return 0;
    var i: c_int = wlNLTerm(pX) - 1;
    while (i >= 0) : (i -= 1) {
        if (wlALTermAt(pX, @intCast(i)) == null) continue;
        var j: c_int = wlNLTerm(pY) - 1;
        while (j >= 0) : (j -= 1) {
            if (wlALTermAt(pY, @intCast(j)) == wlALTermAt(pX, @intCast(i))) break;
        }
        if (j < 0) return 0;
    }
    if ((wlWsFlags(pX) & WHERE_IDX_ONLY) != 0 and (wlWsFlags(pY) & WHERE_IDX_ONLY) == 0) {
        return 0;
    }
    return 1;
}

fn whereLoopAdjustCost(p0: Ptr, pTemplate: Ptr) void {
    if ((wlWsFlags(pTemplate) & WHERE_INDEXED) == 0) return;
    var p = p0;
    while (p != null) : (p = wlNext(p)) {
        if (wlITab(p) != wlITab(pTemplate)) continue;
        if ((wlWsFlags(p) & WHERE_INDEXED) == 0) continue;
        if (whereLoopCheaperProperSubset(p, pTemplate) != 0) {
            wr(LogEst, pTemplate, WhereLoop_rRun, imin(wlRRun(p), wlRRun(pTemplate)));
            wr(LogEst, pTemplate, WhereLoop_nOut, imin(wlNOut(p) - 1, wlNOut(pTemplate)));
        } else if (whereLoopCheaperProperSubset(pTemplate, p) != 0) {
            wr(LogEst, pTemplate, WhereLoop_rRun, imax(wlRRun(p), wlRRun(pTemplate)));
            wr(LogEst, pTemplate, WhereLoop_nOut, imax(wlNOut(p) + 1, wlNOut(pTemplate)));
        }
    }
}

// returns the **WhereLoop link to overwrite, or null (sentinel) meaning "discard"
fn whereLoopFindLesser(ppPrev0: *Ptr, pTemplate: Ptr) ?*Ptr {
    var ppPrev = ppPrev0;
    var p = ppPrev.*;
    while (p != null) {
        if (wlITab(p) != wlITab(pTemplate) or
            rd(u8, p, WhereLoop_iSortIdx) != rd(u8, pTemplate, WhereLoop_iSortIdx))
        {
            ppPrev = @ptrCast(@alignCast(fieldPtr(p, WhereLoop_pNextLoop)));
            p = ppPrev.*;
            continue;
        }
        if ((wlWsFlags(p) & WHERE_AUTO_INDEX) != 0 and
            wlNSkip(pTemplate) == 0 and
            (wlWsFlags(pTemplate) & WHERE_INDEXED) != 0 and
            (wlWsFlags(pTemplate) & WHERE_COLUMN_EQ) != 0 and
            (wlPrereq(p) & wlPrereq(pTemplate)) == wlPrereq(pTemplate))
        {
            break;
        }
        if ((wlPrereq(p) & wlPrereq(pTemplate)) == wlPrereq(p) and
            wlRSetup(p) <= wlRSetup(pTemplate) and
            wlRRun(p) <= wlRRun(pTemplate) and
            wlNOut(p) <= wlNOut(pTemplate))
        {
            return null; // discard pTemplate
        }
        if ((wlPrereq(p) & wlPrereq(pTemplate)) == wlPrereq(pTemplate) and
            wlRRun(p) >= wlRRun(pTemplate) and
            wlNOut(p) >= wlNOut(pTemplate))
        {
            break;
        }
        ppPrev = @ptrCast(@alignCast(fieldPtr(p, WhereLoop_pNextLoop)));
        p = ppPrev.*;
    }
    return ppPrev;
}

fn whereLoopInsert(pBuilder: Ptr, pTemplate: Ptr) c_int {
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    const db = parseDb(wiParse(pWInfo));

    if (rd(u32, pBuilder, WhereLoopBuilder_iPlanLimit) == 0) {
        if (rdp(pBuilder, WhereLoopBuilder_pOrSet) != null) {
            wr(u16, rdp(pBuilder, WhereLoopBuilder_pOrSet), WhereOrSet_n, 0);
        }
        return SQLITE_DONE;
    }
    wr(u32, pBuilder, WhereLoopBuilder_iPlanLimit, rd(u32, pBuilder, WhereLoopBuilder_iPlanLimit) - 1);

    whereLoopAdjustCost(rdp(pWInfo, WhereInfo_pLoops), pTemplate);

    if (rdp(pBuilder, WhereLoopBuilder_pOrSet) != null) {
        if (wlNLTerm(pTemplate) != 0) {
            _ = whereOrInsert(rdp(pBuilder, WhereLoopBuilder_pOrSet), wlPrereq(pTemplate), wlRRun(pTemplate), wlNOut(pTemplate));
        }
        return SQLITE_OK;
    }

    // whereLoopFindLesser operates on the live WhereInfo.pLoops slot.
    const headPtr: *Ptr = @ptrCast(@alignCast(fieldPtr(pWInfo, WhereInfo_pLoops)));
    const ppPrevOpt = whereLoopFindLesser(headPtr, pTemplate);
    if (ppPrevOpt == null) {
        return SQLITE_OK; // existing loop better; ignore
    }
    const ppPrev = ppPrevOpt.?;
    var p = ppPrev.*;

    if (p == null) {
        p = c.sqlite3DbMallocRawNN(db, sizeof_WhereLoop);
        if (p == null) return SQLITE_NOMEM;
        ppPrev.* = p;
        whereLoopInit(p);
        wr(?*anyopaque, p, WhereLoop_pNextLoop, null);
    } else {
        var ppTail: *Ptr = @ptrCast(@alignCast(fieldPtr(p, WhereLoop_pNextLoop)));
        while (ppTail.* != null) {
            const t = whereLoopFindLesser(ppTail, pTemplate);
            if (t == null) break;
            ppTail = t.?;
            const pToDel = ppTail.*;
            if (pToDel == null) break;
            ppTail.* = wlNext(pToDel);
            whereLoopDelete(db, pToDel);
        }
    }
    const rc = whereLoopXfer(db, p, pTemplate);
    if ((wlWsFlags(p) & WHERE_VIRTUALTABLE) == 0) {
        const pIndex = wlPIndex(p);
        if (pIndex != null and idxType(pIndex) == SQLITE_IDXTYPE_IPK) {
            wr(?*anyopaque, p, WhereLoop_u_btree_pIndex, null);
        }
    }
    return rc;
}

// ════════════════════════════════════════════════════════════════════════════
// whereLoopAddBtreeIndex
// ════════════════════════════════════════════════════════════════════════════

fn whereLoopAddBtreeIndex(pBuilder: Ptr, pSrc: Ptr, pProbe: Ptr, nInMul: LogEst) c_int {
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    const pParse = wiParse(pWInfo);
    const db = parseDb(pParse);
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);
    var rc: c_int = SQLITE_OK;
    var pTop: Ptr = null;
    var pBtm: Ptr = null;

    if (rd(c_int, pParse, Parse_nErr) != 0) {
        return rd(c_int, pParse, Parse_rc);
    }

    var opMask: u32 = undefined;
    if ((wlWsFlags(pNew) & WHERE_BTM_LIMIT) != 0) {
        opMask = WO_LT | WO_LE;
    } else {
        opMask = WO_EQ | WO_IN | WO_GT | WO_GE | WO_LT | WO_LE | WO_ISNULL | WO_IS;
    }
    if (idxBUnordered(pProbe)) {
        opMask &= ~@as(u32, WO_GT | WO_GE | WO_LT | WO_LE);
    }

    const saved_nEq = rd(u16, pNew, WhereLoop_u_btree_nEq);
    const saved_nBtm = rd(u16, pNew, WhereLoop_u_btree_nBtm);
    const saved_nTop = rd(u16, pNew, WhereLoop_u_btree_nTop);
    const saved_nSkip = rd(u16, pNew, WhereLoop_nSkip);
    const saved_nLTerm = rd(u16, pNew, WhereLoop_nLTerm);
    const saved_wsFlags = wlWsFlags(pNew);
    const saved_prereq = wlPrereq(pNew);
    const saved_nOut = wlNOut(pNew);

    var scan: [sizeof_WhereScan_buf]u8 align(8) = undefined;
    @memset(&scan, 0);
    const pScan: Ptr = @ptrCast(&scan);
    var pTerm = whereScanInit(pScan, rdp(pBuilder, WhereLoopBuilder_pWC), rd(c_int, pSrc, SrcItem_iCursor), saved_nEq, opMask, pProbe);
    wr(LogEst, pNew, WhereLoop_rSetup, 0);
    const rSize = idxAiRowLogEst(pProbe)[0];
    const rLogSize = estLog(rSize);

    while (rc == SQLITE_OK and pTerm != null) : (pTerm = whereScanNext(pScan)) {
        const eOp = wtEOperator(pTerm);
        var nIn: LogEst = 0;
        if ((eOp == WO_ISNULL or (wtWtFlags(pTerm) & TERM_VNULL) != 0) and
            indexColumnNotNull(pProbe, @intCast(saved_nEq)) != 0)
        {
            continue;
        }
        if ((wtPrereqRight(pTerm) & wlMaskSelf(pNew)) != 0) continue;
        if ((wtWtFlags(pTerm) & TERM_LIKEOPT) != 0 and wtEOperator(pTerm) == WO_LT) continue;
        if ((fgJoin(pSrc) & @as(u8, @intCast(JT_LEFT | JT_LTORJ | JT_RIGHT))) != 0 and
            constraintCompatibleWithOuterJoin(pTerm, pSrc) == 0)
        {
            continue;
        }
        if (isUniqueIndex(pProbe) and saved_nEq == idxNKeyCol(pProbe) - 1) {
            wr(u8, pBuilder, WhereLoopBuilder_bldFlags1, rd(u8, pBuilder, WhereLoopBuilder_bldFlags1) | SQLITE_BLDF1_UNIQUE);
        } else {
            wr(u8, pBuilder, WhereLoopBuilder_bldFlags1, rd(u8, pBuilder, WhereLoopBuilder_bldFlags1) | SQLITE_BLDF1_INDEXED);
        }
        wlSetWsFlags(pNew, saved_wsFlags);
        wr(u16, pNew, WhereLoop_u_btree_nEq, saved_nEq);
        wr(u16, pNew, WhereLoop_u_btree_nBtm, saved_nBtm);
        wr(u16, pNew, WhereLoop_u_btree_nTop, saved_nTop);
        wr(u16, pNew, WhereLoop_nLTerm, saved_nLTerm);
        if (wlNLTerm(pNew) >= rd(u16, pNew, WhereLoop_nLSlot) and
            whereLoopResize(db, pNew, wlNLTerm(pNew) + 1) != 0)
        {
            break;
        }
        wlALTerm(pNew)[@intCast(wlNLTerm(pNew))] = pTerm;
        wr(u16, pNew, WhereLoop_nLTerm, @intCast(wlNLTerm(pNew) + 1));
        wr(Bitmask, pNew, WhereLoop_prereq, (saved_prereq | wtPrereqRight(pTerm)) & ~wlMaskSelf(pNew));

        if ((eOp & WO_IN) != 0) {
            const pExpr = wtExpr(pTerm);
            if ((exprFlags(pExpr) & EP_xIsSelect) != 0) {
                var bRedundant = false;
                nIn = 46;
                var i: c_int = 0;
                while (i < wlNLTerm(pNew) - 1) : (i += 1) {
                    const aTi = wlALTermAt(pNew, @intCast(i));
                    if (aTi != null and wtExpr(aTi) == pExpr) {
                        nIn = 0;
                        if (wtIField(aTi) == wtIField(pTerm)) bRedundant = true;
                    }
                }
                if (bRedundant) {
                    wr(u16, pNew, WhereLoop_nLTerm, @intCast(wlNLTerm(pNew) - 1));
                    continue;
                }
            } else {
                const pList = rdp(pExpr, Expr_x);
                if (pList != null and elNExpr(pList) != 0) {
                    nIn = c.sqlite3LogEst(@intCast(elNExpr(pList)));
                }
            }
            if (idxHasStat1(pProbe) and rLogSize >= 10) {
                const M = idxAiRowLogEst(pProbe)[@intCast(saved_nEq)];
                const logK = estLog(nIn);
                const x = M + logK + 10 - (nIn + rLogSize);
                if (x >= 0) {
                    // prefers indexed lookup
                } else if (nInMul < 2 and optimizationEnabled(db, SQLITE_SeekScan)) {
                    wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_IN_SEEKSCAN);
                } else {
                    continue;
                }
            }
            wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COLUMN_IN);
        } else if ((eOp & (WO_EQ | WO_IS)) != 0) {
            const iCol = idxAiColumn(pProbe)[@intCast(saved_nEq)];
            wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COLUMN_EQ);
            if (iCol == XN_ROWID or
                (iCol >= 0 and nInMul == 0 and saved_nEq == idxNKeyCol(pProbe) - 1))
            {
                if (iCol == XN_ROWID or idxUniqNotNull(pProbe) or
                    (idxNKeyCol(pProbe) == 1 and rd(u8, pProbe, Index_onError) != 0 and (eOp & WO_EQ) != 0))
                {
                    wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_ONEROW);
                } else {
                    wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_UNQ_WANTED);
                }
            }
            if (rd(u8, pScan, WhereScan_iEquiv) > 1) wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_TRANSCONS);
        } else if ((eOp & WO_ISNULL) != 0) {
            wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COLUMN_NULL);
        } else {
            const nVecLen = whereRangeVectorLen(pParse, rd(c_int, pSrc, SrcItem_iCursor), pProbe, saved_nEq, pTerm);
            if ((eOp & (WO_GT | WO_GE)) != 0) {
                wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COLUMN_RANGE | WHERE_BTM_LIMIT);
                wr(u16, pNew, WhereLoop_u_btree_nBtm, @intCast(nVecLen));
                pBtm = pTerm;
                pTop = null;
                if ((wtWtFlags(pTerm) & TERM_LIKEOPT) != 0) {
                    pTop = fieldPtr(pTerm, sizeof_WhereTerm);
                    if (whereLoopResize(db, pNew, wlNLTerm(pNew) + 1) != 0) break;
                    wlALTerm(pNew)[@intCast(wlNLTerm(pNew))] = pTop;
                    wr(u16, pNew, WhereLoop_nLTerm, @intCast(wlNLTerm(pNew) + 1));
                    wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_TOP_LIMIT);
                    wr(u16, pNew, WhereLoop_u_btree_nTop, 1);
                }
            } else {
                wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COLUMN_RANGE | WHERE_TOP_LIMIT);
                wr(u16, pNew, WhereLoop_u_btree_nTop, @intCast(nVecLen));
                pTop = pTerm;
                pBtm = if ((wlWsFlags(pNew) & WHERE_BTM_LIMIT) != 0) wlALTermAt(pNew, @intCast(wlNLTerm(pNew) - 2)) else null;
            }
        }

        if ((wlWsFlags(pNew) & WHERE_COLUMN_RANGE) != 0) {
            _ = whereRangeScanEst(pParse, pBuilder, pBtm, pTop, pNew);
        } else {
            wr(u16, pNew, WhereLoop_u_btree_nEq, @intCast(wlNEq(pNew) + 1));
            const nEq = wlNEq(pNew);
            if (wtTruthProb(pTerm) <= 0 and idxAiColumn(pProbe)[@intCast(saved_nEq)] >= 0) {
                wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) + wtTruthProb(pTerm));
                wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) - nIn);
            } else {
                wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) + (idxAiRowLogEst(pProbe)[@intCast(nEq)] - idxAiRowLogEst(pProbe)[@intCast(nEq - 1)]));
                if ((eOp & WO_ISNULL) != 0) {
                    wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) + 10);
                }
            }
        }

        var rCostIdx: LogEst = undefined;
        if (idxType(pProbe) == SQLITE_IDXTYPE_IPK) {
            rCostIdx = wlNOut(pNew) + 16;
        } else {
            const szIdx = rd(LogEst, pProbe, Index_szIdxRow);
            const szTab = rd(LogEst, rdp(pSrc, SrcItem_pSTab), Table_szTabRow);
            rCostIdx = wlNOut(pNew) + 1 + @as(LogEst, @intCast(@divTrunc(15 * @as(c_int, szIdx), @as(c_int, szTab))));
        }
        rCostIdx = c.sqlite3LogEstAdd(rLogSize, rCostIdx);

        wr(LogEst, pNew, WhereLoop_rRun, rCostIdx);
        if ((wlWsFlags(pNew) & (WHERE_IDX_ONLY | WHERE_IPK | WHERE_EXPRIDX)) == 0) {
            wr(LogEst, pNew, WhereLoop_rRun, c.sqlite3LogEstAdd(wlRRun(pNew), wlNOut(pNew) + 16));
        }

        const nOutUnadjusted = wlNOut(pNew);
        wr(LogEst, pNew, WhereLoop_rRun, wlRRun(pNew) + nInMul + nIn);
        wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) + nInMul + nIn);
        whereLoopOutputAdjust(rdp(pBuilder, WhereLoopBuilder_pWC), pNew, rSize);
        if ((fgB3(pSrc) & FG_fromExists) != 0) wr(LogEst, pNew, WhereLoop_nOut, 0);
        rc = whereLoopInsert(pBuilder, pNew);

        if ((wlWsFlags(pNew) & WHERE_COLUMN_RANGE) != 0) {
            wr(LogEst, pNew, WhereLoop_nOut, saved_nOut);
        } else {
            wr(LogEst, pNew, WhereLoop_nOut, nOutUnadjusted);
        }

        if ((wlWsFlags(pNew) & WHERE_TOP_LIMIT) == 0 and
            wlNEq(pNew) < idxNColumn(pProbe) and
            (wlNEq(pNew) < idxNKeyCol(pProbe) or idxType(pProbe) != SQLITE_IDXTYPE_PRIMARYKEY))
        {
            if (wlNEq(pNew) > 3) _ = c.sqlite3ProgressCheck(pParse);
            _ = whereLoopAddBtreeIndex(pBuilder, pSrc, pProbe, nInMul + nIn);
        }
        wr(LogEst, pNew, WhereLoop_nOut, saved_nOut);
    }
    wr(Bitmask, pNew, WhereLoop_prereq, saved_prereq);
    wr(u16, pNew, WhereLoop_u_btree_nEq, saved_nEq);
    wr(u16, pNew, WhereLoop_u_btree_nBtm, saved_nBtm);
    wr(u16, pNew, WhereLoop_u_btree_nTop, saved_nTop);
    wr(u16, pNew, WhereLoop_nSkip, saved_nSkip);
    wlSetWsFlags(pNew, saved_wsFlags);
    wr(LogEst, pNew, WhereLoop_nOut, saved_nOut);
    wr(u16, pNew, WhereLoop_nLTerm, saved_nLTerm);

    if (saved_nEq == saved_nSkip and
        saved_nEq + 1 < idxNKeyCol(pProbe) and
        saved_nEq == wlNLTerm(pNew) and
        !idxNoSkipScan(pProbe) and
        idxHasStat1(pProbe) and
        optimizationEnabled(db, SQLITE_SkipScan) and
        idxAiRowLogEst(pProbe)[@intCast(saved_nEq + 1)] >= 42 and
        (fgB3(pSrc) & FG_fromExists) == 0 and
        blk: {
            rc = whereLoopResize(db, pNew, wlNLTerm(pNew) + 1);
            break :blk rc == SQLITE_OK;
        })
    {
        wr(u16, pNew, WhereLoop_u_btree_nEq, @intCast(wlNEq(pNew) + 1));
        wr(u16, pNew, WhereLoop_nSkip, @intCast(wlNSkip(pNew) + 1));
        wlALTerm(pNew)[@intCast(wlNLTerm(pNew))] = null;
        wr(u16, pNew, WhereLoop_nLTerm, @intCast(wlNLTerm(pNew) + 1));
        wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_SKIPSCAN);
        var nIter = idxAiRowLogEst(pProbe)[@intCast(saved_nEq)] - idxAiRowLogEst(pProbe)[@intCast(saved_nEq + 1)];
        wr(LogEst, pNew, WhereLoop_nOut, wlNOut(pNew) - nIter);
        nIter += 5;
        _ = whereLoopAddBtreeIndex(pBuilder, pSrc, pProbe, nIter + nInMul);
        wr(LogEst, pNew, WhereLoop_nOut, saved_nOut);
        wr(u16, pNew, WhereLoop_u_btree_nEq, saved_nEq);
        wr(u16, pNew, WhereLoop_nSkip, saved_nSkip);
        wlSetWsFlags(pNew, saved_wsFlags);
    }
    return rc;
}

// ════════════════════════════════════════════════════════════════════════════
// Index helpers used by whereLoopAddBtree
// ════════════════════════════════════════════════════════════════════════════

fn indexMightHelpWithOrderBy(pBuilder: Ptr, pIndex: Ptr, iCursor: c_int) c_int {
    if (idxBUnordered(pIndex)) return 0;
    const pOB = rdp(rdp(pBuilder, WhereLoopBuilder_pWInfo), WhereInfo_pOrderBy);
    if (pOB == null) return 0;
    var ii: c_int = 0;
    const n = elNExpr(pOB);
    while (ii < n) : (ii += 1) {
        const pExpr = c.sqlite3ExprSkipCollateAndLikely(elItemExpr(pOB, @intCast(ii)));
        if (pExpr == null) continue;
        if ((exprOp(pExpr) == TK_COLUMN or exprOp(pExpr) == TK_AGG_COLUMN) and
            exprITable(pExpr) == iCursor)
        {
            if (exprIColumn(pExpr) < 0) return 1;
            var jj: c_int = 0;
            const nk = idxNKeyCol(pIndex);
            while (jj < nk) : (jj += 1) {
                if (exprIColumn(pExpr) == idxAiColumn(pIndex)[@intCast(jj)]) return 1;
            }
        } else {
            const aColExpr = rdp(pIndex, Index_aColExpr);
            if (aColExpr != null) {
                var jj: c_int = 0;
                const nk = idxNKeyCol(pIndex);
                while (jj < nk) : (jj += 1) {
                    if (idxAiColumn(pIndex)[@intCast(jj)] != XN_EXPR) continue;
                    if (c.sqlite3ExprCompareSkip(pExpr, elItemExpr(aColExpr, @intCast(jj)), iCursor) == 0) return 1;
                }
            }
        }
    }
    return 0;
}

const JT_OUTER_C: u8 = @intCast(JT_OUTER);
fn whereUsablePartialIndex(iTab: c_int, jointype: u8, pWC: Ptr, pWhere0: Ptr) c_int {
    var pWhere = pWhere0;
    if ((jointype & @as(u8, @intCast(JT_LTORJ))) != 0) return 0;
    const pParse = wiParse(wcWInfo(pWC));
    while (exprOp(pWhere) == TK_AND) {
        if (whereUsablePartialIndex(iTab, jointype, pWC, exprLeft(pWhere)) == 0) return 0;
        pWhere = exprRight(pWhere);
    }
    var i: c_int = 0;
    var pTerm = wcA(pWC);
    const nt = wcNTerm(pWC);
    while (i < nt) : ({
        i += 1;
        pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
    }) {
        const pExpr = wtExpr(pTerm);
        if ((!hasProp(pExpr, EP_OuterON) or rd(c_int, pExpr, Expr_w_iJoin) == iTab) and
            ((jointype & JT_OUTER_C) == 0 or hasProp(pExpr, EP_OuterON)) and
            c.sqlite3ExprImpliesExpr(pParse, pExpr, pWhere, iTab) != 0 and
            c.sqlite3ExprImpliesExpr(pParse, pExpr, pWhere, -1) == 0 and
            (wtWtFlags(pTerm) & TERM_VNULL) == 0)
        {
            return 1;
        }
    }
    return 0;
}

fn exprIsCoveredByIndex(pExpr: Ptr, pIdx: Ptr, iTabCur: c_int) c_int {
    var i: c_int = 0;
    const n = idxNColumn(pIdx);
    while (i < n) : (i += 1) {
        if (idxAiColumn(pIdx)[@intCast(i)] == XN_EXPR and
            c.sqlite3ExprCompare(null, pExpr, elItemExpr(rdp(pIdx, Index_aColExpr), @intCast(i)), iTabCur) == 0)
        {
            return 1;
        }
    }
    return 0;
}

// CoveringIndexCheck: pIdx(0), iTabCur(8), bExpr(12), bUnidx(13)
const CIC_pIdx: usize = 0;
const CIC_iTabCur: usize = 8;
const CIC_bExpr: usize = 12;
const CIC_bUnidx: usize = 13;
const sizeof_CIC: usize = 16;
const Walker_u_pCovIdxCk = Walker_u;

fn whereIsCoveringIndexWalkCallback(pWalk: Ptr, pExpr: Ptr) callconv(.c) c_int {
    const pCk = rdp(pWalk, Walker_u_pCovIdxCk);
    var pIdx = rdp(pCk, CIC_pIdx);
    if (exprOp(pExpr) == TK_COLUMN or exprOp(pExpr) == TK_AGG_COLUMN) {
        if (exprITable(pExpr) != rd(c_int, pCk, CIC_iTabCur)) return WRC_Continue;
        pIdx = rdp(pCk, CIC_pIdx);
        const nColumn = idxNColumn(pIdx);
        var i: c_int = 0;
        while (i < nColumn) : (i += 1) {
            if (idxAiColumn(pIdx)[@intCast(i)] == exprIColumn(pExpr)) return WRC_Continue;
        }
        wr(u8, pCk, CIC_bUnidx, 1);
        return WRC_Abort;
    } else if (idxBHasExpr(pIdx) and exprIsCoveredByIndex(pExpr, pIdx, rd(c_int, pCk, CIC_iTabCur)) != 0) {
        wr(u8, pCk, CIC_bExpr, 1);
        return WRC_Prune;
    }
    return WRC_Continue;
}

fn whereIsCoveringIndex(pWInfo: Ptr, pIdx: Ptr, iTabCur: c_int) u32 {
    if (rdp(pWInfo, WhereInfo_pSelect) == null) return 0;
    if (!idxBHasExpr(pIdx)) {
        var i: c_int = 0;
        const n = idxNColumn(pIdx);
        while (i < n) : (i += 1) {
            if (idxAiColumn(pIdx)[@intCast(i)] >= BMS - 1) break;
        }
        if (i >= n) return 0;
    }
    var ck: [sizeof_CIC]u8 align(8) = undefined;
    @memset(&ck, 0);
    const ckp: Ptr = @ptrCast(&ck);
    wr(?*anyopaque, ckp, CIC_pIdx, pIdx);
    wr(c_int, ckp, CIC_iTabCur, iTabCur);
    wr(u8, ckp, CIC_bExpr, 0);
    wr(u8, ckp, CIC_bUnidx, 0);
    var w: [sizeof_Walker]u8 align(8) = undefined;
    @memset(&w, 0);
    const wp: Ptr = @ptrCast(&w);
    wr(?*anyopaque, wp, Walker_xExprCallback, @constCast(@ptrCast(&whereIsCoveringIndexWalkCallback)));
    wr(?*anyopaque, wp, Walker_xSelectCallback, @constCast(@ptrCast(&c.sqlite3SelectWalkNoop)));
    wr(?*anyopaque, wp, Walker_u, ckp);
    _ = c.sqlite3WalkSelect(wp, rdp(pWInfo, WhereInfo_pSelect));
    if (rd(u8, ckp, CIC_bUnidx) != 0) {
        return 0;
    } else if (rd(u8, ckp, CIC_bExpr) != 0) {
        return WHERE_EXPRIDX;
    } else {
        return WHERE_IDX_ONLY;
    }
}

fn whereIndexedExprCleanup(db: Ptr, pObject: Ptr) callconv(.c) void {
    const pp: *Ptr = @ptrCast(@alignCast(pObject.?));
    while (pp.* != null) {
        const p = pp.*;
        pp.* = rdp(p, IndexedExpr_pIENext);
        c.sqlite3ExprDelete(db, rdp(p, IndexedExpr_pExpr));
        c.sqlite3DbFreeNN(db, p);
    }
}

fn wherePartIdxExpr(pParse: Ptr, pIdx: Ptr, pPart0: Ptr, pMask: ?*Bitmask, iIdxCur: c_int, pItem: Ptr) void {
    var pPart = pPart0;
    if (exprOp(pPart) == TK_AND) {
        wherePartIdxExpr(pParse, pIdx, exprRight(pPart), pMask, iIdxCur, pItem);
        pPart = exprLeft(pPart);
    }
    if (exprOp(pPart) == TK_EQ or exprOp(pPart) == TK_IS) {
        const pLeft = exprLeft(pPart);
        const pRight = exprRight(pPart);
        if (exprOp(pLeft) != TK_COLUMN) return;
        if (c.sqlite3ExprIsConstant(null, pRight) == 0) return;
        if (c.sqlite3IsBinary(c.sqlite3ExprCompareCollSeq(pParse, pPart)) == 0) return;
        if (exprIColumn(pLeft) < 0) return;
        const aff = colAffinity(rdp(pIdx, Index_pTable), @intCast(exprIColumn(pLeft)));
        if (aff >= SQLITE_AFF_TEXT) {
            if (pItem != null) {
                const db = parseDb(pParse);
                const p = c.sqlite3DbMallocRaw(db, sizeof_IndexedExpr);
                if (p != null) {
                    const bNullRow: u8 = @intFromBool((fgJoin(pItem) & @as(u8, @intCast(JT_LEFT | JT_LTORJ))) != 0);
                    wr(?*anyopaque, p, IndexedExpr_pExpr, c.sqlite3ExprDup(db, pRight, 0));
                    wr(c_int, p, IndexedExpr_iDataCur, rd(c_int, pItem, SrcItem_iCursor));
                    wr(c_int, p, IndexedExpr_iIdxCur, iIdxCur);
                    wr(c_int, p, IndexedExpr_iIdxCol, exprIColumn(pLeft));
                    wr(u8, p, IndexedExpr_bMaybeNullRow, bNullRow);
                    wr(?*anyopaque, p, IndexedExpr_pIENext, rdp(pParse, Parse_pIdxPartExpr));
                    wr(u8, p, IndexedExpr_aff, aff);
                    wr(?*anyopaque, pParse, Parse_pIdxPartExpr, p);
                    if (rdp(p, IndexedExpr_pIENext) == null) {
                        c.sqlite3ParserAddCleanup(pParse, &whereIndexedExprCleanup, fieldPtr(pParse, Parse_pIdxPartExpr));
                    }
                }
            } else if (exprIColumn(pLeft) < BMS - 1) {
                if (pMask) |m| {
                    m.* &= ~(@as(Bitmask, 1) << @intCast(exprIColumn(pLeft)));
                }
            }
        }
    }
}

// ════════════════════════════════════════════════════════════════════════════
// whereLoopAddBtree
// ════════════════════════════════════════════════════════════════════════════

fn whereLoopAddBtree(pBuilder: Ptr, mPrereq: Bitmask) c_int {
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    const pTabList = rdp(pWInfo, WhereInfo_pTabList);
    const pSrc = slItem(pTabList, wlITab(pNew));
    const pTab = rdp(pSrc, SrcItem_pSTab);
    const pWC = rdp(pBuilder, WhereLoopBuilder_pWC);
    var rc: c_int = SQLITE_OK;
    var iSortIdx: c_int = 1;

    // fake sPk Index object on the stack
    var sPkBuf: [sizeof_Index]u8 align(8) = undefined;
    @memset(&sPkBuf, 0);
    const sPk: Ptr = @ptrCast(&sPkBuf);
    var aiRowEstPk: [2]LogEst = undefined;
    var aiColumnPk: i16 = -1;

    var pProbe: Ptr = undefined;
    if ((fgB1(pSrc) & FG_isIndexedBy) != 0) {
        pProbe = rdp(pSrc, SrcItem_u2_pIBIndex);
    } else if (!hasRowid(pTab)) {
        pProbe = rdp(pTab, Table_pIndex);
    } else {
        wr(u16, sPk, Index_nKeyCol, 1);
        wr(u16, sPk, Index_nColumn, 1);
        wr(?*anyopaque, sPk, Index_aiColumn, @ptrCast(&aiColumnPk));
        wr(?*anyopaque, sPk, Index_aiRowLogEst, @ptrCast(&aiRowEstPk));
        wr(u8, sPk, Index_onError, OE_Replace);
        wr(?*anyopaque, sPk, Index_pTable, pTab);
        wr(LogEst, sPk, Index_szIdxRow, 3);
        // idxType = SQLITE_IDXTYPE_IPK (3) — set the bitfield byte
        wr(u8, sPk, IDX_BITS_BYTE, (rd(u8, sPk, IDX_BITS_BYTE) & ~IDX_idxType_MASK) | SQLITE_IDXTYPE_IPK);
        aiRowEstPk[0] = rd(LogEst, pTab, Table_nRowLogEst);
        aiRowEstPk[1] = 0;
        const pFirst = rdp(rdp(pSrc, SrcItem_pSTab), Table_pIndex);
        if ((fgB1(pSrc) & FG_notIndexed) == 0) {
            wr(?*anyopaque, sPk, Index_pNext, pFirst);
        }
        pProbe = sPk;
    }
    var rSize = rd(LogEst, pTab, Table_nRowLogEst);

    // Automatic indexes
    if (rdp(pBuilder, WhereLoopBuilder_pOrSet) == null and
        (rd(u16, pWInfo, WhereInfo_wctrlFlags) & (WHERE_RIGHT_JOIN | WHERE_OR_SUBCLAUSE)) == 0 and
        (rd(u64, parseDb(wiParse(pWInfo)), db_flags) & SQLITE_AutoIndex) != 0 and
        (fgB1(pSrc) & FG_isIndexedBy) == 0 and
        (fgB1(pSrc) & FG_notIndexed) == 0 and
        (fgB1(pSrc) & FG_isCorrelated) == 0 and
        (fgB1(pSrc) & FG_isRecursive) == 0 and
        (fgJoin(pSrc) & @as(u8, @intCast(JT_RIGHT))) == 0)
    {
        const rLogSize = estLog(rSize);
        var pTerm = wcA(pWC);
        const nt = wcNTerm(pWC);
        var i: c_int = 0;
        while (rc == SQLITE_OK and i < nt) : ({
            i += 1;
            pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
        }) {
            if ((wtPrereqRight(pTerm) & wlMaskSelf(pNew)) != 0) continue;
            if (termCanDriveIndex(pTerm, pSrc, 0) != 0) {
                wr(u16, pNew, WhereLoop_u_btree_nEq, 1);
                wr(u16, pNew, WhereLoop_nSkip, 0);
                wr(?*anyopaque, pNew, WhereLoop_u_btree_pIndex, null);
                wr(u16, pNew, WhereLoop_nLTerm, 1);
                wlALTerm(pNew)[0] = pTerm;
                wr(LogEst, pNew, WhereLoop_rSetup, rLogSize + rSize);
                if (!isView(pTab) and (tabFlags(pTab) & TF_Ephemeral) == 0) {
                    wr(LogEst, pNew, WhereLoop_rSetup, wlRSetup(pNew) + 28);
                } else {
                    wr(LogEst, pNew, WhereLoop_rSetup, wlRSetup(pNew) - 25);
                }
                if (wlRSetup(pNew) < 0) wr(LogEst, pNew, WhereLoop_rSetup, 0);
                wr(LogEst, pNew, WhereLoop_nOut, 43);
                wr(LogEst, pNew, WhereLoop_rRun, c.sqlite3LogEstAdd(rLogSize, wlNOut(pNew)));
                wlSetWsFlags(pNew, WHERE_AUTO_INDEX);
                wr(Bitmask, pNew, WhereLoop_prereq, mPrereq | wtPrereqRight(pTerm));
                rc = whereLoopInsert(pBuilder, pNew);
            }
        }
    }

    while (rc == SQLITE_OK and pProbe != null) : ({
        pProbe = if ((fgB1(pSrc) & FG_isIndexedBy) != 0) null else rdp(pProbe, Index_pNext);
        iSortIdx += 1;
    }) {
        if (rdp(pProbe, Index_pPartIdxWhere) != null and
            whereUsablePartialIndex(rd(c_int, pSrc, SrcItem_iCursor), fgJoin(pSrc), pWC, rdp(pProbe, Index_pPartIdxWhere)) == 0)
        {
            continue;
        }
        if (idxBNoQuery(pProbe)) continue;
        rSize = idxAiRowLogEst(pProbe)[0];
        wr(u16, pNew, WhereLoop_u_btree_nEq, 0);
        wr(u16, pNew, WhereLoop_u_btree_nBtm, 0);
        wr(u16, pNew, WhereLoop_u_btree_nTop, 0);
        wr(u16, pNew, WhereLoop_u_btree_nDistinctCol, 0);
        wr(u16, pNew, WhereLoop_nSkip, 0);
        wr(u16, pNew, WhereLoop_nLTerm, 0);
        wr(u8, pNew, WhereLoop_iSortIdx, 0);
        wr(LogEst, pNew, WhereLoop_rSetup, 0);
        wr(Bitmask, pNew, WhereLoop_prereq, mPrereq);
        wr(LogEst, pNew, WhereLoop_nOut, rSize);
        wr(?*anyopaque, pNew, WhereLoop_u_btree_pIndex, pProbe);
        wr(?*anyopaque, pNew, WhereLoop_u_btree_pOrderBy, null);
        const b = indexMightHelpWithOrderBy(pBuilder, pProbe, rd(c_int, pSrc, SrcItem_iCursor));

        if (idxType(pProbe) == SQLITE_IDXTYPE_IPK) {
            wlSetWsFlags(pNew, WHERE_IPK);
            wr(u8, pNew, WhereLoop_iSortIdx, if (b != 0) @intCast(iSortIdx) else 0);
            wr(LogEst, pNew, WhereLoop_rRun, rSize + 16);
            whereLoopOutputAdjust(pWC, pNew, rSize);
            if ((fgB1(pSrc) & FG_isSubquery) != 0) {
                if ((fgB1(pSrc) & FG_viaCoroutine) != 0) wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_COROUTINE);
                const pSubq = rdp(pSrc, SrcItem_u4_pSubq);
                const pSel = rdp(pSubq, Subquery_pSelect);
                if ((rd(u32, pSel, Select_selFlags) & SF_Recursive) == 0) {
                    wr(?*anyopaque, pNew, WhereLoop_u_btree_pOrderBy, rdp(pSel, Select_pOrderBy));
                }
            } else if ((fgB3(pSrc) & FG_fromExists) != 0) {
                wr(LogEst, pNew, WhereLoop_nOut, 0);
            }
            rc = whereLoopInsert(pBuilder, pNew);
            wr(LogEst, pNew, WhereLoop_nOut, rSize);
            if (rc != 0) break;
        } else {
            var m: Bitmask = undefined;
            if (idxIsCovering(pProbe)) {
                m = 0;
                wlSetWsFlags(pNew, WHERE_IDX_ONLY | WHERE_INDEXED);
            } else {
                m = rd(Bitmask, pSrc, SrcItem_colUsed) & rd(Bitmask, pProbe, Index_colNotIdxed);
                if (rdp(pProbe, Index_pPartIdxWhere) != null) {
                    wherePartIdxExpr(wiParse(pWInfo), pProbe, rdp(pProbe, Index_pPartIdxWhere), &m, 0, null);
                }
                wlSetWsFlags(pNew, WHERE_INDEXED);
                if (m == TOPBIT or (idxBHasExpr(pProbe) and !idxBHasVCol(pProbe) and m != 0)) {
                    const isCov = whereIsCoveringIndex(pWInfo, pProbe, rd(c_int, pSrc, SrcItem_iCursor));
                    if (isCov == 0) {
                        // not covering
                    } else {
                        m = 0;
                        wlSetWsFlags(pNew, wlWsFlags(pNew) | isCov);
                    }
                } else if (m == 0 and
                    (hasRowid(pTab) or rdp(pWInfo, WhereInfo_pSelect) != null or c.sqlite3FaultSim(700) != 0))
                {
                    wlSetWsFlags(pNew, WHERE_IDX_ONLY | WHERE_INDEXED);
                }
            }

            if (b != 0 or
                !hasRowid(pTab) or
                rdp(pProbe, Index_pPartIdxWhere) != null or
                (fgB1(pSrc) & FG_isIndexedBy) != 0 or
                (m == 0 and
                    !idxBUnordered(pProbe) and
                    rd(LogEst, pProbe, Index_szIdxRow) < rd(LogEst, pTab, Table_szTabRow) and
                    (rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_ONEPASS_DESIRED) == 0 and
                    globalBUseCis() and
                    optimizationEnabled(parseDb(wiParse(pWInfo)), SQLITE_CoverIdxScan)))
            {
                wr(u8, pNew, WhereLoop_iSortIdx, if (b != 0) @intCast(iSortIdx) else 0);
                wr(LogEst, pNew, WhereLoop_rRun, rSize + 1 + @as(LogEst, @intCast(@divTrunc(15 * @as(c_int, rd(LogEst, pProbe, Index_szIdxRow)), @as(c_int, rd(LogEst, pTab, Table_szTabRow))))));
                if (m != 0) {
                    var nLookup = rSize + 16;
                    const iCur = rd(c_int, pSrc, SrcItem_iCursor);
                    const pWC2 = wiSWC(pWInfo);
                    var ii: c_int = 0;
                    const nt2 = wcNTerm(pWC2);
                    while (ii < nt2) : (ii += 1) {
                        const pTermL = wcTermAt(pWC2, ii);
                        if (c.sqlite3ExprCoveredByIndex(wtExpr(pTermL), iCur, pProbe) == 0) break;
                        if (wtTruthProb(pTermL) <= 0) {
                            nLookup += wtTruthProb(pTermL);
                        } else {
                            nLookup -= 1;
                            if ((wtEOperator(pTermL) & (WO_EQ | WO_IS)) != 0) nLookup -= 19;
                        }
                    }
                    wr(LogEst, pNew, WhereLoop_rRun, c.sqlite3LogEstAdd(wlRRun(pNew), nLookup));
                }
                whereLoopOutputAdjust(pWC, pNew, rSize);
                if ((fgJoin(pSrc) & @as(u8, @intCast(JT_RIGHT))) != 0 and rdp(pProbe, Index_aColExpr) != null) {
                    // skip
                } else {
                    if ((fgB3(pSrc) & FG_fromExists) != 0) wr(LogEst, pNew, WhereLoop_nOut, 0);
                    rc = whereLoopInsert(pBuilder, pNew);
                }
                wr(LogEst, pNew, WhereLoop_nOut, rSize);
                if (rc != 0) break;
            }
        }

        wr(u8, pBuilder, WhereLoopBuilder_bldFlags1, 0);
        rc = whereLoopAddBtreeIndex(pBuilder, pSrc, pProbe, 0);
        if (rd(u8, pBuilder, WhereLoopBuilder_bldFlags1) == SQLITE_BLDF1_INDEXED) {
            wr(u32, pTab, Table_tabFlags, tabFlags(pTab) | TF_MaybeReanalyze);
        }
    }
    return rc;
}
fn globalBUseCis() bool {
    const gc: [*]const u8 = @ptrCast(&c.sqlite3Config);
    return gc[GC_bUseCis] != 0;
}

// ════════════════════════════════════════════════════════════════════════════
// Virtual-table loops + public sqlite3_vtab_* interface
// ════════════════════════════════════════════════════════════════════════════

fn isLimitTerm(pTerm: Ptr) c_int {
    return @intFromBool(wtEMatchOp(pTerm) >= IC_LIMIT and wtEMatchOp(pTerm) <= IC_OFFSET);
}

fn allConstraintsUsed(pIdxInfo: Ptr, nCons: c_int) c_int {
    var ii: c_int = 0;
    while (ii < nCons) : (ii += 1) {
        if (rd(c_int, iiUsageAt(pIdxInfo, @intCast(ii)), IU_argvIndex) <= 0) return 0;
    }
    return 1;
}

fn whereLoopAddVirtualOne(pBuilder: Ptr, mPrereq: Bitmask, mUsable: Bitmask, mExclude: u16, pIdxInfo: Ptr, mNoOmit: u16, pbIn: *c_int, pbRetryLimit: ?*c_int) c_int {
    const pWC = rdp(pBuilder, WhereLoopBuilder_pWC);
    const pHidden = hiddenOf(pIdxInfo);
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);
    const pParse = wiParse(rdp(pBuilder, WhereLoopBuilder_pWInfo));
    const pSrc = slItem(rdp(rdp(pBuilder, WhereLoopBuilder_pWInfo), WhereInfo_pTabList), wlITab(pNew));
    const nConstraint = rd(c_int, pIdxInfo, II_nConstraint);
    var rc: c_int = SQLITE_OK;

    pbIn.* = 0;
    wr(Bitmask, pNew, WhereLoop_prereq, mPrereq);

    {
        var i: c_int = 0;
        while (i < nConstraint) : (i += 1) {
            const pIdxCons = iiConsAt(pIdxInfo, @intCast(i));
            const pTerm = termFromWhereClause(pWC, rd(c_int, pIdxCons, IC_iTermOffset));
            wr(u8, pIdxCons, IC_usable, 0);
            if ((wtPrereqRight(pTerm) & mUsable) == wtPrereqRight(pTerm) and
                (wtEOperator(pTerm) & mExclude) == 0 and
                (pbRetryLimit != null or isLimitTerm(pTerm) == 0))
            {
                wr(u8, pIdxCons, IC_usable, 1);
            }
        }
    }

    {
        const usage = rdp(pIdxInfo, II_aConstraintUsage);
        @memset(@as([*]u8, @ptrCast(usage.?))[0 .. sizeof_idxusage * @as(usize, @intCast(nConstraint))], 0);
    }
    wr(?*anyopaque, pIdxInfo, II_idxStr, null);
    wr(c_int, pIdxInfo, II_idxNum, 0);
    wr(c_int, pIdxInfo, II_orderByConsumed, 0);
    wr(f64, pIdxInfo, II_estimatedCost, SQLITE_BIG_DBL / 2.0);
    wr(i64, pIdxInfo, II_estimatedRows, 25);
    wr(c_int, pIdxInfo, II_idxFlags, 0);
    wr(u32, pHidden, HII_mHandleIn, 0);

    rc = vtabBestIndex(pParse, rdp(pSrc, SrcItem_pSTab), pIdxInfo);
    if (rc != 0) {
        if (rc == SQLITE_CONSTRAINT) {
            freeIdxStr(pIdxInfo);
            return SQLITE_OK;
        }
        return rc;
    }

    var mxTerm: c_int = -1;
    @memset(@as([*]u8, @ptrCast(rdp(pNew, WhereLoop_aLTerm).?))[0 .. 8 * @as(usize, @intCast(nConstraint))], 0);
    // memset(&pNew->u.vtab, 0, sizeof(pNew->u.vtab)) — vtab union is the u area; size is at most 24 bytes
    @memset(@as([*]u8, @ptrCast(fieldPtr(pNew, WhereLoop_u).?))[0..24], 0);
    const usage = rdp(pIdxInfo, II_aConstraintUsage);
    var i: c_int = 0;
    while (i < nConstraint) : (i += 1) {
        const pIdxCons = iiConsAt(pIdxInfo, @intCast(i));
        const pUse = fieldPtr(usage, @as(usize, @intCast(i)) * sizeof_idxusage);
        const iTerm = rd(c_int, pUse, IU_argvIndex) - 1;
        if (iTerm >= 0) {
            const j = rd(c_int, pIdxCons, IC_iTermOffset);
            const pTerm = termFromWhereClause(pWC, j);
            if (iTerm >= nConstraint or j < 0 or pTerm == null or
                wlALTermAt(pNew, @intCast(iTerm)) != null or rd(u8, pIdxCons, IC_usable) == 0)
            {
                c.sqlite3ErrorMsg(pParse, "%s.xBestIndex malfunction", rd(?[*:0]const u8, rdp(pSrc, SrcItem_pSTab), Table_zName));
                freeIdxStr(pIdxInfo);
                return SQLITE_ERROR;
            }
            wr(Bitmask, pNew, WhereLoop_prereq, wlPrereq(pNew) | wtPrereqRight(pTerm));
            wlALTerm(pNew)[@intCast(iTerm)] = pTerm;
            if (iTerm > mxTerm) mxTerm = iTerm;
            if (rd(u8, pUse, IU_omit) != 0) {
                if (i < 16 and ((@as(u16, 1) << @intCast(i)) & mNoOmit) == 0) {
                    wr(u16, pNew, WhereLoop_u_vtab_omitMask, rd(u16, pNew, WhereLoop_u_vtab_omitMask) | (@as(u16, 1) << @intCast(iTerm)));
                }
                if (wtEMatchOp(pTerm) == @as(u8, @intCast(IC_OFFSET))) {
                    wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) | VTAB_bOmitOffset);
                }
            }
            if ((smaskbit32(i) & rd(u32, pHidden, HII_mHandleIn)) != 0) {
                wr(u32, pNew, WhereLoop_u_vtab_mHandleIn, rd(u32, pNew, WhereLoop_u_vtab_mHandleIn) | maskbit32(iTerm));
            } else if ((wtEOperator(pTerm) & WO_IN) != 0) {
                wr(c_int, pIdxInfo, II_orderByConsumed, 0);
                wr(c_int, pIdxInfo, II_idxFlags, rd(c_int, pIdxInfo, II_idxFlags) & ~SQLITE_INDEX_SCAN_UNIQUE);
                pbIn.* = 1;
            }
            if (isLimitTerm(pTerm) != 0 and (pbIn.* != 0 or allConstraintsUsed(pIdxInfo, i) == 0)) {
                freeIdxStr(pIdxInfo);
                if (pbRetryLimit) |pr| pr.* = 1;
                return SQLITE_OK;
            }
        }
    }

    wr(u16, pNew, WhereLoop_nLTerm, @intCast(mxTerm + 1));
    {
        var k: c_int = 0;
        while (k <= mxTerm) : (k += 1) {
            if (wlALTermAt(pNew, @intCast(k)) == null) {
                c.sqlite3ErrorMsg(pParse, "%s.xBestIndex malfunction", rd(?[*:0]const u8, rdp(pSrc, SrcItem_pSTab), Table_zName));
                freeIdxStr(pIdxInfo);
                return SQLITE_ERROR;
            }
        }
    }
    wr(c_int, pNew, WhereLoop_u_vtab_idxNum, rd(c_int, pIdxInfo, II_idxNum));
    if (rd(c_int, pIdxInfo, II_needToFreeIdxStr) != 0) {
        wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) | VTAB_needFree);
    } else {
        wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) & ~VTAB_needFree);
    }
    wr(c_int, pIdxInfo, II_needToFreeIdxStr, 0);
    wr(?*anyopaque, pNew, WhereLoop_u_vtab_idxStr, rdp(pIdxInfo, II_idxStr));
    wr(i8, pNew, WhereLoop_u_vtab_isOrdered, if (rd(c_int, pIdxInfo, II_orderByConsumed) != 0) @intCast(rd(c_int, pIdxInfo, II_nOrderBy)) else 0);
    if ((rd(c_int, pIdxInfo, II_idxFlags) & SQLITE_INDEX_SCAN_HEX) != 0) {
        wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) | VTAB_bIdxNumHex);
    } else {
        wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) & ~VTAB_bIdxNumHex);
    }
    wr(LogEst, pNew, WhereLoop_rSetup, 0);
    wr(LogEst, pNew, WhereLoop_rRun, c.sqlite3LogEstFromDouble(rd(f64, pIdxInfo, II_estimatedCost)));
    wr(LogEst, pNew, WhereLoop_nOut, c.sqlite3LogEst(@bitCast(rd(i64, pIdxInfo, II_estimatedRows))));

    if ((rd(c_int, pIdxInfo, II_idxFlags) & SQLITE_INDEX_SCAN_UNIQUE) != 0) {
        wlSetWsFlags(pNew, wlWsFlags(pNew) | WHERE_ONEROW);
    } else {
        wlSetWsFlags(pNew, wlWsFlags(pNew) & ~WHERE_ONEROW);
    }
    rc = whereLoopInsert(pBuilder, pNew);
    if ((rd(u8, pNew, WhereLoop_u_vtab_bits) & VTAB_needFree) != 0) {
        c.sqlite3_free(rdp(pNew, WhereLoop_u_vtab_idxStr));
        wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) & ~VTAB_needFree);
    }
    return rc;
}

export fn sqlite3_vtab_collation(pIdxInfo: Ptr, iCons: c_int) ?[*:0]const u8 {
    const pHidden = hiddenOf(pIdxInfo);
    var zRet: ?[*:0]const u8 = null;
    if (iCons >= 0 and iCons < rd(c_int, pIdxInfo, II_nConstraint)) {
        const iTerm = rd(c_int, iiConsAt(pIdxInfo, @intCast(iCons)), IC_iTermOffset);
        const pX = wtExpr(termFromWhereClause(rdp(pHidden, HII_pWC), iTerm));
        var pC: Ptr = null;
        if (exprLeft(pX) != null) {
            pC = c.sqlite3ExprCompareCollSeq(rdp(pHidden, HII_pParse), pX);
        }
        zRet = if (pC != null) rd(?[*:0]const u8, pC, CollSeq_zName) else strBINARY();
    }
    return zRet;
}

export fn sqlite3_vtab_in(pIdxInfo: Ptr, iCons: c_int, bHandle: c_int) c_int {
    const pHidden = hiddenOf(pIdxInfo);
    const m = smaskbit32(iCons);
    if ((m & rd(u32, pHidden, HII_mIn)) != 0) {
        if (bHandle == 0) {
            wr(u32, pHidden, HII_mHandleIn, rd(u32, pHidden, HII_mHandleIn) & ~m);
        } else if (bHandle > 0) {
            wr(u32, pHidden, HII_mHandleIn, rd(u32, pHidden, HII_mHandleIn) | m);
        }
        return 1;
    }
    return 0;
}

export fn sqlite3_vtab_rhs_value(pIdxInfo: Ptr, iCons: c_int, ppVal: *Ptr) c_int {
    const pH = hiddenOf(pIdxInfo);
    var pVal: Ptr = null;
    var rc: c_int = SQLITE_OK;
    if (iCons < 0 or iCons >= rd(c_int, pIdxInfo, II_nConstraint)) {
        rc = SQLITE_MISUSE;
    } else {
        const rhsP = fieldPtr(pH, HII_aRhs + @as(usize, @intCast(iCons)) * 8);
        if (rdp(rhsP, 0) == null) {
            const pTerm = termFromWhereClause(rdp(pH, HII_pWC), rd(c_int, iiConsAt(pIdxInfo, @intCast(iCons)), IC_iTermOffset));
            var out: Ptr = null;
            rc = c.sqlite3ValueFromExpr(parseDb(rdp(pH, HII_pParse)), exprRight(wtExpr(pTerm)), dbEnc(parseDb(rdp(pH, HII_pParse))), SQLITE_AFF_BLOB, &out);
            wr(?*anyopaque, rhsP, 0, out);
        }
        pVal = rdp(rhsP, 0);
    }
    ppVal.* = pVal;
    if (rc == SQLITE_OK and pVal == null) {
        rc = SQLITE_NOTFOUND;
    }
    return rc;
}

export fn sqlite3_vtab_distinct(pIdxInfo: Ptr) c_int {
    const pHidden = hiddenOf(pIdxInfo);
    return rd(c_int, pHidden, HII_eDistinct);
}

export fn sqlite3VtabUsesAllSchemas(pParse: Ptr) void {
    const nDb = rd(c_int, parseDb(pParse), db_nDb);
    var i: c_int = 0;
    while (i < nDb) : (i += 1) {
        c.sqlite3CodeVerifySchema(pParse, i);
    }
    // DbMaskNonZero(pParse->writeMask): writeMask is a yDbMask. With <=32 dbs it's a u32.
    if (dbMaskNonZero(pParse)) {
        i = 0;
        while (i < nDb) : (i += 1) {
            c.sqlite3BeginWriteOperation(pParse, 0, i);
        }
    }
}
fn dbMaskNonZero(pParse: Ptr) bool {
    // yDbMask: if SQLITE_MAX_ATTACHED>30 it's an array; default config is u32.
    return rd(u32, pParse, Parse_writeMask) != 0;
}

fn whereLoopAddVirtual(pBuilder: Ptr, mPrereq: Bitmask, mUnusable: Bitmask) c_int {
    var rc: c_int = SQLITE_OK;
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    const pParse = wiParse(pWInfo);
    const pWC = rdp(pBuilder, WhereLoopBuilder_pWC);
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);
    const pSrc = slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pNew));
    var bIn: c_int = 0;
    var mNoOmit: u16 = 0;
    var bRetry: c_int = 0;

    const p = allocateIndexInfo(pWInfo, pWC, mUnusable, pSrc, &mNoOmit);
    if (p == null) return SQLITE_NOMEM;
    wr(LogEst, pNew, WhereLoop_rSetup, 0);
    wlSetWsFlags(pNew, WHERE_VIRTUALTABLE);
    wr(u16, pNew, WhereLoop_nLTerm, 0);
    wr(u8, pNew, WhereLoop_u_vtab_bits, rd(u8, pNew, WhereLoop_u_vtab_bits) & ~VTAB_needFree);
    const nConstraint = rd(c_int, p, II_nConstraint);
    if (whereLoopResize(parseDb(pParse), pNew, nConstraint) != 0) {
        freeIndexInfo(parseDb(pParse), p);
        return SQLITE_NOMEM;
    }

    rc = whereLoopAddVirtualOne(pBuilder, mPrereq, ALLBITS, 0, p, mNoOmit, &bIn, &bRetry);
    if (bRetry != 0) {
        rc = whereLoopAddVirtualOne(pBuilder, mPrereq, ALLBITS, 0, p, mNoOmit, &bIn, null);
    }

    var mBest: Bitmask = 0;
    if (rc == SQLITE_OK and (blk: {
        mBest = wlPrereq(pNew) & ~mPrereq;
        break :blk mBest != 0 or bIn != 0;
    })) {
        var seenZero: c_int = 0;
        var seenZeroNoIN: c_int = 0;
        var mPrev: Bitmask = 0;
        var mBestNoIn: Bitmask = 0;

        if (bIn != 0) {
            rc = whereLoopAddVirtualOne(pBuilder, mPrereq, ALLBITS, WO_IN, p, mNoOmit, &bIn, null);
            mBestNoIn = wlPrereq(pNew) & ~mPrereq;
            if (mBestNoIn == 0) {
                seenZero = 1;
                seenZeroNoIN = 1;
            }
        }

        while (rc == SQLITE_OK) {
            var mNext: Bitmask = ALLBITS;
            var i: c_int = 0;
            while (i < nConstraint) : (i += 1) {
                const iTerm = rd(c_int, iiConsAt(p, @intCast(i)), IC_iTermOffset);
                const mThis = wtPrereqRight(termFromWhereClause(pWC, iTerm)) & ~mPrereq;
                if (mThis > mPrev and mThis < mNext) mNext = mThis;
            }
            mPrev = mNext;
            if (mNext == ALLBITS) break;
            if (mNext == mBest or mNext == mBestNoIn) continue;
            rc = whereLoopAddVirtualOne(pBuilder, mPrereq, mNext | mPrereq, 0, p, mNoOmit, &bIn, null);
            if (wlPrereq(pNew) == mPrereq) {
                seenZero = 1;
                if (bIn == 0) seenZeroNoIN = 1;
            }
        }

        if (rc == SQLITE_OK and seenZero == 0) {
            rc = whereLoopAddVirtualOne(pBuilder, mPrereq, mPrereq, 0, p, mNoOmit, &bIn, null);
            if (bIn == 0) seenZeroNoIN = 1;
        }
        if (rc == SQLITE_OK and seenZeroNoIN == 0) {
            rc = whereLoopAddVirtualOne(pBuilder, mPrereq, mPrereq, WO_IN, p, mNoOmit, &bIn, null);
        }
    }

    freeIndexInfo(parseDb(pParse), p);
    return rc;
}

// ════════════════════════════════════════════════════════════════════════════
// whereLoopAddOr / whereLoopAddAll
// ════════════════════════════════════════════════════════════════════════════

fn whereLoopAddOr(pBuilder: Ptr, mPrereq: Bitmask, mUnusable: Bitmask) c_int {
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    const pWC = rdp(pBuilder, WhereLoopBuilder_pWC);
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);
    var rc: c_int = SQLITE_OK;
    var tempWCbuf: [sizeof_WhereClause]u8 align(8) = undefined;
    @memset(&tempWCbuf, 0);
    const tempWC: Ptr = @ptrCast(&tempWCbuf);
    var sSubBuildBuf: [sizeof_WhereLoopBuilder]u8 align(8) = undefined;
    @memset(&sSubBuildBuf, 0);
    const sSubBuild: Ptr = @ptrCast(&sSubBuildBuf);
    var sSumBuf: [sizeof_WhereOrSet]u8 align(8) = undefined;
    @memset(&sSumBuf, 0);
    var sCurBuf: [sizeof_WhereOrSet]u8 align(8) = undefined;
    @memset(&sCurBuf, 0);
    const sSum: Ptr = @ptrCast(&sSumBuf);
    const sCur: Ptr = @ptrCast(&sCurBuf);
    var sPrevBuf: [sizeof_WhereOrSet]u8 align(8) = undefined;
    @memset(&sPrevBuf, 0);
    const sPrev: Ptr = @ptrCast(&sPrevBuf);

    const pItem = slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pNew));
    const iCur = rd(c_int, pItem, SrcItem_iCursor);

    if ((fgJoin(pItem) & @as(u8, @intCast(JT_RIGHT))) != 0) return SQLITE_OK;

    var pTerm = wcA(pWC);
    var ti: c_int = 0;
    const nt = wcNTerm(pWC);
    while (ti < nt and rc == SQLITE_OK) : ({
        ti += 1;
        pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
    }) {
        if ((wtEOperator(pTerm) & WO_OR) != 0 and
            (rd(Bitmask, rdp(pTerm, WhereTerm_u), WhereOrInfo_indexable) & wlMaskSelf(pNew)) != 0)
        {
            const pOrWC = fieldPtr(rdp(pTerm, WhereTerm_u), WhereOrInfo_wc);
            const nOrTerm = wcNTerm(pOrWC);
            var once: c_int = 1;

            @memcpy(@as([*]u8, @ptrCast(sSubBuild.?))[0..sizeof_WhereLoopBuilder], @as([*]u8, @ptrCast(pBuilder.?)));
            wr(?*anyopaque, sSubBuild, WhereLoopBuilder_pOrSet, sCur);

            var oi: c_int = 0;
            var pOrTerm = wcA(pOrWC);
            while (oi < nOrTerm) : ({
                oi += 1;
                pOrTerm = fieldPtr(pOrTerm, sizeof_WhereTerm);
            }) {
                if ((wtEOperator(pOrTerm) & WO_AND) != 0) {
                    wr(?*anyopaque, sSubBuild, WhereLoopBuilder_pWC, fieldPtr(rdp(pOrTerm, WhereTerm_u), WhereAndInfo_wc));
                } else if (wtLeftCursor(pOrTerm) == iCur) {
                    wr(?*anyopaque, tempWC, WhereClause_pWInfo, rdp(pWC, WhereClause_pWInfo));
                    wr(?*anyopaque, tempWC, WhereClause_pOuter, pWC);
                    wr(u8, tempWC, WhereClause_op, @intCast(TK_AND));
                    wr(c_int, tempWC, WhereClause_nTerm, 1);
                    wr(c_int, tempWC, WhereClause_nBase, 1);
                    wr(?*anyopaque, tempWC, WhereClause_a, pOrTerm);
                    wr(?*anyopaque, sSubBuild, WhereLoopBuilder_pWC, tempWC);
                } else {
                    continue;
                }
                wr(u16, sCur, WhereOrSet_n, 0);
                if (isVirtualTab(rdp(pItem, SrcItem_pSTab))) {
                    rc = whereLoopAddVirtual(sSubBuild, mPrereq, mUnusable);
                } else {
                    rc = whereLoopAddBtree(sSubBuild, mPrereq);
                }
                if (rc == SQLITE_OK) {
                    rc = whereLoopAddOr(sSubBuild, mPrereq, mUnusable);
                }
                if (rd(u16, sCur, WhereOrSet_n) == 0) {
                    wr(u16, sSum, WhereOrSet_n, 0);
                    break;
                } else if (once != 0) {
                    whereOrMove(sSum, sCur);
                    once = 0;
                } else {
                    whereOrMove(sPrev, sSum);
                    wr(u16, sSum, WhereOrSet_n, 0);
                    var i: u16 = 0;
                    const np = rd(u16, sPrev, WhereOrSet_n);
                    while (i < np) : (i += 1) {
                        const pi = orSetA(sPrev, i);
                        var j: u16 = 0;
                        const ncur = rd(u16, sCur, WhereOrSet_n);
                        while (j < ncur) : (j += 1) {
                            const pj = orSetA(sCur, j);
                            _ = whereOrInsert(sSum, rd(Bitmask, pi, WhereOrCost_prereq) | rd(Bitmask, pj, WhereOrCost_prereq), c.sqlite3LogEstAdd(rd(LogEst, pi, WhereOrCost_rRun), rd(LogEst, pj, WhereOrCost_rRun)), c.sqlite3LogEstAdd(rd(LogEst, pi, WhereOrCost_nOut), rd(LogEst, pj, WhereOrCost_nOut)));
                        }
                    }
                }
            }
            wr(u16, pNew, WhereLoop_nLTerm, 1);
            wlALTerm(pNew)[0] = pTerm;
            wlSetWsFlags(pNew, WHERE_MULTI_OR);
            wr(LogEst, pNew, WhereLoop_rSetup, 0);
            wr(u8, pNew, WhereLoop_iSortIdx, 0);
            @memset(@as([*]u8, @ptrCast(fieldPtr(pNew, WhereLoop_u).?))[0..24], 0);
            var i: c_int = 0;
            const nsum = rd(u16, sSum, WhereOrSet_n);
            while (rc == SQLITE_OK and i < nsum) : (i += 1) {
                const pa = orSetA(sSum, @intCast(i));
                wr(LogEst, pNew, WhereLoop_rRun, rd(LogEst, pa, WhereOrCost_rRun) + 1);
                wr(LogEst, pNew, WhereLoop_nOut, rd(LogEst, pa, WhereOrCost_nOut));
                wr(Bitmask, pNew, WhereLoop_prereq, rd(Bitmask, pa, WhereOrCost_prereq));
                rc = whereLoopInsert(pBuilder, pNew);
            }
        }
    }
    return rc;
}

fn whereLoopAddAll(pBuilder: Ptr) c_int {
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    var mPrereq: Bitmask = 0;
    var mPrior: Bitmask = 0;
    const pTabList = rdp(pWInfo, WhereInfo_pTabList);
    const nLevel = wiNLevel(pWInfo);
    const db = parseDb(wiParse(pWInfo));
    var rc: c_int = SQLITE_OK;
    var bFirstPastRJ: bool = false;
    var hasRightCrossJoin: bool = false;
    const pNew = rdp(pBuilder, WhereLoopBuilder_pNew);

    wr(u32, pBuilder, WhereLoopBuilder_iPlanLimit, SQLITE_QUERY_PLANNER_LIMIT);
    var iTab: c_int = 0;
    while (iTab < nLevel) : (iTab += 1) {
        const pItem = slItem(pTabList, @intCast(iTab));
        var mUnusable: Bitmask = 0;
        wr(u8, pNew, WhereLoop_iTab, @intCast(iTab));
        wr(u32, pBuilder, WhereLoopBuilder_iPlanLimit, rd(u32, pBuilder, WhereLoopBuilder_iPlanLimit) + SQLITE_QUERY_PLANNER_LIMIT_INCR);
        wr(Bitmask, pNew, WhereLoop_maskSelf, sqlite3WhereGetMask(wiMaskSet(pWInfo), rd(c_int, pItem, SrcItem_iCursor)));
        if (bFirstPastRJ or
            (fgJoin(pItem) & @as(u8, @intCast(JT_OUTER | JT_CROSS | JT_LTORJ))) != 0)
        {
            if ((fgJoin(pItem) & @as(u8, @intCast(JT_LTORJ | JT_CROSS))) != 0) {
                hasRightCrossJoin = true;
            }
            mPrereq |= mPrior;
            bFirstPastRJ = (fgJoin(pItem) & @as(u8, @intCast(JT_RIGHT))) != 0;
        } else if ((fgB3(pItem) & FG_fromExists) != 0) {
            const pWC = wiSWC(pWInfo);
            var i: c_int = wcNBase(pWC);
            var pTerm = wcA(pWC);
            while (i > 0) : ({
                i -= 1;
                pTerm = fieldPtr(pTerm, sizeof_WhereTerm);
            }) {
                if ((wlMaskSelf(pNew) & wtPrereqAll(pTerm)) != 0) {
                    mPrereq |= (wtPrereqAll(pTerm) & (wlMaskSelf(pNew) -% 1));
                }
            }
        } else if (!hasRightCrossJoin) {
            mPrereq = 0;
        }
        if (isVirtualTab(rdp(pItem, SrcItem_pSTab))) {
            var pEndIdx: c_int = iTab + 1;
            while (pEndIdx < nLevel) : (pEndIdx += 1) {
                const pp = slItem(pTabList, @intCast(pEndIdx));
                if (mUnusable != 0 or (fgJoin(pp) & @as(u8, @intCast(JT_OUTER | JT_CROSS))) != 0) {
                    mUnusable |= sqlite3WhereGetMask(wiMaskSet(pWInfo), rd(c_int, pp, SrcItem_iCursor));
                }
            }
            rc = whereLoopAddVirtual(pBuilder, mPrereq, mUnusable);
        } else {
            rc = whereLoopAddBtree(pBuilder, mPrereq);
        }
        if (rc == SQLITE_OK and rd(u8, rdp(pBuilder, WhereLoopBuilder_pWC), WhereClause_hasOr) != 0) {
            rc = whereLoopAddOr(pBuilder, mPrereq, mUnusable);
        }
        mPrior |= wlMaskSelf(pNew);
        if (rc != 0 or dbMallocFailed(db)) {
            if (rc == SQLITE_DONE) {
                c.sqlite3_log(SQLITE_WARNING, "abbreviated query algorithm search");
                rc = SQLITE_OK;
            } else {
                break;
            }
        }
    }
    whereLoopClear(db, pNew);
    return rc;
}

// ════════════════════════════════════════════════════════════════════════════
// ORDER BY satisfaction + solver
// ════════════════════════════════════════════════════════════════════════════

inline fn elSortFlags(pList: Ptr, i: usize) u8 {
    return rd(u8, elItem(pList, i), ExprList_item_fg_sortFlags);
}
inline fn elIOrderByCol(pList: Ptr, i: usize) u16 {
    return rd(u16, elItem(pList, i), ExprList_item_u_x_iOrderByCol);
}

fn wherePathMatchSubqueryOB(pWInfo: Ptr, pLoop: Ptr, iLoop: c_int, iCur: c_int, pOrderBy: Ptr, pRevMask: *Bitmask, pOBSat: *Bitmask) c_int {
    var rev: u8 = 0;
    const pSubOB = rdp(pLoop, WhereLoop_u_btree_pOrderBy);
    var iOB: c_int = 0;
    while ((maskbit(iOB) & pOBSat.*) != 0) iOB += 1;
    var jSub: c_int = 0;
    const nSub = elNExpr(pSubOB);
    const nOB = elNExpr(pOrderBy);
    while (jSub < nSub and iOB < nOB) : ({
        jSub += 1;
        iOB += 1;
    }) {
        if (elIOrderByCol(pSubOB, @intCast(jSub)) == 0) break;
        const pOBExpr = elItemExpr(pOrderBy, @intCast(iOB));
        if (exprOp(pOBExpr) != TK_COLUMN and exprOp(pOBExpr) != TK_AGG_COLUMN) break;
        if (exprITable(pOBExpr) != iCur) break;
        if (exprIColumn(pOBExpr) != elIOrderByCol(pSubOB, @intCast(jSub)) - 1) break;
        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_GROUPBY) == 0) {
            const sfOB = elSortFlags(pOrderBy, @intCast(iOB));
            const sfSub = elSortFlags(pSubOB, @intCast(jSub));
            if ((sfSub & KEYINFO_ORDER_BIGNULL) != (sfOB & KEYINFO_ORDER_BIGNULL)) break;
            const revIdx = sfSub & KEYINFO_ORDER_DESC;
            if (jSub > 0) {
                if ((rev ^ revIdx) != (sfOB & KEYINFO_ORDER_DESC)) break;
            } else {
                rev = revIdx ^ (sfOB & KEYINFO_ORDER_DESC);
                if (rev != 0) {
                    if ((wlWsFlags(pLoop) & WHERE_COROUTINE) != 0) break;
                    pRevMask.* |= maskbit(iLoop);
                }
            }
        }
        pOBSat.* |= maskbit(iOB);
    }
    return @intFromBool(jSub > 0);
}

fn wherePathSatisfiesOrderBy(pWInfo: Ptr, pOrderBy: Ptr, pPath: Ptr, wctrlFlags: u16, nLoop: u16, pLast: Ptr, pRevMask: *Bitmask) i8 {
    var revSet: u8 = 0;
    var rev: u8 = 0;
    var isOrderDistinct: u8 = 1;
    var distinctColumns: u8 = 0;
    var isMatch: u8 = 0;
    const db = parseDb(wiParse(pWInfo));
    var obSat: Bitmask = 0;
    var orderDistinctMask: Bitmask = 0;
    var ready: Bitmask = 0;
    var pLoop: Ptr = null;

    if (nLoop != 0 and optimizationDisabled(db, SQLITE_OrderByIdxJoin)) return 0;
    const nOrderBy = elNExpr(pOrderBy);
    if (nOrderBy > BMS - 1) return 0;
    const obDone = maskbit(nOrderBy) - 1;
    var eqOpMask: u16 = WO_EQ | WO_IS | WO_ISNULL;
    if ((wctrlFlags & (WHERE_ORDERBY_LIMIT | WHERE_ORDERBY_MAX | WHERE_ORDERBY_MIN)) != 0) {
        eqOpMask |= WO_IN;
    }

    var iLoop: c_int = 0;
    while (isOrderDistinct != 0 and obSat < obDone and iLoop <= nLoop) : (iLoop += 1) {
        if (iLoop > 0) ready |= wlMaskSelf(pLoop);
        if (iLoop < nLoop) {
            pLoop = rdp(pPath, WherePath_aLoop);
            pLoop = @as([*]Ptr, @ptrCast(@alignCast(rdp(pPath, WherePath_aLoop).?)))[@intCast(iLoop)];
            if ((wctrlFlags & WHERE_ORDERBY_LIMIT) != 0) continue;
        } else {
            pLoop = pLast;
        }
        if ((wlWsFlags(pLoop) & WHERE_VIRTUALTABLE) != 0) {
            if (rd(i8, pLoop, WhereLoop_u_vtab_isOrdered) != 0 and rdp(pWInfo, WhereInfo_pOrderBy) == pOrderBy) {
                obSat = obDone;
            } else {
                isOrderDistinct = 0;
            }
            break;
        }
        const iCur = rd(c_int, slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pLoop)), SrcItem_iCursor);

        {
            var i: c_int = 0;
            while (i < nOrderBy) : (i += 1) {
                if ((maskbit(i) & obSat) != 0) continue;
                const pOBExpr = c.sqlite3ExprSkipCollateAndLikely(elItemExpr(pOrderBy, @intCast(i)));
                if (pOBExpr == null) continue;
                if (exprOp(pOBExpr) != TK_COLUMN and exprOp(pOBExpr) != TK_AGG_COLUMN) continue;
                if (exprITable(pOBExpr) != iCur) continue;
                const pTerm = sqlite3WhereFindTerm(wiSWC(pWInfo), iCur, exprIColumn(pOBExpr), ~ready, eqOpMask, null);
                if (pTerm == null) continue;
                if (wtEOperator(pTerm) == WO_IN) {
                    var j: c_int = 0;
                    while (j < wlNLTerm(pLoop) and pTerm != wlALTermAt(pLoop, @intCast(j))) j += 1;
                    if (j >= wlNLTerm(pLoop)) continue;
                }
                if ((wtEOperator(pTerm) & (WO_EQ | WO_IS)) != 0 and exprIColumn(pOBExpr) >= 0) {
                    const pParse = wiParse(pWInfo);
                    const pColl1 = c.sqlite3ExprNNCollSeq(pParse, elItemExpr(pOrderBy, @intCast(i)));
                    const pColl2 = c.sqlite3ExprCompareCollSeq(pParse, wtExpr(pTerm));
                    if (pColl2 == null or c.sqlite3StrICmp(rd(?[*:0]const u8, pColl1, CollSeq_zName), rd(?[*:0]const u8, pColl2, CollSeq_zName)) != 0) {
                        continue;
                    }
                }
                obSat |= maskbit(i);
            }
        }

        var nKeyCol: u16 = 0;
        var nColumn: u16 = 0;
        var pIndex: Ptr = null;
        if ((wlWsFlags(pLoop) & WHERE_ONEROW) == 0) {
            if ((wlWsFlags(pLoop) & WHERE_IPK) != 0) {
                if (rdp(pLoop, WhereLoop_u_btree_pOrderBy) != null and
                    optimizationEnabled(db, SQLITE_OrderBySubq) and
                    wherePathMatchSubqueryOB(pWInfo, pLoop, iLoop, iCur, pOrderBy, pRevMask, &obSat) != 0)
                {
                    nColumn = 0;
                    isOrderDistinct = 0;
                } else {
                    nColumn = 1;
                }
                pIndex = null;
                nKeyCol = 0;
            } else {
                pIndex = wlPIndex(pLoop);
                if (pIndex == null or idxBUnordered(pIndex)) return 0;
                nKeyCol = @intCast(idxNKeyCol(pIndex));
                nColumn = @intCast(idxNColumn(pIndex));
                isOrderDistinct = @intFromBool(isUniqueIndex(pIndex) and (wlWsFlags(pLoop) & WHERE_SKIPSCAN) == 0);
            }

            rev = 0;
            revSet = 0;
            distinctColumns = 0;
            var j: c_int = 0;
            while (j < nColumn) : (j += 1) {
                var bOnce: u8 = 1;
                if (j < wlNEq(pLoop) and j >= wlNSkip(pLoop)) {
                    const eOp = wtEOperator(wlALTermAt(pLoop, @intCast(j)));
                    if ((eOp & eqOpMask) != 0) {
                        if ((eOp & (WO_ISNULL | WO_IS)) != 0) {
                            isOrderDistinct = 0;
                        }
                        continue;
                    } else if ((eOp & WO_IN) != 0) {
                        const pX = wtExpr(wlALTermAt(pLoop, @intCast(j)));
                        var ii: c_int = j + 1;
                        while (ii < wlNEq(pLoop)) : (ii += 1) {
                            if (wtExpr(wlALTermAt(pLoop, @intCast(ii))) == pX) {
                                bOnce = 0;
                                break;
                            }
                        }
                    }
                }

                var iColumn: c_int = undefined;
                var revIdx: u8 = undefined;
                if (pIndex != null) {
                    iColumn = idxAiColumn(pIndex)[@intCast(j)];
                    revIdx = idxASortOrder(pIndex)[@intCast(j)] & KEYINFO_ORDER_DESC;
                    if (iColumn == rd(i16, rdp(pIndex, Index_pTable), Table_iPKey)) iColumn = XN_ROWID;
                } else {
                    iColumn = XN_ROWID;
                    revIdx = 0;
                }

                if (isOrderDistinct != 0) {
                    if (iColumn >= 0 and j >= wlNEq(pLoop) and
                        !colNotNull(rdp(pIndex, Index_pTable), @intCast(iColumn)))
                    {
                        isOrderDistinct = 0;
                    }
                    if (iColumn == XN_EXPR) isOrderDistinct = 0;
                }

                isMatch = 0;
                var i: c_int = 0;
                while (bOnce != 0 and i < nOrderBy) : (i += 1) {
                    if ((maskbit(i) & obSat) != 0) continue;
                    const pOBExpr = c.sqlite3ExprSkipCollateAndLikely(elItemExpr(pOrderBy, @intCast(i)));
                    if (pOBExpr == null) continue;
                    if ((wctrlFlags & (WHERE_GROUPBY | WHERE_DISTINCTBY)) == 0) bOnce = 0;
                    if (iColumn >= XN_ROWID) {
                        if (exprOp(pOBExpr) != TK_COLUMN and exprOp(pOBExpr) != TK_AGG_COLUMN) continue;
                        if (exprITable(pOBExpr) != iCur) continue;
                        if (exprIColumn(pOBExpr) != iColumn) continue;
                    } else {
                        const pIxExpr = elItemExpr(rdp(pIndex, Index_aColExpr), @intCast(j));
                        if (c.sqlite3ExprCompareSkip(pOBExpr, pIxExpr, iCur) != 0) continue;
                    }
                    if (iColumn != XN_ROWID) {
                        const pColl = c.sqlite3ExprNNCollSeq(wiParse(pWInfo), elItemExpr(pOrderBy, @intCast(i)));
                        if (c.sqlite3StrICmp(rd(?[*:0]const u8, pColl, CollSeq_zName), idxAzColl(pIndex)[@intCast(j)]) != 0) continue;
                    }
                    if ((wctrlFlags & WHERE_DISTINCTBY) != 0) {
                        wr(u16, pLoop, WhereLoop_u_btree_nDistinctCol, @intCast(j + 1));
                    }
                    isMatch = 1;
                    break;
                }
                if (isMatch != 0 and (wctrlFlags & WHERE_GROUPBY) == 0) {
                    if (revSet != 0) {
                        if ((rev ^ revIdx) != (elSortFlags(pOrderBy, @intCast(i)) & KEYINFO_ORDER_DESC)) {
                            isMatch = 0;
                        }
                    } else {
                        rev = revIdx ^ (elSortFlags(pOrderBy, @intCast(i)) & KEYINFO_ORDER_DESC);
                        if (rev != 0) pRevMask.* |= maskbit(iLoop);
                        revSet = 1;
                    }
                }
                if (isMatch != 0 and (elSortFlags(pOrderBy, @intCast(i)) & KEYINFO_ORDER_BIGNULL) != 0) {
                    if (j == wlNEq(pLoop)) {
                        wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_BIGNULL_SORT);
                    } else {
                        isMatch = 0;
                    }
                }
                if (isMatch != 0) {
                    if (iColumn == XN_ROWID) distinctColumns = 1;
                    obSat |= maskbit(i);
                } else {
                    if (j == 0 or j < nKeyCol) {
                        isOrderDistinct = 0;
                    }
                    break;
                }
            }
            if (distinctColumns != 0) isOrderDistinct = 1;
        }

        if (isOrderDistinct != 0) {
            orderDistinctMask |= wlMaskSelf(pLoop);
            var i: c_int = 0;
            while (i < nOrderBy) : (i += 1) {
                if ((maskbit(i) & obSat) != 0) continue;
                const p = elItemExpr(pOrderBy, @intCast(i));
                const mTerm = c.sqlite3WhereExprUsage(wiMaskSet(pWInfo), p);
                if (mTerm == 0 and c.sqlite3ExprIsConstant(null, p) == 0) continue;
                if ((mTerm & ~orderDistinctMask) == 0) {
                    obSat |= maskbit(i);
                }
            }
        }
    }
    if (obSat == obDone) return @intCast(nOrderBy);
    if (isOrderDistinct == 0) {
        var i: c_int = nOrderBy - 1;
        while (i > 0) : (i -= 1) {
            const m: Bitmask = if (i < BMS) maskbit(i) - 1 else 0;
            if ((obSat & m) == m) return @intCast(i);
        }
        return 0;
    }
    return -1;
}

export fn sqlite3WhereIsSorted(pWInfo: Ptr) c_int {
    return @intFromBool(wiBitGet(pWInfo, WI_sorted));
}

fn whereSortingCost(pWInfo: Ptr, nRow0: LogEst, nOrderBy: c_int, nSorted: c_int) LogEst {
    var nRow = nRow0;
    const nCol = c.sqlite3LogEst(@intCast(@divTrunc(elNExpr(rdp(rdp(pWInfo, WhereInfo_pSelect), Select_pEList)) + 59, 30)));
    var rSortCost = nRow + nCol;
    if (nSorted > 0) {
        rSortCost += c.sqlite3LogEst(@intCast(@divTrunc((nOrderBy - nSorted) * 100, nOrderBy))) - 66;
    }
    if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_USE_LIMIT) != 0) {
        rSortCost += 10;
        if (nSorted != 0) rSortCost += 6;
        if (rd(LogEst, pWInfo, WhereInfo_iLimit) < nRow) {
            nRow = rd(LogEst, pWInfo, WhereInfo_iLimit);
        }
    } else if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_WANT_DISTINCT) != 0) {
        if (nRow > 10) nRow -= 10;
    }
    rSortCost += estLog(nRow);
    return rSortCost;
}

fn computeMxChoice(pWInfo: Ptr) c_int {
    const nLoop = wiNLevel(pWInfo);
    if (nLoop >= 4 and !wiBitGet(pWInfo, WI_bStarDone) and
        optimizationEnabled(parseDb(wiParse(pWInfo)), SQLITE_StarQuery))
    {
        wiBitSet(pWInfo, WI_bStarDone, true);
        const aFromTabs = rdp(pWInfo, WhereInfo_pTabList);
        var pStart = rdp(pWInfo, WhereInfo_pLoops);
        var mSelfJoin: Bitmask = 0;
        var iFromIdx: c_int = 0;
        var m: Bitmask = 1;
        while (iFromIdx < nLoop) : ({
            iFromIdx += 1;
            m <<= 1;
        }) {
            var nDep: c_int = 0;
            var mSeen: Bitmask = 0;
            const pFactTab = slItem(aFromTabs, @intCast(iFromIdx));
            if ((fgJoin(pFactTab) & @as(u8, @intCast(JT_OUTER | JT_CROSS))) != 0) {
                if (iFromIdx + 3 > nLoop) break;
                while (pStart != null and wlITab(pStart) <= iFromIdx) {
                    pStart = wlNext(pStart);
                }
            }
            var pWLoop = pStart;
            while (pWLoop != null) : (pWLoop = wlNext(pWLoop)) {
                if ((fgJoin(slItem(aFromTabs, wlITab(pWLoop))) & @as(u8, @intCast(JT_OUTER | JT_CROSS))) != 0) break;
                if ((wlPrereq(pWLoop) & m) != 0 and
                    (wlMaskSelf(pWLoop) & mSeen) == 0 and
                    (wlMaskSelf(pWLoop) & mSelfJoin) == 0)
                {
                    if (rdp(slItem(aFromTabs, wlITab(pWLoop)), SrcItem_pSTab) == rdp(pFactTab, SrcItem_pSTab)) {
                        mSelfJoin |= m;
                    } else {
                        nDep += 1;
                        mSeen |= wlMaskSelf(pWLoop);
                    }
                }
            }
            if (nDep <= 2) continue;
            wiBitSet(pWInfo, WI_bStarUsed, true);
            var mxRun: LogEst = LOGEST_MIN;
            pWLoop = pStart;
            while (pWLoop != null) : (pWLoop = wlNext(pWLoop)) {
                if (wlITab(pWLoop) < iFromIdx) continue;
                if (wlITab(pWLoop) > iFromIdx) break;
                if (wlRRun(pWLoop) > mxRun) mxRun = wlRRun(pWLoop);
            }
            if (mxRun < LOGEST_MAX) mxRun += 1;
            pWLoop = pStart;
            while (pWLoop != null) : (pWLoop = wlNext(pWLoop)) {
                if ((wlMaskSelf(pWLoop) & mSeen) == 0) continue;
                if (wlNLTerm(pWLoop) != 0) continue;
                if (wlRRun(pWLoop) < mxRun) {
                    wr(LogEst, pWLoop, WhereLoop_rRun, mxRun);
                }
            }
        }
    }
    return if (wiBitGet(pWInfo, WI_bStarUsed)) 18 else 12;
}

fn whereLoopIsNoBetter(pCandidate: Ptr, pBaseline: Ptr) c_int {
    if ((wlWsFlags(pCandidate) & WHERE_INDEXED) == 0) return 1;
    if ((wlWsFlags(pBaseline) & WHERE_INDEXED) == 0) return 1;
    if (rd(LogEst, wlPIndex(pCandidate), Index_szIdxRow) < rd(LogEst, wlPIndex(pBaseline), Index_szIdxRow)) return 0;
    return 1;
}

// sqlite3StackAllocRawNN/FreeNN are macros (alloca OFF => DbMalloc/DbFree).
const cs = struct {
    inline fn sqlite3StackAllocRawNN(db: Ptr, n: u64) Ptr {
        return c.sqlite3DbMallocRawNN(db, n);
    }
    inline fn sqlite3StackFreeNN(db: Ptr, p: Ptr) void {
        c.sqlite3DbFreeNN(db, p);
    }
};

inline fn pathLoop(pPath: Ptr, i: usize) Ptr {
    return @as([*]Ptr, @ptrCast(@alignCast(rdp(pPath, WherePath_aLoop).?)))[i];
}
inline fn pathSetLoop(pPath: Ptr, i: usize, v: Ptr) void {
    @as([*]Ptr, @ptrCast(@alignCast(rdp(pPath, WherePath_aLoop).?)))[i] = v;
}
inline fn pathAt(aBase: Ptr, i: usize) Ptr {
    return fieldPtr(aBase, i * sizeof_WherePath);
}

fn wherePathSolver(pWInfo: Ptr, nRowEst: LogEst) c_int {
    const pParse = wiParse(pWInfo);
    const nLoop = wiNLevel(pWInfo);
    var mxI: c_int = 0;
    var mxCost: LogEst = 0;
    var mxUnsort: LogEst = 0;

    var mxChoice: c_int = undefined;
    if (nLoop <= 1) {
        mxChoice = 1;
    } else if (nLoop == 2) {
        mxChoice = 5;
    } else if (rd(c_int, pParse, Parse_nErr) != 0) {
        mxChoice = 1;
    } else {
        mxChoice = computeMxChoice(pWInfo);
    }

    var nOrderBy: c_int = undefined;
    if (rdp(pWInfo, WhereInfo_pOrderBy) == null or nRowEst == 0) {
        nOrderBy = 0;
    } else {
        nOrderBy = elNExpr(rdp(pWInfo, WhereInfo_pOrderBy));
    }

    const nSpace: usize = (sizeof_WherePath + 8 * @as(usize, @intCast(nLoop))) * @as(usize, @intCast(mxChoice)) * 2 + 2 * @as(usize, @intCast(nOrderBy));
    const pSpace = cs.sqlite3StackAllocRawNN(parseDb(pParse), nSpace);
    if (pSpace == null) return SQLITE_NOMEM;
    var aTo: Ptr = pSpace;
    var aFrom: Ptr = pathAt(aTo, @intCast(mxChoice));
    @memset(@as([*]u8, @ptrCast(aFrom.?))[0..sizeof_WherePath], 0);
    var pX: Ptr = pathAt(aFrom, @intCast(mxChoice)); // WhereLoop** region
    {
        var ii: c_int = mxChoice * 2;
        var pFrom = aTo;
        while (ii > 0) : ({
            ii -= 1;
            pFrom = fieldPtr(pFrom, sizeof_WherePath);
            pX = fieldPtr(pX, 8 * @as(usize, @intCast(nLoop)));
        }) {
            wr(?*anyopaque, pFrom, WherePath_aLoop, pX);
        }
    }
    var aSortCost: Ptr = null;
    if (nOrderBy != 0) {
        aSortCost = pX;
        @memset(@as([*]u8, @ptrCast(aSortCost.?))[0 .. 2 * @as(usize, @intCast(nOrderBy))], 0);
    }

    const seed: LogEst = @intCast(imin(rd(c_int, pParse, Parse_nQueryLoop), 48));
    wr(LogEst, pathAt(aFrom, 0), WherePath_nRow, seed);
    var nFrom: c_int = 1;
    if (nOrderBy != 0) {
        wr(i8, pathAt(aFrom, 0), WherePath_isOrdered, if (nLoop > 0) -1 else @intCast(nOrderBy));
    }

    var iLoop: c_int = 0;
    while (iLoop < nLoop) : (iLoop += 1) {
        var nTo: c_int = 0;
        var ii: c_int = 0;
        while (ii < nFrom) : (ii += 1) {
            const pFrom = pathAt(aFrom, @intCast(ii));
            var pWLoop = rdp(pWInfo, WhereInfo_pLoops);
            while (pWLoop != null) : (pWLoop = wlNext(pWLoop)) {
                if ((wlPrereq(pWLoop) & ~rd(Bitmask, pFrom, WherePath_maskLoop)) != 0) continue;
                if ((wlMaskSelf(pWLoop) & rd(Bitmask, pFrom, WherePath_maskLoop)) != 0) continue;
                if ((wlWsFlags(pWLoop) & WHERE_AUTO_INDEX) != 0 and rd(LogEst, pFrom, WherePath_nRow) < 3) continue;

                var rUnsort = wlRRun(pWLoop) + rd(LogEst, pFrom, WherePath_nRow);
                if (wlRSetup(pWLoop) != 0) {
                    rUnsort = c.sqlite3LogEstAdd(wlRSetup(pWLoop), rUnsort);
                }
                rUnsort = c.sqlite3LogEstAdd(rUnsort, rd(LogEst, pFrom, WherePath_rUnsort));
                const nOut = rd(LogEst, pFrom, WherePath_nRow) + wlNOut(pWLoop);
                const maskNew = rd(Bitmask, pFrom, WherePath_maskLoop) | wlMaskSelf(pWLoop);
                var isOrdered = rd(i8, pFrom, WherePath_isOrdered);
                var revMask: Bitmask = undefined;
                if (isOrdered < 0) {
                    revMask = 0;
                    isOrdered = wherePathSatisfiesOrderBy(pWInfo, rdp(pWInfo, WhereInfo_pOrderBy), pFrom, rd(u16, pWInfo, WhereInfo_wctrlFlags), @intCast(iLoop), pWLoop, &revMask);
                } else {
                    revMask = rd(Bitmask, pFrom, WherePath_revLoop);
                }
                var rCost: LogEst = undefined;
                if (isOrdered >= 0 and isOrdered < nOrderBy) {
                    if (rd(LogEst, aSortCost, @as(usize, @intCast(isOrdered)) * 2) == 0) {
                        wr(LogEst, aSortCost, @as(usize, @intCast(isOrdered)) * 2, whereSortingCost(pWInfo, nRowEst, nOrderBy, isOrdered));
                    }
                    rCost = c.sqlite3LogEstAdd(rUnsort, rd(LogEst, aSortCost, @as(usize, @intCast(isOrdered)) * 2)) + 3;
                } else {
                    rCost = rUnsort;
                    rUnsort -= 2;
                }

                var jj: c_int = 0;
                var pTo: Ptr = aTo;
                while (jj < nTo) : ({
                    jj += 1;
                    pTo = fieldPtr(pTo, sizeof_WherePath);
                }) {
                    if (rd(Bitmask, pTo, WherePath_maskLoop) == maskNew and
                        (((rd(i8, pTo, WherePath_isOrdered) ^ isOrdered) & @as(i8, @bitCast(@as(u8, 0x80)))) == 0 or iLoop == nLoop - 1))
                    {
                        break;
                    }
                }
                if (jj >= nTo) {
                    if (nTo >= mxChoice and
                        (rCost > mxCost or (rCost == mxCost and rUnsort >= mxUnsort)))
                    {
                        continue;
                    }
                    if (nTo < mxChoice) {
                        jj = nTo;
                        nTo += 1;
                    } else {
                        jj = mxI;
                    }
                    pTo = pathAt(aTo, @intCast(jj));
                } else {
                    if ((rd(LogEst, pTo, WherePath_rCost) < rCost) or
                        (rd(LogEst, pTo, WherePath_rCost) == rCost and rd(LogEst, pTo, WherePath_nRow) < nOut) or
                        (rd(LogEst, pTo, WherePath_rCost) == rCost and rd(LogEst, pTo, WherePath_nRow) == nOut and rd(LogEst, pTo, WherePath_rUnsort) < rUnsort) or
                        (rd(LogEst, pTo, WherePath_rCost) == rCost and rd(LogEst, pTo, WherePath_nRow) == nOut and rd(LogEst, pTo, WherePath_rUnsort) == rUnsort and
                            whereLoopIsNoBetter(pWLoop, pathLoop(pTo, @intCast(iLoop))) != 0))
                    {
                        continue;
                    }
                }
                wr(Bitmask, pTo, WherePath_maskLoop, rd(Bitmask, pFrom, WherePath_maskLoop) | wlMaskSelf(pWLoop));
                wr(Bitmask, pTo, WherePath_revLoop, revMask);
                wr(LogEst, pTo, WherePath_nRow, nOut);
                wr(LogEst, pTo, WherePath_rCost, rCost);
                wr(LogEst, pTo, WherePath_rUnsort, rUnsort);
                wr(i8, pTo, WherePath_isOrdered, isOrdered);
                @memcpy(@as([*]u8, @ptrCast(rdp(pTo, WherePath_aLoop).?))[0 .. 8 * @as(usize, @intCast(iLoop))], @as([*]u8, @ptrCast(rdp(pFrom, WherePath_aLoop).?)));
                pathSetLoop(pTo, @intCast(iLoop), pWLoop);
                if (nTo >= mxChoice) {
                    mxI = 0;
                    mxCost = rd(LogEst, pathAt(aTo, 0), WherePath_rCost);
                    mxUnsort = rd(LogEst, pathAt(aTo, 0), WherePath_nRow);
                    var jx: c_int = 1;
                    while (jx < mxChoice) : (jx += 1) {
                        const pTx = pathAt(aTo, @intCast(jx));
                        if (rd(LogEst, pTx, WherePath_rCost) > mxCost or
                            (rd(LogEst, pTx, WherePath_rCost) == mxCost and rd(LogEst, pTx, WherePath_rUnsort) > mxUnsort))
                        {
                            mxCost = rd(LogEst, pTx, WherePath_rCost);
                            mxUnsort = rd(LogEst, pTx, WherePath_rUnsort);
                            mxI = jx;
                        }
                    }
                }
            }
        }
        // swap aFrom/aTo
        const tmp = aTo;
        aTo = aFrom;
        aFrom = tmp;
        nFrom = nTo;
    }

    if (nFrom == 0) {
        c.sqlite3ErrorMsg(pParse, "no query solution");
        cs.sqlite3StackFreeNN(parseDb(pParse), pSpace);
        return SQLITE_ERROR;
    }

    const pFrom = aFrom;
    {
        var i: c_int = 0;
        while (i < nLoop) : (i += 1) {
            const pLevel = wiLevelAt(pWInfo, @intCast(i));
            const pWLoop = pathLoop(pFrom, @intCast(i));
            wr(?*anyopaque, pLevel, WhereLevel_pWLoop, pWLoop);
            wr(u8, pLevel, WhereLevel_iFrom, wlITab(pWLoop));
            wr(c_int, pLevel, WhereLevel_iTabCur, rd(c_int, slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pWLoop)), SrcItem_iCursor));
        }
    }
    if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_WANT_DISTINCT) != 0 and
        (rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_DISTINCTBY) == 0 and
        rd(u8, pWInfo, WhereInfo_eDistinct) == WHERE_DISTINCT_NOOP and
        nRowEst != 0)
    {
        var notUsed: Bitmask = 0;
        const rcc = wherePathSatisfiesOrderBy(pWInfo, rdp(pWInfo, WhereInfo_pResultSet), pFrom, WHERE_DISTINCTBY, @intCast(nLoop - 1), pathLoop(pFrom, @intCast(nLoop - 1)), &notUsed);
        if (rcc == elNExpr(rdp(pWInfo, WhereInfo_pResultSet))) {
            wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_ORDERED);
        }
    }
    wiBitSet(pWInfo, WI_bOrderedInnerLoop, false);
    if (rdp(pWInfo, WhereInfo_pOrderBy) != null) {
        wr(i8, pWInfo, WhereInfo_nOBSat, rd(i8, pFrom, WherePath_isOrdered));
        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_DISTINCTBY) != 0) {
            if (rd(i8, pFrom, WherePath_isOrdered) == elNExpr(rdp(pWInfo, WhereInfo_pOrderBy))) {
                wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_ORDERED);
            }
        } else {
            wr(Bitmask, pWInfo, WhereInfo_revMask, rd(Bitmask, pFrom, WherePath_revLoop));
            if (rd(i8, pWInfo, WhereInfo_nOBSat) <= 0) {
                wr(i8, pWInfo, WhereInfo_nOBSat, 0);
                if (nLoop > 0) {
                    const wsFlags = wlWsFlags(pathLoop(pFrom, @intCast(nLoop - 1)));
                    if ((wsFlags & WHERE_ONEROW) == 0 and
                        (wsFlags & (WHERE_IPK | WHERE_COLUMN_IN)) != (WHERE_IPK | WHERE_COLUMN_IN))
                    {
                        var mm: Bitmask = 0;
                        const rcc = wherePathSatisfiesOrderBy(pWInfo, rdp(pWInfo, WhereInfo_pOrderBy), pFrom, WHERE_ORDERBY_LIMIT, @intCast(nLoop - 1), pathLoop(pFrom, @intCast(nLoop - 1)), &mm);
                        if (rcc == elNExpr(rdp(pWInfo, WhereInfo_pOrderBy))) {
                            wiBitSet(pWInfo, WI_bOrderedInnerLoop, true);
                            wr(Bitmask, pWInfo, WhereInfo_revMask, mm);
                        }
                    }
                }
            } else if (nLoop != 0 and rd(i8, pWInfo, WhereInfo_nOBSat) == 1 and
                (rd(u16, pWInfo, WhereInfo_wctrlFlags) & (WHERE_ORDERBY_MIN | WHERE_ORDERBY_MAX)) != 0)
            {
                wiBitSet(pWInfo, WI_bOrderedInnerLoop, true);
            }
        }
        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_SORTBYGROUP) != 0 and
            rd(i8, pWInfo, WhereInfo_nOBSat) == elNExpr(rdp(pWInfo, WhereInfo_pOrderBy)) and nLoop > 0)
        {
            var revMask: Bitmask = 0;
            const nOrder = wherePathSatisfiesOrderBy(pWInfo, rdp(pWInfo, WhereInfo_pOrderBy), pFrom, 0, @intCast(nLoop - 1), pathLoop(pFrom, @intCast(nLoop - 1)), &revMask);
            if (nOrder == elNExpr(rdp(pWInfo, WhereInfo_pOrderBy))) {
                wiBitSet(pWInfo, WI_sorted, true);
                wr(Bitmask, pWInfo, WhereInfo_revMask, revMask);
            }
        }
    }
    wr(LogEst, pWInfo, WhereInfo_nRowOut, rd(LogEst, pFrom, WherePath_nRow));
    cs.sqlite3StackFreeNN(parseDb(pParse), pSpace);
    return SQLITE_OK;
}

fn whereInterstageHeuristic(pWInfo: Ptr) void {
    var i: c_int = 0;
    while (i < wiNLevel(pWInfo)) : (i += 1) {
        const p = wlvWLoop(wiLevelAt(pWInfo, @intCast(i)));
        if (p == null) break;
        if ((wlWsFlags(p) & WHERE_VIRTUALTABLE) != 0) break;
        if ((wlWsFlags(p) & (WHERE_COLUMN_EQ | WHERE_COLUMN_NULL | WHERE_COLUMN_IN)) != 0) {
            const iTab = wlITab(p);
            var pLoop = rdp(pWInfo, WhereInfo_pLoops);
            while (pLoop != null) : (pLoop = wlNext(pLoop)) {
                if (wlITab(pLoop) != iTab) continue;
                if ((wlWsFlags(pLoop) & (WHERE_CONSTRAINT | WHERE_AUTO_INDEX)) != 0) continue;
                wr(Bitmask, pLoop, WhereLoop_prereq, ALLBITS);
            }
        } else {
            break;
        }
    }
}

// ════════════════════════════════════════════════════════════════════════════
// whereShortCut + small pre-Begin helpers
// ════════════════════════════════════════════════════════════════════════════

fn whereShortCut(pBuilder: Ptr) c_int {
    const pWInfo = rdp(pBuilder, WhereLoopBuilder_pWInfo);
    if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_OR_SUBCLAUSE) != 0) return 0;
    const pItem = slItem(rdp(pWInfo, WhereInfo_pTabList), 0);
    const pTab = rdp(pItem, SrcItem_pSTab);
    if (isVirtualTab(pTab)) return 0;
    if ((fgB1(pItem) & FG_isIndexedBy) != 0 or (fgB1(pItem) & FG_notIndexed) != 0) return 0;
    const iCur = rd(c_int, pItem, SrcItem_iCursor);
    const pWC = wiSWC(pWInfo);
    const pLoop = rdp(pBuilder, WhereLoopBuilder_pNew);
    wlSetWsFlags(pLoop, 0);
    wr(u16, pLoop, WhereLoop_nSkip, 0);
    var scan: [sizeof_WhereScan_buf]u8 align(8) = undefined;
    @memset(&scan, 0);
    const pScan: Ptr = @ptrCast(&scan);
    var pTerm = whereScanInit(pScan, pWC, iCur, -1, WO_EQ | WO_IS, null);
    while (pTerm != null and wtPrereqRight(pTerm) != 0) pTerm = whereScanNext(pScan);
    if (pTerm != null) {
        wlSetWsFlags(pLoop, WHERE_COLUMN_EQ | WHERE_IPK | WHERE_ONEROW);
        wlALTerm(pLoop)[0] = pTerm;
        wr(u16, pLoop, WhereLoop_nLTerm, 1);
        wr(u16, pLoop, WhereLoop_u_btree_nEq, 1);
        wr(LogEst, pLoop, WhereLoop_rRun, 33);
    } else {
        var pIdx = rdp(pTab, Table_pIndex);
        while (pIdx != null) : (pIdx = rdp(pIdx, Index_pNext)) {
            if (!isUniqueIndex(pIdx) or rdp(pIdx, Index_pPartIdxWhere) != null or idxNKeyCol(pIdx) > ALTERMSPACE_N) continue;
            const opMask: u32 = if (idxUniqNotNull(pIdx)) (WO_EQ | WO_IS) else WO_EQ;
            var j: c_int = 0;
            const nk = idxNKeyCol(pIdx);
            while (j < nk) : (j += 1) {
                pTerm = whereScanInit(pScan, pWC, iCur, j, opMask, pIdx);
                while (pTerm != null and wtPrereqRight(pTerm) != 0) pTerm = whereScanNext(pScan);
                if (pTerm == null) break;
                wlALTerm(pLoop)[@intCast(j)] = pTerm;
            }
            if (j != idxNKeyCol(pIdx)) continue;
            wlSetWsFlags(pLoop, WHERE_COLUMN_EQ | WHERE_ONEROW | WHERE_INDEXED);
            if (idxIsCovering(pIdx) or (rd(Bitmask, pItem, SrcItem_colUsed) & rd(Bitmask, pIdx, Index_colNotIdxed)) == 0) {
                wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_IDX_ONLY);
            }
            wr(u16, pLoop, WhereLoop_nLTerm, @intCast(j));
            wr(u16, pLoop, WhereLoop_u_btree_nEq, @intCast(j));
            wr(?*anyopaque, pLoop, WhereLoop_u_btree_pIndex, pIdx);
            wr(LogEst, pLoop, WhereLoop_rRun, 39);
            break;
        }
    }
    if (wlWsFlags(pLoop) != 0) {
        wr(LogEst, pLoop, WhereLoop_nOut, 1);
        wr(?*anyopaque, wiLevelAt(pWInfo, 0), WhereLevel_pWLoop, pLoop);
        wr(Bitmask, pLoop, WhereLoop_maskSelf, 1);
        wr(c_int, wiLevelAt(pWInfo, 0), WhereLevel_iTabCur, iCur);
        wr(LogEst, pWInfo, WhereInfo_nRowOut, 1);
        if (rdp(pWInfo, WhereInfo_pOrderBy) != null) {
            wr(i8, pWInfo, WhereInfo_nOBSat, @intCast(elNExpr(rdp(pWInfo, WhereInfo_pOrderBy))));
        }
        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_WANT_DISTINCT) != 0) {
            wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_UNIQUE);
        }
        if (rd(u8, pScan, WhereScan_iEquiv) > 1) wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_TRANSCONS);
        return 1;
    }
    return 0;
}

fn exprNodeIsDeterministic(pWalker: Ptr, pExpr: Ptr) callconv(.c) c_int {
    if (exprOp(pExpr) == TK_FUNCTION and !hasProp(pExpr, EP_ConstFunc)) {
        wr(u16, pWalker, Walker_eCode, 0);
        return WRC_Abort;
    }
    return WRC_Continue;
}

fn exprIsDeterministic(p: Ptr) c_int {
    var w: [sizeof_Walker]u8 align(8) = undefined;
    @memset(&w, 0);
    const wp: Ptr = @ptrCast(&w);
    wr(u16, wp, Walker_eCode, 1);
    wr(?*anyopaque, wp, Walker_xExprCallback, @constCast(@ptrCast(&exprNodeIsDeterministic)));
    wr(?*anyopaque, wp, Walker_xSelectCallback, @constCast(@ptrCast(&c.sqlite3SelectWalkFail)));
    _ = c.sqlite3WalkExpr(wp, p);
    return rd(u16, wp, Walker_eCode);
}

fn whereOmitNoopJoin(pWInfo: Ptr, notReady0: Bitmask) Bitmask {
    var notReady = notReady0;
    var tabUsed = c.sqlite3WhereExprListUsage(wiMaskSet(pWInfo), rdp(pWInfo, WhereInfo_pResultSet));
    if (rdp(pWInfo, WhereInfo_pOrderBy) != null) {
        tabUsed |= c.sqlite3WhereExprListUsage(wiMaskSet(pWInfo), rdp(pWInfo, WhereInfo_pOrderBy));
    }
    const hasRightJoin = (fgJoin(slItem(rdp(pWInfo, WhereInfo_pTabList), 0)) & @as(u8, @intCast(JT_LTORJ))) != 0;
    var i: c_int = wiNLevel(pWInfo) - 1;
    while (i >= 1) : (i -= 1) {
        const pLoop = wlvWLoop(wiLevelAt(pWInfo, @intCast(i)));
        const pItem = slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pLoop));
        if ((fgJoin(pItem) & @as(u8, @intCast(JT_LEFT | JT_RIGHT))) != @as(u8, @intCast(JT_LEFT))) continue;
        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_WANT_DISTINCT) == 0 and
            (wlWsFlags(pLoop) & WHERE_ONEROW) == 0)
        {
            continue;
        }
        if ((tabUsed & wlMaskSelf(pLoop)) != 0) continue;
        const pSWC = wiSWC(pWInfo);
        const nt = wcNTerm(pSWC);
        var k: c_int = 0;
        var broke = false;
        while (k < nt) : (k += 1) {
            const pTerm = wcTermAt(pSWC, k);
            if ((wtPrereqAll(pTerm) & wlMaskSelf(pLoop)) != 0) {
                if (!hasProp(wtExpr(pTerm), EP_OuterON) or rd(c_int, wtExpr(pTerm), Expr_w_iJoin) != rd(c_int, pItem, SrcItem_iCursor)) {
                    broke = true;
                    break;
                }
            }
            if (hasRightJoin and hasProp(wtExpr(pTerm), EP_InnerON)) {
                broke = true;
                break;
            }
        }
        if (broke) continue;
        const m1 = maskbit(i) - 1;
        const rm = rd(Bitmask, pWInfo, WhereInfo_revMask);
        wr(Bitmask, pWInfo, WhereInfo_revMask, (m1 & rm) | ((rm >> 1) & ~m1));
        notReady &= ~wlMaskSelf(pLoop);
        var k2: c_int = 0;
        while (k2 < nt) : (k2 += 1) {
            const pTerm = wcTermAt(pSWC, k2);
            if ((wtPrereqAll(pTerm) & wlMaskSelf(pLoop)) != 0) {
                wtSetWtFlags(pTerm, wtWtFlags(pTerm) | TERM_CODED);
                wr(Bitmask, pTerm, WhereTerm_prereqAll, 0);
            }
        }
        if (i != wiNLevel(pWInfo) - 1) {
            const nByte: usize = @intCast(@as(c_int, wiNLevel(pWInfo) - 1 - i) * @as(c_int, @intCast(sizeof_WhereLevel)));
            std.mem.copyForwards(u8, @as([*]u8, @ptrCast(wiLevelAt(pWInfo, @intCast(i)).?))[0..nByte], @as([*]u8, @ptrCast(wiLevelAt(pWInfo, @intCast(i + 1)).?))[0..nByte]);
        }
        wr(u8, pWInfo, WhereInfo_nLevel, @intCast(wiNLevel(pWInfo) - 1));
    }
    return notReady;
}

fn whereCheckIfBloomFilterIsUseful(pWInfo: Ptr) void {
    var nSearch: LogEst = 0;
    var i: c_int = 0;
    while (i < wiNLevel(pWInfo)) : (i += 1) {
        const pLoop = wlvWLoop(wiLevelAt(pWInfo, @intCast(i)));
        const reqFlags = WHERE_SELFCULL | WHERE_COLUMN_EQ;
        const pItem = slItem(rdp(pWInfo, WhereInfo_pTabList), wlITab(pLoop));
        const pTab = rdp(pItem, SrcItem_pSTab);
        if ((tabFlags(pTab) & TF_HasStat1) == 0) break;
        wr(u32, pTab, Table_tabFlags, tabFlags(pTab) | TF_MaybeReanalyze);
        if (i >= 1 and (wlWsFlags(pLoop) & reqFlags) == reqFlags) {
            if (nSearch > rd(LogEst, pTab, Table_nRowLogEst)) {
                wlSetWsFlags(pLoop, wlWsFlags(pLoop) | WHERE_BLOOMFILTER);
                wlSetWsFlags(pLoop, wlWsFlags(pLoop) & ~WHERE_IDX_ONLY);
            }
        }
        nSearch += wlNOut(pLoop);
    }
}

const Parse_explain_u8 = Parse_explain;
const Column_zCnName_unused = 0;
const Index_zIdxName_unused = 0;

fn whereAddIndexedExpr(pParse: Ptr, pIdx: Ptr, iIdxCur: c_int, pTabItem: Ptr) void {
    const pTab = rdp(pIdx, Index_pTable);
    var i: c_int = 0;
    const n = idxNColumn(pIdx);
    while (i < n) : (i += 1) {
        var pExpr: Ptr = undefined;
        const j = idxAiColumn(pIdx)[@intCast(i)];
        if (j == XN_EXPR) {
            pExpr = elItemExpr(rdp(pIdx, Index_aColExpr), @intCast(i));
        } else if (j >= 0 and (rd(u16, tabAColAt(pTab, @intCast(j)), Column_colFlags) & COLFLAG_VIRTUAL) != 0) {
            pExpr = c.sqlite3ColumnExpr(pTab, tabAColAt(pTab, @intCast(j)));
        } else {
            continue;
        }
        if (c.sqlite3ExprIsConstant(null, pExpr) != 0) continue;
        const p = c.sqlite3DbMallocRaw(parseDb(pParse), sizeof_IndexedExpr);
        if (p == null) break;
        wr(?*anyopaque, p, IndexedExpr_pIENext, rdp(pParse, Parse_pIdxEpr));
        wr(?*anyopaque, p, IndexedExpr_pExpr, c.sqlite3ExprDup(parseDb(pParse), pExpr, 0));
        wr(c_int, p, IndexedExpr_iDataCur, rd(c_int, pTabItem, SrcItem_iCursor));
        wr(c_int, p, IndexedExpr_iIdxCur, iIdxCur);
        wr(c_int, p, IndexedExpr_iIdxCol, i);
        wr(u8, p, IndexedExpr_bMaybeNullRow, @intFromBool((fgJoin(pTabItem) & @as(u8, @intCast(JT_LEFT | JT_LTORJ | JT_RIGHT))) != 0));
        if (c.sqlite3IndexAffinityStr(parseDb(pParse), pIdx) != null) {
            wr(u8, p, IndexedExpr_aff, @as([*]u8, @ptrCast(rdp(pIdx, Index_zColAff).?))[@intCast(i)]);
        }
        wr(?*anyopaque, p, IndexedExpr_zIdxName, rdp(pIdx, Index_zName));
        wr(?*anyopaque, pParse, Parse_pIdxEpr, p);
        if (rdp(p, IndexedExpr_pIENext) == null) {
            c.sqlite3ParserAddCleanup(pParse, &whereIndexedExprCleanup, fieldPtr(pParse, Parse_pIdxEpr));
        }
    }
}
const IndexedExpr_zIdxName = off("IndexedExpr_zIdxName", 32); // after pIENext; present w/ explain comments

fn whereReverseScanOrder(pWInfo: Ptr) void {
    var ii: c_int = 0;
    const n = slNSrc(rdp(pWInfo, WhereInfo_pTabList));
    while (ii < n) : (ii += 1) {
        const pItem = slItem(rdp(pWInfo, WhereInfo_pTabList), @intCast(ii));
        if ((fgB2(pItem) & FG_isCte) == 0 or
            rd(u8, rdp(pItem, SrcItem_u2_pCteUse), CteUse_eM10d) != M10d_Yes or
            (fgB1(pItem) & FG_isSubquery) == 0 or
            rdp(rdp(rdp(pItem, SrcItem_u4_pSubq), Subquery_pSelect), Select_pOrderBy) == null)
        {
            wr(Bitmask, pWInfo, WhereInfo_revMask, rd(Bitmask, pWInfo, WhereInfo_revMask) | maskbit(ii));
        }
    }
}

// ════════════════════════════════════════════════════════════════════════════
// sqlite3WhereBegin
// ════════════════════════════════════════════════════════════════════════════

inline fn round8(x: usize) usize {
    return (x + 7) & ~@as(usize, 7);
}
fn szWhereInfo(N: c_int) usize {
    return round8(WhereInfo_a + @as(usize, @intCast(N)) * sizeof_WhereLevel);
}

const SF_MultiValue_C: u32 = SF_MultiValue;
const SF_WhereBegin: u32 = 524288;

export fn sqlite3WhereBegin(pParse: Ptr, pTabList: Ptr, pWhere: Ptr, pOrderBy0: Ptr, pResultSet: Ptr, pSelect: Ptr, wctrlFlags0: u16, iAuxArg: c_int) Ptr {
    var pOrderBy = pOrderBy0;
    var wctrlFlags = wctrlFlags0;
    const v = rdp(pParse, Parse_pVdbe);
    var notReady: Bitmask = undefined;
    var rc: c_int = undefined;
    var bFordelete: u8 = 0;
    const db = parseDb(pParse);

    var sWLBbuf: [sizeof_WhereLoopBuilder]u8 align(8) = undefined;
    @memset(&sWLBbuf, 0);
    const sWLB: Ptr = @ptrCast(&sWLBbuf);

    if (pOrderBy != null and elNExpr(pOrderBy) >= BMS) {
        pOrderBy = null;
        wctrlFlags &= ~WHERE_WANT_DISTINCT;
        wctrlFlags |= WHERE_KEEP_ALL_JOINS;
    }

    if (slNSrc(pTabList) > BMS) {
        c.sqlite3ErrorMsg(pParse, "at most %d tables in a join", BMS);
        return null;
    }

    const nTabList: c_int = if ((wctrlFlags & WHERE_OR_SUBCLAUSE) != 0) 1 else slNSrc(pTabList);

    const nByteWInfo = szWhereInfo(nTabList);
    var pWInfo = c.sqlite3DbMallocRawNN(db, nByteWInfo + sizeof_WhereLoop);
    if (dbMallocFailed(db)) {
        c.sqlite3DbFree(db, pWInfo);
        pWInfo = null;
        return whereBeginError(pParse, db, null);
    }
    wr(?*anyopaque, pWInfo, WhereInfo_pParse, pParse);
    wr(?*anyopaque, pWInfo, WhereInfo_pTabList, pTabList);
    wr(?*anyopaque, pWInfo, WhereInfo_pOrderBy, pOrderBy);
    wr(?*anyopaque, pWInfo, WhereInfo_pResultSet, pResultSet);
    {
        const ap: [*]c_int = @ptrCast(@alignCast(fieldPtr(pWInfo, WhereInfo_aiCurOnePass)));
        ap[0] = -1;
        ap[1] = -1;
    }
    wr(u8, pWInfo, WhereInfo_nLevel, @intCast(nTabList));
    const lbl = c.sqlite3VdbeMakeLabel(pParse);
    wr(c_int, pWInfo, WhereInfo_iBreak, lbl);
    wr(c_int, pWInfo, WhereInfo_iContinue, lbl);
    wr(u16, pWInfo, WhereInfo_wctrlFlags, wctrlFlags);
    wr(LogEst, pWInfo, WhereInfo_iLimit, @intCast(iAuxArg));
    wr(c_int, pWInfo, WhereInfo_savedNQueryLoop, rd(c_int, pParse, Parse_nQueryLoop));
    wr(?*anyopaque, pWInfo, WhereInfo_pSelect, pSelect);
    // memset(&pWInfo->nOBSat, 0, offsetof(WhereInfo,sWC)-offsetof(WhereInfo,nOBSat))
    @memset(@as([*]u8, @ptrCast(fieldPtr(pWInfo, WhereInfo_nOBSat).?))[0 .. WhereInfo_sWC - WhereInfo_nOBSat], 0);
    // memset(&pWInfo->a[0], 0, sizeof(WhereLoop)+nTabList*sizeof(WhereLevel))
    @memset(@as([*]u8, @ptrCast(fieldPtr(pWInfo, WhereInfo_a).?))[0 .. sizeof_WhereLoop + @as(usize, @intCast(nTabList)) * sizeof_WhereLevel], 0);
    const pMaskSet = wiMaskSet(pWInfo);
    wr(c_int, pMaskSet, WhereMaskSet_n, 0);
    @as([*]c_int, @ptrCast(@alignCast(fieldPtr(pMaskSet, WhereMaskSet_ix))))[0] = -99;
    wr(?*anyopaque, sWLB, WhereLoopBuilder_pWInfo, pWInfo);
    wr(?*anyopaque, sWLB, WhereLoopBuilder_pWC, wiSWC(pWInfo));
    wr(?*anyopaque, sWLB, WhereLoopBuilder_pNew, fieldPtr(pWInfo, nByteWInfo));
    whereLoopInit(rdp(sWLB, WhereLoopBuilder_pNew));

    c.sqlite3WhereClauseInit(wiSWC(pWInfo), pWInfo);
    c.sqlite3WhereSplit(wiSWC(pWInfo), pWhere, @intCast(TK_AND));

    if (nTabList == 0) {
        if (pOrderBy != null) wr(i8, pWInfo, WhereInfo_nOBSat, @intCast(elNExpr(pOrderBy)));
        if ((wctrlFlags & WHERE_WANT_DISTINCT) != 0 and optimizationEnabled(db, SQLITE_DistinctOpt)) {
            wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_UNIQUE);
        }
        if (rdp(pWInfo, WhereInfo_pSelect) != null and (rd(u32, rdp(pWInfo, WhereInfo_pSelect), Select_selFlags) & SF_MultiValue_C) == 0) {
            // ExplainQueryPlan SCAN CONSTANT ROW — emitted as OP_Explain (no-op if not EQP)
            _ = c.sqlite3VdbeExplain(pParse, 0, "SCAN CONSTANT ROW");
        }
    } else {
        var ii: c_int = 0;
        while (true) {
            createMask(pMaskSet, rd(c_int, slItem(pTabList, @intCast(ii)), SrcItem_iCursor));
            c.sqlite3WhereTabFuncArgs(pParse, slItem(pTabList, @intCast(ii)), wiSWC(pWInfo));
            ii += 1;
            if (ii >= slNSrc(pTabList)) break;
        }
    }

    c.sqlite3WhereExprAnalyze(pTabList, wiSWC(pWInfo));
    if (pSelect != null and rdp(pSelect, Select_pLimit) != null) {
        c.sqlite3WhereAddLimit(wiSWC(pWInfo), pSelect);
    }
    if (rd(c_int, pParse, Parse_nErr) != 0) return whereBeginError(pParse, db, pWInfo);

    {
        var ii: c_int = 0;
        const nb = wcNBase(wiSWC(pWInfo));
        while (ii < nb) : (ii += 1) {
            const pT = wcTermAt(wiSWC(pWInfo), ii);
            if ((wtWtFlags(pT) & TERM_VIRTUAL) != 0) continue;
            const pX = wtExpr(pT);
            if (wtPrereqAll(pT) == 0 and
                (nTabList == 0 or exprIsDeterministic(pX) != 0) and
                !(hasProp(pX, EP_InnerON) and (fgJoin(slItem(pTabList, 0)) & @as(u8, @intCast(JT_LTORJ))) != 0))
            {
                c.sqlite3ExprIfFalse(pParse, pX, rd(c_int, pWInfo, WhereInfo_iBreak), SQLITE_JUMPIFNULL);
                wtSetWtFlags(pT, wtWtFlags(pT) | TERM_CODED);
            }
        }
    }

    if ((wctrlFlags & WHERE_WANT_DISTINCT) != 0) {
        if (optimizationDisabled(db, SQLITE_DistinctOpt)) {
            wctrlFlags &= ~WHERE_WANT_DISTINCT;
            wr(u16, pWInfo, WhereInfo_wctrlFlags, rd(u16, pWInfo, WhereInfo_wctrlFlags) & ~WHERE_WANT_DISTINCT);
        } else if (isDistinctRedundant(pParse, pTabList, wiSWC(pWInfo), pResultSet) != 0) {
            wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_UNIQUE);
        } else if (pOrderBy == null) {
            wr(u16, pWInfo, WhereInfo_wctrlFlags, rd(u16, pWInfo, WhereInfo_wctrlFlags) | WHERE_DISTINCTBY);
            wr(?*anyopaque, pWInfo, WhereInfo_pOrderBy, pResultSet);
        }
    }

    if (nTabList != 1 or whereShortCut(sWLB) == 0) {
        rc = whereLoopAddAll(sWLB);
        if (rc != 0) return whereBeginError(pParse, db, pWInfo);

        _ = wherePathSolver(pWInfo, 0);
        if (dbMallocFailed(db)) return whereBeginError(pParse, db, pWInfo);
        if (rdp(pWInfo, WhereInfo_pOrderBy) != null) {
            whereInterstageHeuristic(pWInfo);
            _ = wherePathSolver(pWInfo, if (rd(LogEst, pWInfo, WhereInfo_nRowOut) < 0) 1 else rd(LogEst, pWInfo, WhereInfo_nRowOut) + 1);
            if (dbMallocFailed(db)) return whereBeginError(pParse, db, pWInfo);
        }

        if ((rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_WANT_DISTINCT) != 0) {
            wr(LogEst, pWInfo, WhereInfo_nRowOut, rd(LogEst, pWInfo, WhereInfo_nRowOut) - 30);
        }
    }

    if (rdp(pWInfo, WhereInfo_pOrderBy) == null and (rd(u64, db, db_flags) & SQLITE_ReverseOrder) != 0) {
        whereReverseScanOrder(pWInfo);
    }
    if (rd(c_int, pParse, Parse_nErr) != 0) return whereBeginError(pParse, db, pWInfo);

    notReady = ~@as(Bitmask, 0);
    if (wiNLevel(pWInfo) >= 2 and pResultSet != null and
        (wctrlFlags & (WHERE_AGG_DISTINCT | WHERE_KEEP_ALL_JOINS)) == 0 and
        optimizationEnabled(db, SQLITE_OmitNoopJoin))
    {
        notReady = whereOmitNoopJoin(pWInfo, notReady);
        // nTabList = pWInfo->nLevel (re-read below)
    }
    const nTabList2: c_int = if (wiNLevel(pWInfo) >= 2 and pResultSet != null and
        (wctrlFlags & (WHERE_AGG_DISTINCT | WHERE_KEEP_ALL_JOINS)) == 0 and
        optimizationEnabled(db, SQLITE_OmitNoopJoin)) wiNLevel(pWInfo) else nTabList;

    if (wiNLevel(pWInfo) >= 2 and optimizationEnabled(db, SQLITE_BloomFilter)) {
        whereCheckIfBloomFilterIsUseful(pWInfo);
    }

    wr(c_int, pParse, Parse_nQueryLoop, rd(c_int, pParse, Parse_nQueryLoop) + rd(LogEst, pWInfo, WhereInfo_nRowOut));

    if ((wctrlFlags & WHERE_ONEPASS_DESIRED) != 0) {
        const wsFlags = wlWsFlags(wlvWLoop(wiLevelAt(pWInfo, 0)));
        const bOnerow = (wsFlags & WHERE_ONEROW) != 0;
        if (bOnerow or (
            (wctrlFlags & WHERE_ONEPASS_MULTIROW) != 0 and
            !isVirtualTab(rdp(slItem(pTabList, 0), SrcItem_pSTab)) and
            ((wsFlags & WHERE_MULTI_OR) == 0 or (wctrlFlags & WHERE_DUPLICATES_OK) != 0) and
            optimizationEnabled(db, SQLITE_OnePass)))
        {
            wr(u8, pWInfo, WhereInfo_eOnePass, if (bOnerow) ONEPASS_SINGLE else ONEPASS_MULTI);
            if (hasRowid(rdp(slItem(pTabList, 0), SrcItem_pSTab)) and (wsFlags & WHERE_IDX_ONLY) != 0) {
                if ((wctrlFlags & WHERE_ONEPASS_MULTIROW) != 0) {
                    bFordelete = OPFLAG_FORDELETE;
                }
                wlSetWsFlags(wlvWLoop(wiLevelAt(pWInfo, 0)), wsFlags & ~WHERE_IDX_ONLY);
            }
        }
    }

    // Open tables and indexes
    var ii: c_int = 0;
    while (ii < nTabList2) : (ii += 1) {
        const pLevel = wiLevelAt(pWInfo, @intCast(ii));
        const pTabItem = slItem(pTabList, @intCast(wlvIFrom(pLevel)));
        const pTab = rdp(pTabItem, SrcItem_pSTab);
        const iDb = c.sqlite3SchemaToIndex(db, rdp(pTab, Table_pSchema));
        const pLoop = wlvWLoop(pLevel);
        wr(c_int, pLevel, WhereLevel_addrBrk, c.sqlite3VdbeMakeLabel(pParse));
        if (ii == 0 or (fgJoin(pTabItem) & @as(u8, @intCast(JT_LEFT))) != 0) {
            wr(c_int, pLevel, WhereLevel_addrHalt, rd(c_int, pLevel, WhereLevel_addrBrk));
        } else if (rdp(wiLevelAt(pWInfo, @intCast(ii - 1)), WhereLevel_pRJ) != null) {
            wr(c_int, pLevel, WhereLevel_addrHalt, rd(c_int, wiLevelAt(pWInfo, @intCast(ii - 1)), WhereLevel_addrBrk));
        } else {
            wr(c_int, pLevel, WhereLevel_addrHalt, rd(c_int, wiLevelAt(pWInfo, @intCast(ii - 1)), WhereLevel_addrHalt));
        }
        if ((tabFlags(pTab) & TF_Ephemeral) != 0 or isView(pTab)) {
            // nothing
        } else if ((wlWsFlags(pLoop) & WHERE_VIRTUALTABLE) != 0) {
            const pVTab: ?[*]const u8 = @ptrCast(c.sqlite3GetVTable(db, pTab));
            _ = c.sqlite3VdbeAddOp4(v, OP_VOpen, rd(c_int, pTabItem, SrcItem_iCursor), 0, 0, pVTab, P4_VTAB);
        } else if (isVirtualTab(pTab)) {
            // noop
        } else if (((wlWsFlags(pLoop) & WHERE_IDX_ONLY) == 0 and (wctrlFlags & WHERE_OR_SUBCLAUSE) == 0) or
            (fgJoin(pTabItem) & @as(u8, @intCast(JT_LTORJ | JT_RIGHT))) != 0)
        {
            var op: c_int = OP_OpenRead;
            if (rd(u8, pWInfo, WhereInfo_eOnePass) != ONEPASS_OFF) {
                op = OP_OpenWrite;
                @as([*]c_int, @ptrCast(@alignCast(fieldPtr(pWInfo, WhereInfo_aiCurOnePass))))[0] = rd(c_int, pTabItem, SrcItem_iCursor);
            }
            c.sqlite3OpenTable(pParse, rd(c_int, pTabItem, SrcItem_iCursor), iDb, pTab, op);
            if (rd(u8, pWInfo, WhereInfo_eOnePass) == ONEPASS_OFF and
                rd(i16, pTab, Table_nCol) < BMS and
                (tabFlags(pTab) & (TF_HasGenerated | TF_WithoutRowid)) == 0 and
                (wlWsFlags(pLoop) & (WHERE_AUTO_INDEX | WHERE_BLOOMFILTER)) == 0)
            {
                var b = rd(Bitmask, pTabItem, SrcItem_colUsed);
                var n: c_int = 0;
                while (b != 0) : ({
                    b >>= 1;
                    n += 1;
                }) {}
                c.sqlite3VdbeChangeP4(v, -1, @ptrFromInt(@as(usize, @intCast(n))), P4_INT32);
            }
            c.sqlite3VdbeChangeP5(v, bFordelete);
            if (ii >= 2 and (fgJoin(pTabItem) & @as(u8, @intCast(JT_LTORJ | JT_LEFT))) == 0 and
                rd(c_int, pLevel, WhereLevel_addrHalt) == rd(c_int, wiLevelAt(pWInfo, 0), WhereLevel_addrHalt))
            {
                _ = c.sqlite3VdbeAddOp2(v, OP_IfEmpty, rd(c_int, pTabItem, SrcItem_iCursor), rd(c_int, pWInfo, WhereInfo_iBreak));
            }
        } else {
            c.sqlite3TableLock(pParse, iDb, rd(u32, pTab, Table_tnum), 0, rd(?[*:0]const u8, pTab, Table_zName));
        }
        if ((wlWsFlags(pLoop) & WHERE_INDEXED) != 0) {
            const pIx = wlPIndex(pLoop);
            var iIndexCur: c_int = undefined;
            var op: c_int = OP_OpenRead;
            if (!hasRowid(pTab) and isPrimaryKeyIndex(pIx) and (wctrlFlags & WHERE_OR_SUBCLAUSE) != 0) {
                iIndexCur = rd(c_int, pLevel, WhereLevel_iTabCur);
                op = 0;
            } else if (rd(u8, pWInfo, WhereInfo_eOnePass) != ONEPASS_OFF) {
                var pJ = rdp(rdp(pTabItem, SrcItem_pSTab), Table_pIndex);
                iIndexCur = iAuxArg;
                while (pJ != null and pJ != pIx) {
                    iIndexCur += 1;
                    pJ = rdp(pJ, Index_pNext);
                }
                op = OP_OpenWrite;
                @as([*]c_int, @ptrCast(@alignCast(fieldPtr(pWInfo, WhereInfo_aiCurOnePass))))[1] = iIndexCur;
            } else if (iAuxArg != 0 and (wctrlFlags & WHERE_OR_SUBCLAUSE) != 0) {
                iIndexCur = iAuxArg;
                op = OP_ReopenIdx;
            } else {
                iIndexCur = rd(c_int, pParse, Parse_nTab);
                wr(c_int, pParse, Parse_nTab, iIndexCur + 1);
                if (idxBHasExpr(pIx) and optimizationEnabled(db, SQLITE_IndexedExpr)) {
                    whereAddIndexedExpr(pParse, pIx, iIndexCur, pTabItem);
                }
                if (rdp(pIx, Index_pPartIdxWhere) != null and (fgJoin(pTabItem) & @as(u8, @intCast(JT_RIGHT))) == 0) {
                    wherePartIdxExpr(pParse, pIx, rdp(pIx, Index_pPartIdxWhere), null, iIndexCur, pTabItem);
                }
            }
            wr(c_int, pLevel, WhereLevel_iIdxCur, iIndexCur);
            if (op != 0) {
                _ = c.sqlite3VdbeAddOp3(v, op, iIndexCur, @intCast(rd(u32, pIx, Index_tnum)), iDb);
                c.sqlite3VdbeSetP4KeyInfo(pParse, pIx);
                if ((wlWsFlags(pLoop) & WHERE_CONSTRAINT) != 0 and
                    (wlWsFlags(pLoop) & (WHERE_COLUMN_RANGE | WHERE_SKIPSCAN)) == 0 and
                    (wlWsFlags(pLoop) & WHERE_BIGNULL_SORT) == 0 and
                    (wlWsFlags(pLoop) & WHERE_IN_SEEKSCAN) == 0 and
                    (rd(u16, pWInfo, WhereInfo_wctrlFlags) & WHERE_ORDERBY_MIN) == 0 and
                    rd(u8, pWInfo, WhereInfo_eDistinct) != WHERE_DISTINCT_ORDERED)
                {
                    c.sqlite3VdbeChangeP5(v, OPFLAG_SEEKEQ);
                }
            }
        }
        if (iDb >= 0) c.sqlite3CodeVerifySchema(pParse, iDb);
        if ((fgJoin(pTabItem) & @as(u8, @intCast(JT_RIGHT))) != 0) {
            const pRJ = sqlite3WhereMalloc(pWInfo, sizeof_WhereRightJoin);
            wr(?*anyopaque, pLevel, WhereLevel_pRJ, pRJ);
            if (pRJ != null) {
                wr(c_int, pRJ, WhereRightJoin_iMatch, rd(c_int, pParse, Parse_nTab));
                wr(c_int, pParse, Parse_nTab, rd(c_int, pParse, Parse_nTab) + 1);
                wr(c_int, pParse, Parse_nMem, rd(c_int, pParse, Parse_nMem) + 1);
                wr(c_int, pRJ, WhereRightJoin_regBloom, rd(c_int, pParse, Parse_nMem));
                _ = c.sqlite3VdbeAddOp2(v, OP_Blob, 65536, rd(c_int, pRJ, WhereRightJoin_regBloom));
                wr(c_int, pParse, Parse_nMem, rd(c_int, pParse, Parse_nMem) + 1);
                wr(c_int, pRJ, WhereRightJoin_regReturn, rd(c_int, pParse, Parse_nMem));
                _ = c.sqlite3VdbeAddOp2(v, OP_Null, 0, rd(c_int, pRJ, WhereRightJoin_regReturn));
                if (hasRowid(pTab)) {
                    _ = c.sqlite3VdbeAddOp2(v, OP_OpenEphemeral, rd(c_int, pRJ, WhereRightJoin_iMatch), 1);
                    const pInfo = c.sqlite3KeyInfoAlloc(parseDb(pParse), 1, 0);
                    if (pInfo != null) {
                        @as([*]Ptr, @ptrCast(@alignCast(fieldPtr(pInfo, KeyInfo_aColl).?)))[0] = null;
                        @as([*]u8, @ptrCast(fieldPtr(pInfo, keyInfoASortFlags(pInfo)).?))[0] = 0;
                        c.sqlite3VdbeAppendP4(v, pInfo, P4_KEYINFO);
                    }
                } else {
                    const pPk = c.sqlite3PrimaryKeyIndex(pTab);
                    _ = c.sqlite3VdbeAddOp2(v, OP_OpenEphemeral, rd(c_int, pRJ, WhereRightJoin_iMatch), idxNKeyCol(pPk));
                    c.sqlite3VdbeSetP4KeyInfo(pParse, pPk);
                }
                wlSetWsFlags(pLoop, wlWsFlags(pLoop) & ~WHERE_IDX_ONLY);
                wr(i8, pWInfo, WhereInfo_nOBSat, 0);
                wr(u8, pWInfo, WhereInfo_eDistinct, WHERE_DISTINCT_UNORDERED);
            }
        }
    }
    wr(c_int, pWInfo, WhereInfo_iTop, c.sqlite3VdbeCurrentAddr(v));
    if (dbMallocFailed(db)) return whereBeginError(pParse, db, pWInfo);

    // Generate the search code (loop start for each nested loop)
    ii = 0;
    while (ii < nTabList2) : (ii += 1) {
        if (rd(c_int, pParse, Parse_nErr) != 0) return whereBeginError(pParse, db, pWInfo);
        const pLevel = wiLevelAt(pWInfo, @intCast(ii));
        const wsFlags = wlWsFlags(wlvWLoop(pLevel));
        const pSrc = slItem(pTabList, @intCast(wlvIFrom(pLevel)));
        if ((fgB1(pSrc) & FG_isMaterialized) != 0) {
            const pSubq = rdp(pSrc, SrcItem_u4_pSubq);
            var iOnce: c_int = 0;
            if ((fgB1(pSrc) & FG_isCorrelated) == 0) {
                iOnce = c.sqlite3VdbeAddOp0(v, OP_Once);
            }
            _ = c.sqlite3VdbeAddOp2(v, OP_Gosub, rd(c_int, pSubq, Subquery_regReturn), rd(c_int, pSubq, Subquery_addrFillSub));
            if (iOnce != 0) c.sqlite3VdbeJumpHere(v, iOnce);
        }
        if ((wsFlags & (WHERE_AUTO_INDEX | WHERE_BLOOMFILTER)) != 0) {
            if ((wsFlags & WHERE_AUTO_INDEX) != 0) {
                constructAutomaticIndex(pParse, wiSWC(pWInfo), notReady, pLevel);
            } else {
                sqlite3ConstructBloomFilter(pWInfo, ii, pLevel, notReady);
            }
            if (dbMallocFailed(db)) return whereBeginError(pParse, db, pWInfo);
        }
        const addrExplain = c.sqlite3WhereExplainOneScan(pParse, pTabList, pLevel, wctrlFlags);
        wr(c_int, pLevel, WhereLevel_addrBody, c.sqlite3VdbeCurrentAddr(v));
        notReady = c.sqlite3WhereCodeOneLoopStart(pParse, v, pWInfo, ii, pLevel, notReady);
        wr(c_int, pWInfo, WhereInfo_iContinue, rd(c_int, pLevel, WhereLevel_addrCont));
        if ((wsFlags & WHERE_MULTI_OR) == 0 and (wctrlFlags & WHERE_OR_SUBCLAUSE) == 0) {
            sqlite3WhereAddScanStatus(v, pTabList, pLevel, addrExplain);
        }
    }

    wr(c_int, pWInfo, WhereInfo_iEndWhere, c.sqlite3VdbeCurrentAddr(v));
    return pWInfo;
}

fn whereBeginError(pParse: Ptr, db: Ptr, pWInfo: Ptr) Ptr {
    if (pWInfo != null) {
        wr(c_int, pParse, Parse_nQueryLoop, rd(c_int, pWInfo, WhereInfo_savedNQueryLoop));
        whereInfoFree(db, pWInfo);
    }
    return null;
}
const Table_tnum = off("Table_tnum", 40);
const KeyInfo_aColl = off("KeyInfo_aColl", 32);
fn keyInfoASortFlags(pInfo: Ptr) usize {
    _ = pInfo;
    return off("KeyInfo_aSortFlags", 24);
}

// ════════════════════════════════════════════════════════════════════════════
// sqlite3WhereEnd
// ════════════════════════════════════════════════════════════════════════════

const SQLITE_ENABLE_OFFSET_SQL_FUNC = true; // build flag ON

export fn sqlite3WhereEnd(pWInfo: Ptr) void {
    const pParse = wiParse(pWInfo);
    const v = rdp(pParse, Parse_pVdbe);
    const pTabList = rdp(pWInfo, WhereInfo_pTabList);
    const db = parseDb(pParse);
    const iEnd = c.sqlite3VdbeCurrentAddr(v);
    var nRJ: c_int = 0;
    var addrSeek: c_int = 0;

    var i: c_int = wiNLevel(pWInfo) - 1;
    while (i >= 0) : (i -= 1) {
        var addr: c_int = undefined;
        const pLevel = wiLevelAt(pWInfo, @intCast(i));
        if (rdp(pLevel, WhereLevel_pRJ) != null) {
            const pRJ = rdp(pLevel, WhereLevel_pRJ);
            c.sqlite3VdbeResolveLabel(v, rd(c_int, pLevel, WhereLevel_addrCont));
            wr(c_int, pLevel, WhereLevel_addrCont, c.sqlite3VdbeMakeLabel(pParse));
            wr(c_int, pRJ, WhereRightJoin_endSubrtn, c.sqlite3VdbeCurrentAddr(v));
            _ = c.sqlite3VdbeAddOp3(v, OP_Return, rd(c_int, pRJ, WhereRightJoin_regReturn), rd(c_int, pRJ, WhereRightJoin_addrSubrtn), 1);
            nRJ += 1;
        }
        const pLoop = wlvWLoop(pLevel);
        if (rd(u8, pLevel, WhereLevel_op) != OP_Noop) {
            if (rd(u8, pWInfo, WhereInfo_eDistinct) == WHERE_DISTINCT_ORDERED and
                i == wiNLevel(pWInfo) - 1 and
                (wlWsFlags(pLoop) & WHERE_INDEXED) != 0 and
                idxHasStat1(wlPIndex(pLoop)) and
                rd(u16, pLoop, WhereLoop_u_btree_nDistinctCol) > 0 and
                idxAiRowLogEst(wlPIndex(pLoop))[@intCast(rd(u16, pLoop, WhereLoop_u_btree_nDistinctCol))] >= 36)
            {
                const pIdx = wlPIndex(pLoop);
                const r1 = rd(c_int, pParse, Parse_nMem) + 1;
                const n = rd(u16, pLoop, WhereLoop_u_btree_nDistinctCol);
                var addrIfNull: c_int = 0;
                if (rd(c_int, pLevel, WhereLevel_iLeftJoin) != 0) {
                    addrIfNull = c.sqlite3VdbeAddOp2(v, OP_IfNullRow, rd(c_int, pLevel, WhereLevel_iIdxCur), r1);
                }
                var j: c_int = 0;
                while (j < n) : (j += 1) {
                    _ = c.sqlite3VdbeAddOp3(v, OP_Column, rd(c_int, pLevel, WhereLevel_iIdxCur), j, r1 + j);
                }
                wr(c_int, pParse, Parse_nMem, rd(c_int, pParse, Parse_nMem) + n + 1);
                const op: c_int = if (rd(u8, pLevel, WhereLevel_op) == OP_Prev) OP_SeekLT else OP_SeekGT;
                addrSeek = c.sqlite3VdbeAddOp4Int(v, op, rd(c_int, pLevel, WhereLevel_iIdxCur), 0, r1, n);
                _ = c.sqlite3VdbeAddOp2(v, OP_Goto, 1, rd(c_int, pLevel, WhereLevel_p2));
                if (rd(c_int, pLevel, WhereLevel_iLeftJoin) != 0) {
                    c.sqlite3VdbeJumpHere(v, addrIfNull);
                }
                _ = pIdx;
            }
        }
        if ((fgB3(slItem(pTabList, @intCast(wlvIFrom(pLevel)))) & FG_fromExists) != 0) {
            _ = c.sqlite3VdbeAddOp2(v, OP_Goto, 0, rd(c_int, pLevel, WhereLevel_addrBrk));
        }
        c.sqlite3VdbeResolveLabel(v, rd(c_int, pLevel, WhereLevel_addrCont));
        if (rd(u8, pLevel, WhereLevel_op) != OP_Noop) {
            _ = c.sqlite3VdbeAddOp3(v, rd(u8, pLevel, WhereLevel_op), rd(c_int, pLevel, WhereLevel_p1), rd(c_int, pLevel, WhereLevel_p2), rd(u8, pLevel, WhereLevel_p3));
            c.sqlite3VdbeChangeP5(v, rd(u8, pLevel, WhereLevel_p5));
            if (rd(c_int, pLevel, WhereLevel_regBignull) != 0) {
                c.sqlite3VdbeResolveLabel(v, rd(c_int, pLevel, WhereLevel_addrBignull));
                _ = c.sqlite3VdbeAddOp2(v, OP_DecrJumpZero, rd(c_int, pLevel, WhereLevel_regBignull), rd(c_int, pLevel, WhereLevel_p2) - 1);
            }
            if (addrSeek != 0) {
                c.sqlite3VdbeJumpHere(v, addrSeek);
                addrSeek = 0;
            }
        }
        if ((wlWsFlags(pLoop) & WHERE_IN_ABLE) != 0 and rd(c_int, pLevel, WhereLevel_u_in_nIn) > 0) {
            c.sqlite3VdbeResolveLabel(v, rd(c_int, pLevel, WhereLevel_addrNxt));
            var j: c_int = rd(c_int, pLevel, WhereLevel_u_in_nIn);
            var pIn = fieldPtr(rdp(pLevel, WhereLevel_u_in_aInLoop), @as(usize, @intCast(j - 1)) * sizeof_InLoop);
            while (j > 0) : ({
                j -= 1;
                pIn = fieldPtr(pIn, 0 -% sizeof_InLoop);
            }) {
                c.sqlite3VdbeJumpHere(v, rd(c_int, pIn, InLoop_addrInTop) + 1);
                if (rd(u8, pIn, InLoop_eEndLoopOp) != OP_Noop) {
                    if (rd(c_int, pIn, InLoop_nPrefix) != 0) {
                        const bEarlyOut = (wlWsFlags(pLoop) & WHERE_VIRTUALTABLE) == 0 and
                            (wlWsFlags(pLoop) & WHERE_IN_EARLYOUT) != 0;
                        if (rd(c_int, pLevel, WhereLevel_iLeftJoin) != 0) {
                            _ = c.sqlite3VdbeAddOp2(v, OP_IfNotOpen, rd(c_int, pIn, InLoop_iCur), c.sqlite3VdbeCurrentAddr(v) + 2 + @intFromBool(bEarlyOut));
                        }
                        if (bEarlyOut) {
                            _ = c.sqlite3VdbeAddOp4Int(v, OP_IfNoHope, rd(c_int, pLevel, WhereLevel_iIdxCur), c.sqlite3VdbeCurrentAddr(v) + 2, rd(c_int, pIn, InLoop_iBase), rd(c_int, pIn, InLoop_nPrefix));
                            c.sqlite3VdbeJumpHere(v, rd(c_int, pIn, InLoop_addrInTop) + 1);
                        }
                    }
                    _ = c.sqlite3VdbeAddOp2(v, rd(u8, pIn, InLoop_eEndLoopOp), rd(c_int, pIn, InLoop_iCur), rd(c_int, pIn, InLoop_addrInTop));
                }
                c.sqlite3VdbeJumpHere(v, rd(c_int, pIn, InLoop_addrInTop) - 1);
            }
        }
        c.sqlite3VdbeResolveLabel(v, rd(c_int, pLevel, WhereLevel_addrBrk));
        if (rdp(pLevel, WhereLevel_pRJ) != null) {
            _ = c.sqlite3VdbeAddOp3(v, OP_Return, rd(c_int, rdp(pLevel, WhereLevel_pRJ), WhereRightJoin_regReturn), 0, 1);
        }
        if (rd(c_int, pLevel, WhereLevel_addrSkip) != 0) {
            _ = c.sqlite3VdbeGoto(v, rd(c_int, pLevel, WhereLevel_addrSkip));
            c.sqlite3VdbeJumpHere(v, rd(c_int, pLevel, WhereLevel_addrSkip));
            c.sqlite3VdbeJumpHere(v, rd(c_int, pLevel, WhereLevel_addrSkip) - 2);
        }
        if (rd(c_int, pLevel, WhereLevel_addrLikeRep) != 0) {
            _ = c.sqlite3VdbeAddOp2(v, OP_DecrJumpZero, @intCast(rd(u32, pLevel, WhereLevel_iLikeRepCntr) >> 1), rd(c_int, pLevel, WhereLevel_addrLikeRep));
        }
        if (rd(c_int, pLevel, WhereLevel_iLeftJoin) != 0) {
            const ws = wlWsFlags(pLoop);
            addr = c.sqlite3VdbeAddOp1(v, OP_IfPos, rd(c_int, pLevel, WhereLevel_iLeftJoin));
            if ((ws & WHERE_IDX_ONLY) == 0) {
                const pSrc = slItem(pTabList, @intCast(wlvIFrom(pLevel)));
                if ((fgB1(pSrc) & FG_viaCoroutine) != 0) {
                    const nn = rd(c_int, rdp(pSrc, SrcItem_u4_pSubq), Subquery_regResult);
                    const m = rd(i16, rdp(pSrc, SrcItem_pSTab), Table_nCol);
                    _ = c.sqlite3VdbeAddOp3(v, OP_Null, 0, nn, nn + m - 1);
                }
                _ = c.sqlite3VdbeAddOp1(v, OP_NullRow, rd(c_int, pLevel, WhereLevel_iTabCur));
            }
            if ((ws & WHERE_INDEXED) != 0 or
                ((ws & WHERE_MULTI_OR) != 0 and rdp(pLevel, WhereLevel_u_pCoveringIdx) != null))
            {
                if ((ws & WHERE_MULTI_OR) != 0) {
                    const pIx = rdp(pLevel, WhereLevel_u_pCoveringIdx);
                    const iDb = c.sqlite3SchemaToIndex(db, rdp(pIx, Index_pSchema));
                    _ = c.sqlite3VdbeAddOp3(v, OP_ReopenIdx, rd(c_int, pLevel, WhereLevel_iIdxCur), @intCast(rd(u32, pIx, Index_tnum)), iDb);
                    c.sqlite3VdbeSetP4KeyInfo(pParse, pIx);
                }
                _ = c.sqlite3VdbeAddOp1(v, OP_NullRow, rd(c_int, pLevel, WhereLevel_iIdxCur));
            }
            if (rd(u8, pLevel, WhereLevel_op) == OP_Return) {
                _ = c.sqlite3VdbeAddOp2(v, OP_Gosub, rd(c_int, pLevel, WhereLevel_p1), rd(c_int, pLevel, WhereLevel_addrFirst));
            } else {
                _ = c.sqlite3VdbeGoto(v, rd(c_int, pLevel, WhereLevel_addrFirst));
            }
            c.sqlite3VdbeJumpHere(v, addr);
        }
    }

    i = 0;
    while (i < wiNLevel(pWInfo)) : (i += 1) {
        const pLevel = wiLevelAt(pWInfo, @intCast(i));
        const pTabItem = slItem(pTabList, @intCast(wlvIFrom(pLevel)));
        const pTab = rdp(pTabItem, SrcItem_pSTab);
        const pLoop = wlvWLoop(pLevel);

        if (rdp(pLevel, WhereLevel_pRJ) != null) {
            c.sqlite3WhereRightJoinLoop(pWInfo, i, pLevel);
            continue;
        }
        if ((fgB1(pTabItem) & FG_viaCoroutine) != 0) {
            translateColumnToCopy(pParse, rd(c_int, pLevel, WhereLevel_addrBody), rd(c_int, pLevel, WhereLevel_iTabCur), rd(c_int, rdp(pTabItem, SrcItem_u4_pSubq), Subquery_regResult), 0);
            continue;
        }

        var pIdx: Ptr = null;
        if ((wlWsFlags(pLoop) & (WHERE_INDEXED | WHERE_IDX_ONLY)) != 0) {
            pIdx = wlPIndex(pLoop);
        } else if ((wlWsFlags(pLoop) & WHERE_MULTI_OR) != 0) {
            pIdx = rdp(pLevel, WhereLevel_u_pCoveringIdx);
        }
        if (pIdx != null and !dbMallocFailed(db)) {
            var last: c_int = undefined;
            if (rd(u8, pWInfo, WhereInfo_eOnePass) == ONEPASS_OFF or !hasRowid(rdp(pIdx, Index_pTable))) {
                last = iEnd;
            } else {
                last = rd(c_int, pWInfo, WhereInfo_iEndWhere);
            }
            if (idxBHasExpr(pIdx)) {
                var p = rdp(pParse, Parse_pIdxEpr);
                while (p != null) {
                    if (rd(c_int, p, IndexedExpr_iIdxCur) == rd(c_int, pLevel, WhereLevel_iIdxCur)) {
                        wr(c_int, p, IndexedExpr_iDataCur, -1);
                        wr(c_int, p, IndexedExpr_iIdxCur, -1);
                    }
                    p = rdp(p, IndexedExpr_pIENext);
                }
            }
            const k = rd(c_int, pLevel, WhereLevel_addrBody) + 1;
            var pOp = c.sqlite3VdbeGetOp(v, k);
            const pLastOp = fieldPtr(pOp, @as(usize, @intCast(last - k)) * sizeof_VdbeOp);
            while (@intFromPtr(pOp) <= @intFromPtr(pLastOp)) : (pOp = fieldPtr(pOp, sizeof_VdbeOp)) {
                if (rd(c_int, pOp, VdbeOp_p1) != rd(c_int, pLevel, WhereLevel_iTabCur)) {
                    // no-op
                } else if (rd(u8, pOp, VdbeOp_opcode) == OP_Column or
                    (SQLITE_ENABLE_OFFSET_SQL_FUNC and rd(u8, pOp, VdbeOp_opcode) == OP_Offset))
                {
                    var x = rd(c_int, pOp, VdbeOp_p2);
                    if (SQLITE_ENABLE_OFFSET_SQL_FUNC and rd(u8, pOp, VdbeOp_opcode) == OP_Offset) {
                        // no column translation for OP_Offset
                    } else if (!hasRowid(pTab)) {
                        const pPk = c.sqlite3PrimaryKeyIndex(pTab);
                        x = idxAiColumn(pPk)[@intCast(x)];
                    } else {
                        x = c.sqlite3StorageColumnToTable(pTab, @intCast(x));
                    }
                    x = c.sqlite3TableColumnToIndex(pIdx, @intCast(x));
                    if (x >= 0) {
                        wr(c_int, pOp, VdbeOp_p2, x);
                        wr(c_int, pOp, VdbeOp_p1, rd(c_int, pLevel, WhereLevel_iIdxCur));
                    } else if ((wlWsFlags(pLoop) & (WHERE_IDX_ONLY | WHERE_EXPRIDX)) != 0) {
                        if ((wlWsFlags(pLoop) & WHERE_IDX_ONLY) != 0) {
                            c.sqlite3ErrorMsg(pParse, "internal query planner error");
                            wr(c_int, pParse, Parse_rc, SQLITE_INTERNAL);
                        } else {
                            wlSetWsFlags(pLoop, wlWsFlags(pLoop) & ~WHERE_EXPRIDX);
                            c.sqlite3WhereAddExplainText(pParse, rd(c_int, pLevel, WhereLevel_addrBody) - 1, pTabList, pLevel, rd(u16, pWInfo, WhereInfo_wctrlFlags));
                        }
                    }
                } else if (rd(u8, pOp, VdbeOp_opcode) == OP_Rowid) {
                    wr(c_int, pOp, VdbeOp_p1, rd(c_int, pLevel, WhereLevel_iIdxCur));
                    wr(u8, pOp, VdbeOp_opcode, @intCast(OP_IdxRowid));
                } else if (rd(u8, pOp, VdbeOp_opcode) == OP_IfNullRow) {
                    wr(c_int, pOp, VdbeOp_p1, rd(c_int, pLevel, WhereLevel_iIdxCur));
                }
            }
        }
    }

    c.sqlite3VdbeResolveLabel(v, rd(c_int, pWInfo, WhereInfo_iBreak));
    wr(c_int, pParse, Parse_nQueryLoop, rd(c_int, pWInfo, WhereInfo_savedNQueryLoop));
    whereInfoFree(db, pWInfo);
    wr(u8, pParse, Parse_withinRJSubrtn, @intCast(@as(c_int, rd(u8, pParse, Parse_withinRJSubrtn)) - nRJ));
}
